#[derive(Debug, Clone)]
struct ClientEventSink {
    client_id: ClientId,
    writer: SharedWriter,
    metrics: MetricsRegistry,
}

impl ClientEventSink {
    const fn new(client_id: ClientId, writer: SharedWriter, metrics: MetricsRegistry) -> Self {
        Self {
            client_id,
            writer,
            metrics,
        }
    }

    const fn client_id(&self) -> ClientId {
        self.client_id
    }

    async fn send(&self, event: Event) -> Result<(), CodecError> {
        let event_kind = client_event_kind(&event);
        let envelope = event_envelope(&event)?;
        let encode_started_at = Instant::now();
        let frames = encode_envelope_frames(&envelope)?;
        let started_at = Instant::now();
        let result = {
            let mut writer = self.writer.writer.lock().await;
            tokio::time::timeout(
                CLIENT_EVENT_SEND_TIMEOUT,
                write_encoded_envelope_frames(&mut *writer, &frames),
            )
            .await
            .unwrap_or_else(|_| {
                Err(CodecError::Io(std::io::Error::new(
                    std::io::ErrorKind::TimedOut,
                    format!("timed out sending event to client {}", self.client_id),
                )))
            })
        };
        let elapsed = started_at.elapsed();
        let mut labels = MetricLabels::new();
        labels.insert("event_kind".to_owned(), event_kind.to_owned());
        self.metrics.record_histogram_with_labels(
            "ipc.event_send.encode_duration_ms",
            elapsed_ms(encode_started_at),
            labels.clone(),
        );
        self.metrics.record_histogram_with_labels(
            "ipc.event_send.duration_ms",
            elapsed_ms(started_at),
            labels.clone(),
        );
        if result.is_err() {
            self.metrics
                .add_counter_with_labels("ipc.event_send.errors_total", 1, labels);
        }
        if elapsed >= CLIENT_EVENT_SEND_TIMEOUT {
            tracing::warn!(
                target: "bcode_server::client_events",
                client_id = %self.client_id,
                event_kind,
                elapsed_ms = elapsed.as_millis(),
                "client event send reached timeout threshold"
            );
        } else {
            tracing::debug!(
                target: "bcode_server::client_events",
                client_id = %self.client_id,
                event_kind,
                elapsed_ms = elapsed.as_millis(),
                "client event sent"
            );
        }
        result
    }
}

const fn client_event_kind(event: &Event) -> &'static str {
    match event {
        Event::Session(_) => "session",
        Event::SessionLive(_) => "session_live",
        Event::RuntimeWork(_) => "runtime_work",
        Event::SessionViewResyncRequired { .. } => "session_view_resync_required",
        Event::SessionCatalogUpdated { .. } => "session_catalog_updated",
    }
}

