#[derive(Debug)]
struct SessionTurnPermit {
    session_id: SessionId,
    turn_entries: u64,
    _private: (),
}

impl SessionTurnPermit {
    #[must_use]
    const fn new(session_id: SessionId) -> Self {
        Self {
            session_id,
            turn_entries: 0,
            _private: (),
        }
    }

    #[must_use]
    const fn session_id(&self) -> SessionId {
        self.session_id
    }

    const fn enter_turn(&mut self) -> SessionId {
        self.turn_entries = self.turn_entries.saturating_add(1);
        self.session_id
    }
}

#[derive(Debug, Default)]
struct TurnCancelState {
    token: CancellationToken,
    marker_commit: Mutex<()>,
}

impl TurnCancelState {
    fn close(&self) {
        self.token.cancel();
    }

    async fn wait_for_commit_boundary(&self) {
        let _commit = self.marker_commit.lock().await;
    }

    async fn cancel(&self) {
        self.close();
        self.wait_for_commit_boundary().await;
    }

    fn is_cancelled(&self) -> bool {
        self.token.is_cancelled()
    }

    async fn cancelled(&self) {
        self.token.cancelled().await;
    }
}

