#[allow(clippy::too_many_arguments)]
async fn handle_request(
    request: Request,
    request_id: u64,
    client_id: ClientId,
    state: &Arc<ServerState>,
    writer: &SharedWriter,
    attached_session: &mut Option<SessionId>,
) -> Result<(), ServerError> {
    let labels = request_metric_labels(&request);
    let context = request_metrics_context(&request, request_id, client_id, *attached_session);
    let result = Box::pin(state.metrics.in_context(context, async {
        Box::pin(handle_request_inner(
            request,
            request_id,
            client_id,
            state,
            writer,
            attached_session,
        ))
        .await
    }))
    .await;
    state
        .metrics
        .span("ipc.request")
        .labels(labels)
        .finish_result(&result);
    result
}

#[allow(clippy::too_many_lines, clippy::large_stack_frames)]
async fn handle_request_inner(
    request: Request,
    request_id: u64,
    client_id: ClientId,
    state: &Arc<ServerState>,
    writer: &SharedWriter,
    attached_session: &mut Option<SessionId>,
) -> Result<(), ServerError> {
    match request {
        Request::Hello {
            client_name,
            runtime_context,
            daemon_namespace,
        } => {
            handle_hello(
                request_id,
                client_id,
                state,
                writer,
                &client_name,
                runtime_context,
                daemon_namespace,
            )
            .await
        }
        Request::UpdateClientRuntimeContext { runtime_context } => {
            handle_update_client_runtime_context(
                request_id,
                client_id,
                state,
                writer,
                runtime_context,
            )
            .await
        }
        Request::Ping => handle_ping(request_id, writer).await,
        Request::IngestClientMetrics { batch } => {
            handle_ingest_client_metrics(request_id, state, writer, batch).await
        }
        Request::ServerStatus { working_directory } => {
            handle_server_status(request_id, state, writer, working_directory.as_deref()).await
        }
        Request::ModelCatalogDiagnostics => {
            handle_model_catalog_diagnostics(request_id, state, writer).await
        }
        Request::ServerStop { mode } => handle_server_stop(request_id, state, writer, mode).await,
        Request::ReleaseSessionDatabase { session_id } => {
            handle_release_session_database(request_id, state, writer, session_id).await
        }
        Request::SetComposerDraft { scope, text } => {
            handle_set_composer_draft(request_id, state, writer, scope, text).await
        }
        Request::ComposerDraft { scope } => {
            handle_composer_draft(request_id, state, writer, scope).await
        }
        Request::CreateSession {
            name,
            working_directory,
        } => handle_create_session(request_id, state, writer, name, working_directory).await,
        Request::ListSessions { working_directory } => {
            handle_list_sessions(request_id, state, writer, &working_directory).await
        }
        Request::SubscribeCatalogUpdates => {
            handle_subscribe_catalog_updates(request_id, client_id, state, writer).await
        }
        Request::ChangeSessionWorkingDirectory {
            session_id,
            working_directory,
        } => {
            handle_change_session_working_directory(
                request_id,
                state,
                writer,
                session_id,
                working_directory,
            )
            .await
        }
        Request::ListWorktrees(request) => {
            handle_list_worktrees(request_id, state, writer, request).await
        }
        Request::CreateWorktree(request) => {
            handle_create_worktree(request_id, state, writer, request).await
        }
        Request::RemoveWorktree(request) => {
            handle_remove_worktree(request_id, state, writer, request).await
        }
        Request::RalphStatus(request) => {
            handle_ralph_status(request_id, state, writer, request).await
        }
        Request::RunRalphLoop(request) => {
            handle_run_ralph_loop(request_id, client_id, state, writer, request).await
        }
        Request::ApproveRalphRun(request) => {
            handle_approve_ralph_run(request_id, client_id, state, writer, request).await
        }
        Request::CancelRalphLoop(request) => {
            Box::pin(handle_cancel_ralph_loop(request_id, state, writer, request)).await
        }
        Request::ListRalphRuns(request) => {
            Box::pin(handle_list_ralph_runs(request_id, state, writer, *request)).await
        }
        Request::ListRalphIterations(request) => {
            Box::pin(handle_list_ralph_iterations(
                request_id, state, writer, *request,
            ))
            .await
        }
        Request::ResumeRalphRun(request) => {
            handle_resume_ralph_run(request_id, state, writer, request).await
        }
        Request::RalphRunStatus(request) => {
            handle_ralph_run_status(request_id, state, writer, request).await
        }
        Request::RecordRalphLifecycle(request) => {
            handle_record_ralph_lifecycle(request_id, state, writer, request).await
        }
        Request::RenameSession { session_id, name } => {
            handle_rename_session(request_id, state, writer, session_id, name).await
        }
        Request::DeleteSession { session_id } => {
            handle_delete_session(request_id, state, writer, session_id).await
        }
        Request::ReadSessionArtifact {
            session_id,
            artifact_id,
            reference_key,
            offset,
            length,
        } => {
            handle_read_session_artifact(
                request_id,
                state,
                writer,
                session_id,
                artifact_id,
                reference_key,
                offset,
                length,
            )
            .await
        }
        Request::InvocationInput { session_id, input } => {
            handle_invocation_input(request_id, state, writer, session_id, input).await
        }
        Request::ForkSession {
            source_session_id,
            prompt_sequence,
            name,
        } => {
            handle_fork_session(
                request_id,
                state,
                writer,
                source_session_id,
                prompt_sequence,
                name,
            )
            .await
        }
        Request::CloneSession {
            source_session_id,
            name,
            expected_generation,
        } => {
            handle_clone_session(
                request_id,
                state,
                writer,
                source_session_id,
                name,
                expected_generation,
            )
            .await
        }
        Request::SessionHistory { session_id } => {
            handle_session_history(request_id, client_id, state, writer, session_id).await
        }
        Request::SessionHistoryPage { session_id, query } => {
            handle_session_history_page(request_id, client_id, state, writer, session_id, query)
                .await
        }
        Request::PrepareSessionOpen { session_id } => {
            handle_prepare_session_open(request_id, state, writer, session_id).await
        }
        Request::WaitSessionOpenProgress {
            session_id,
            operation_id,
            after_revision,
            timeout_ms,
        } => {
            handle_wait_session_open_progress(
                request_id,
                state,
                writer,
                session_id,
                operation_id,
                after_revision,
                timeout_ms,
            )
            .await
        }
        Request::AttachSession { session_id } => {
            let client_cwd = state.client_working_directory(client_id).await;
            let session_id =
                session_import::resolve_attach_session_id(state, session_id, client_cwd.as_deref())
                    .await;
            handle_attach_session(
                request_id,
                client_id,
                state,
                writer,
                attached_session,
                session_id,
            )
            .await
        }
        Request::AttachSessionRecent { session_id, limit } => {
            let client_cwd = state.client_working_directory(client_id).await;
            let session_id =
                session_import::resolve_attach_session_id(state, session_id, client_cwd.as_deref())
                    .await;
            handle_attach_session_recent(
                request_id,
                client_id,
                state,
                writer,
                attached_session,
                session_id,
                limit,
            )
            .await
        }
        Request::AttachSessionProjectionWindow {
            session_id,
            request,
        } => {
            let client_cwd = state.client_working_directory(client_id).await;
            let session_id =
                session_import::resolve_attach_session_id(state, session_id, client_cwd.as_deref())
                    .await;
            handle_attach_session_projection_window(
                request_id,
                client_id,
                state,
                writer,
                attached_session,
                session_id,
                request,
            )
            .await
        }
        Request::ImportExternalSession {
            source_id,
            external_session_id,
            working_directory,
        } => {
            session_import::handle_import_external_session(
                request_id,
                state,
                writer,
                &source_id,
                &external_session_id,
                working_directory,
            )
            .await
        }
        Request::RefreshSessionCatalog {
            working_directory,
            sources,
        } => {
            let Some(working_directory) = working_directory else {
                return send_response(
                    writer,
                    request_id,
                    Response::Err(ErrorResponse::new(
                        "catalog_cwd_required",
                        "catalog refresh requests must include the caller working directory",
                    )),
                )
                .await;
            };
            handle_refresh_session_catalog(
                request_id,
                state,
                writer,
                &working_directory,
                sources.as_deref(),
            )
            .await
        }
        Request::SendUserMessage { session_id, text } => {
            handle_user_message(
                request_id,
                client_id,
                state,
                writer,
                session_id,
                text,
                bcode_ipc::PromptPlacement::Steering,
            )
            .await
        }
        Request::SendUserMessageWithPlacement {
            session_id,
            text,
            placement,
        } => {
            handle_user_message(
                request_id, client_id, state, writer, session_id, text, placement,
            )
            .await
        }
        Request::SubmitTurn {
            session_id,
            text,
            admission,
        } => {
            handle_submit_turn(
                request_id, client_id, state, writer, session_id, text, admission,
            )
            .await
        }
        Request::InvokeSkill {
            session_id,
            skill_id,
            arguments,
            display_text,
        } => {
            handle_invoke_skill(
                request_id,
                client_id,
                state,
                writer,
                session_id,
                skill_id,
                arguments,
                display_text,
            )
            .await
        }
        Request::CancelSessionTurn {
            session_id,
            clear_queue,
        } => {
            handle_cancel_session_turn(
                request_id,
                state,
                writer,
                session_id,
                client_id,
                clear_queue,
            )
            .await
        }
        Request::CancelRuntimeWork {
            session_id,
            work_id,
        } => {
            handle_cancel_runtime_work(request_id, client_id, state, writer, session_id, work_id)
                .await
        }
        Request::ListRuntimeWork { session_id } => {
            handle_list_runtime_work(request_id, state, writer, session_id).await
        }
        Request::RuntimeWorkHistory { session_id, limit } => {
            handle_runtime_work_history(request_id, state, writer, session_id, limit).await
        }
        Request::SubscribeRuntimeWork { session_id } => {
            handle_subscribe_runtime_work(request_id, client_id, state, writer, session_id).await
        }
        Request::CompactSession { session_id } => {
            handle_compact_session(request_id, client_id, state, writer, session_id).await
        }
        Request::SetSessionModel {
            session_id,
            provider_plugin_id,
            model_id,
        } => {
            handle_set_session_model(
                request_id,
                state,
                writer,
                session_id,
                provider_plugin_id,
                model_id,
            )
            .await
        }
        Request::SetSessionReasoning {
            session_id,
            effort,
            summary,
        } => {
            handle_set_session_reasoning(request_id, state, writer, session_id, effort, summary)
                .await
        }
        Request::SessionModelStatus { session_id } => {
            handle_session_model_status(request_id, client_id, state, writer, session_id).await
        }
        Request::DefaultModelStatus => {
            handle_default_model_status(request_id, client_id, state, writer).await
        }
        Request::SessionModelList { provider_plugin_id } => {
            handle_session_model_list(request_id, client_id, state, writer, provider_plugin_id)
                .await
        }
        request => handle_remaining_request(request, request_id, client_id, state, writer).await,
    }
}

async fn handle_remaining_request(
    request: Request,
    request_id: u64,
    client_id: ClientId,
    state: &ServerState,
    writer: &SharedWriter,
) -> Result<(), ServerError> {
    handle_agent_permission_plugin_request(request, request_id, client_id, state, writer).await
}

async fn handle_agent_permission_plugin_request(
    request: Request,
    request_id: u64,
    client_id: ClientId,
    state: &ServerState,
    writer: &SharedWriter,
) -> Result<(), ServerError> {
    match request {
        Request::ListAgents => handle_list_agents(request_id, state, writer).await,
        Request::ListSkills => handle_list_skills(request_id, state, writer).await,
        Request::DescribeSkill { skill_id } => {
            handle_describe_skill(request_id, state, writer, &skill_id).await
        }
        Request::ActivateSkill {
            session_id,
            skill_id,
        } => handle_activate_skill(request_id, state, writer, session_id, skill_id).await,
        Request::DeactivateSkill {
            session_id,
            skill_id,
        } => handle_deactivate_skill(request_id, state, writer, session_id, skill_id).await,
        Request::ActiveSkills { session_id } => {
            handle_active_skills(request_id, state, writer, session_id).await
        }
        Request::AgentPolicyStatus => handle_agent_policy_status(request_id, state, writer).await,
        Request::SetSessionAgent {
            session_id,
            agent_id,
        } => handle_set_session_agent(request_id, state, writer, session_id, agent_id).await,
        Request::ListPermissions
        | Request::ResolvePermission { .. }
        | Request::ResolvePermissionBatch { .. }
        | Request::ListPendingToolExchanges
        | Request::ResolveToolExchange { .. } => {
            handle_permission_interaction_request(request, request_id, client_id, state, writer)
                .await
        }
        Request::AddPermissionRule {
            agent_id,
            category,
            pattern,
            action,
        } => {
            handle_add_permission_rule(
                request_id, state, writer, &agent_id, &category, pattern, &action,
            )
            .await
        }
        Request::ListPluginServices => handle_list_plugin_services(request_id, state, writer).await,
        Request::ListPluginContributions => {
            handle_list_plugin_contributions(request_id, state, writer).await
        }
        Request::InvokePluginService {
            plugin_id,
            interface_id,
            operation,
            payload,
        } => {
            handle_invoke_plugin_service(
                request_id,
                state,
                writer,
                &plugin_id,
                &interface_id,
                operation,
                payload,
            )
            .await
        }
        Request::CallPluginService {
            interface_id,
            operation,
            payload,
        } => {
            handle_call_plugin_service(request_id, state, writer, &interface_id, operation, payload)
                .await
        }
        Request::PublishPluginEvent { topic, payload } => {
            handle_publish_plugin_event(request_id, state, writer, &topic, &payload).await
        }
        Request::ListWorktrees(_)
        | Request::CreateWorktree(_)
        | Request::RemoveWorktree(_)
        | Request::RalphStatus(_)
        | Request::RunRalphLoop(_)
        | Request::ApproveRalphRun(_)
        | Request::CancelRalphLoop(_)
        | Request::ListRalphRuns(_)
        | Request::ListRalphIterations(_)
        | Request::ResumeRalphRun(_)
        | Request::RalphRunStatus(_)
        | Request::RecordRalphLifecycle(_) => {
            unreachable!("primary request routed to primary handler")
        }
        _ => unreachable!("primary request routed to agent/permission/plugin handler"),
    }
}

async fn handle_permission_interaction_request(
    request: Request,
    request_id: u64,
    client_id: ClientId,
    state: &ServerState,
    writer: &SharedWriter,
) -> Result<(), ServerError> {
    match request {
        Request::ListPermissions => handle_list_permissions(request_id, state, writer).await,
        Request::ResolvePermission {
            permission_id,
            approved,
            remember,
        } => {
            handle_resolve_permission(
                request_id,
                state,
                writer,
                &permission_id,
                approved,
                remember,
            )
            .await
        }
        Request::ResolvePermissionBatch { batch_id, approved } => {
            handle_resolve_permission_batch(request_id, state, writer, &batch_id, approved).await
        }
        Request::ListPendingToolExchanges => {
            handle_list_pending_tool_exchanges(request_id, state, writer).await
        }
        Request::ResolveToolExchange {
            exchange_id,
            resolution_json,
        } => {
            let resolution = serde_json::from_value(resolution_json)?;
            handle_resolve_tool_exchange(
                request_id,
                client_id,
                state,
                writer,
                &exchange_id,
                resolution,
            )
            .await
        }
        _ => unreachable!("request routed to permission/interaction handler"),
    }
}

const MAX_CLIENT_INTERACTION_ADAPTERS: usize = 64;
const MAX_INTERACTION_ADAPTER_IDENTIFIER_BYTES: usize = 128;

fn validate_client_interaction_adapters(
    context: Option<&ClientRuntimeContext>,
) -> Result<(), &'static str> {
    let Some(context) = context else {
        return Ok(());
    };
    if context.interaction_adapters.len() > MAX_CLIENT_INTERACTION_ADAPTERS {
        return Err("too many interaction adapters");
    }
    let mut routes = BTreeSet::new();
    for adapter in &context.interaction_adapters {
        let identifiers = [
            adapter.producer_id.as_str(),
            adapter.exchange_schema.as_str(),
            adapter.platform_id.as_str(),
            adapter.interaction_kind.as_str(),
        ];
        if identifiers
            .iter()
            .any(|value| value.is_empty() || value.len() > MAX_INTERACTION_ADAPTER_IDENTIFIER_BYTES)
            || adapter.tui_surface_kind.as_deref().is_some_and(|value| {
                value.is_empty() || value.len() > MAX_INTERACTION_ADAPTER_IDENTIFIER_BYTES
            })
        {
            return Err("interaction adapter identifiers must be non-empty and at most 128 bytes");
        }
        if adapter.min_schema_version == 0
            || adapter.max_schema_version < adapter.min_schema_version
        {
            return Err("interaction adapter schema version range must be positive and ordered");
        }
        if !routes.insert((
            adapter.producer_id.as_str(),
            adapter.exchange_schema.as_str(),
            adapter.min_schema_version,
            adapter.max_schema_version,
            adapter.platform_id.as_str(),
            adapter.priority,
        )) {
            return Err("duplicate interaction adapter route");
        }
    }
    Ok(())
}

async fn handle_update_client_runtime_context(
    request_id: u64,
    client_id: ClientId,
    state: &ServerState,
    writer: &SharedWriter,
    runtime_context: Option<ClientRuntimeContext>,
) -> Result<(), ServerError> {
    if let Err(message) = validate_client_interaction_adapters(runtime_context.as_ref()) {
        return send_response(
            writer,
            request_id,
            Response::Err(ErrorResponse::new("invalid_interaction_adapters", message)),
        )
        .await;
    }
    state
        .set_client_runtime_context(client_id, runtime_context)
        .await;
    send_response(
        writer,
        request_id,
        Response::Ok(ResponsePayload::ClientRuntimeContextUpdated),
    )
    .await
}

async fn handle_ping(request_id: u64, writer: &SharedWriter) -> Result<(), ServerError> {
    send_response(writer, request_id, Response::Ok(ResponsePayload::Pong)).await
}

async fn handle_ingest_client_metrics(
    request_id: u64,
    state: &ServerState,
    writer: &SharedWriter,
    batch: bcode_metrics::ClientMetricBatch,
) -> Result<(), ServerError> {
    if let Err(error) = batch.validate_for_namespace("tui.") {
        return send_response(
            writer,
            request_id,
            Response::Err(ErrorResponse::new(
                "invalid_client_metrics",
                error.to_string(),
            )),
        )
        .await;
    }
    let accepted = batch.observations.len();
    state.metrics.record_client_batch(batch);
    send_response(
        writer,
        request_id,
        Response::Ok(ResponsePayload::ClientMetricsIngested { accepted }),
    )
    .await
}

fn client_name_supports_message_accepted(client_name: &str) -> bool {
    client_name
        .split(';')
        .any(|part| part.trim() == "cap=message_accepted")
}

async fn handle_hello(
    request_id: u64,
    client_id: ClientId,
    state: &ServerState,
    writer: &SharedWriter,
    client_name: &str,
    runtime_context: Option<ClientRuntimeContext>,
    daemon_namespace: String,
) -> Result<(), ServerError> {
    if let Err(message) = validate_client_interaction_adapters(runtime_context.as_ref()) {
        return send_response(
            writer,
            request_id,
            Response::Err(ErrorResponse::new("invalid_interaction_adapters", message)),
        )
        .await;
    }
    if client_name_supports_message_accepted(client_name) {
        state.register_message_accepted_client(client_id).await;
    }
    state
        .set_client_runtime_context(client_id, runtime_context)
        .await;
    state
        .set_client_session_namespace(client_id, daemon_namespace)
        .await;
    send_response(
        writer,
        request_id,
        Response::Ok(ResponsePayload::Hello {
            protocol_version: bcode_ipc::ProtocolVersion::current(),
            client_id,
            daemon: state.daemon_status.clone(),
        }),
    )
    .await
}

async fn handle_server_status(
    request_id: u64,
    state: &ServerState,
    writer: &SharedWriter,
    working_directory: Option<&Path>,
) -> Result<(), ServerError> {
    let status = state.status(working_directory).await;
    send_response(
        writer,
        request_id,
        Response::Ok(ResponsePayload::ServerStatus { status }),
    )
    .await
}

async fn handle_model_catalog_diagnostics(
    request_id: u64,
    state: &ServerState,
    writer: &SharedWriter,
) -> Result<(), ServerError> {
    let diagnostics = state.model_catalog.diagnostics().await;
    let epoch_ms = |time: Option<std::time::SystemTime>| {
        time.and_then(|value| value.duration_since(std::time::UNIX_EPOCH).ok())
            .and_then(|value| u64::try_from(value.as_millis()).ok())
    };
    send_response(
        writer,
        request_id,
        Response::Ok(ResponsePayload::ModelCatalogDiagnostics {
            embedded_revision: diagnostics.embedded_revision,
            remote_revision: diagnostics.remote_revision,
            remote_enabled: diagnostics.remote_enabled,
            cache_state: format!("{:?}", diagnostics.cache_state).to_lowercase(),
            cache_age_seconds: diagnostics.cache_age.map(|age| age.as_secs()),
            refresh_in_progress: diagnostics.refresh_in_progress,
            last_refresh_attempt_ms: epoch_ms(diagnostics.last_refresh_attempt),
            last_refresh_success_ms: epoch_ms(diagnostics.last_refresh_success),
            last_refresh_error: diagnostics.last_refresh_error,
        }),
    )
    .await
}

fn active_migration_shutdown_blocker(active_migrations: usize) -> Option<String> {
    (active_migrations > 0).then(|| {
        format!(
            "daemon has {active_migrations} active session migration(s); refusing shutdown until migration completes"
        )
    })
}

async fn handle_release_session_database(
    request_id: u64,
    state: &ServerState,
    writer: &SharedWriter,
    session_id: SessionId,
) -> Result<(), ServerError> {
    let released = state
        .release_session_database_if_inactive(session_id)
        .await?;
    send_response(
        writer,
        request_id,
        Response::Ok(ResponsePayload::SessionDatabaseReleased {
            session_id,
            released,
        }),
    )
    .await
}

async fn handle_server_stop(
    request_id: u64,
    state: &ServerState,
    writer: &SharedWriter,
    mode: ServerStopMode,
) -> Result<(), ServerError> {
    if let Some(message) = state.active_migration_shutdown_blocker().await {
        return send_response(
            writer,
            request_id,
            Response::Err(ErrorResponse::new("daemon_busy", message)),
        )
        .await;
    }
    if mode == ServerStopMode::IfIdle
        && let Some(message) = state.idle_shutdown_blocker().await
    {
        return send_response(
            writer,
            request_id,
            Response::Err(ErrorResponse::new("daemon_busy", message)),
        )
        .await;
    }
    send_response(
        writer,
        request_id,
        Response::Ok(ResponsePayload::ServerStopping),
    )
    .await?;
    state.request_shutdown();
    Ok(())
}

