async fn handle_describe_skill(
    request_id: u64,
    state: &ServerState,
    writer: &SharedWriter,
    skill_id: &SkillId,
) -> Result<(), ServerError> {
    let Some(registry) = &state.skills else {
        return send_response(
            writer,
            request_id,
            Response::Err(ErrorResponse {
                code: "skills_disabled".to_string(),
                message: "skills are disabled".to_string(),
            }),
        )
        .await;
    };
    match registry.describe(skill_id) {
        Ok(skill) => {
            send_response(
                writer,
                request_id,
                Response::Ok(ResponsePayload::SkillManifest {
                    skill: Box::new(skill),
                }),
            )
            .await
        }
        Err(error) => {
            send_response(
                writer,
                request_id,
                Response::Err(ErrorResponse {
                    code: "skill_describe_failed".to_string(),
                    message: error.to_string(),
                }),
            )
            .await
        }
    }
}

async fn handle_activate_skill(
    request_id: u64,
    state: &ServerState,
    writer: &SharedWriter,
    session_id: SessionId,
    skill_id: SkillId,
) -> Result<(), ServerError> {
    let Some(registry) = &state.skills else {
        return send_response(
            writer,
            request_id,
            Response::Err(ErrorResponse {
                code: "skills_disabled".to_string(),
                message: "skills are disabled".to_string(),
            }),
        )
        .await;
    };
    let Some(summary) = registry.summary(&skill_id).cloned() else {
        return send_response(
            writer,
            request_id,
            Response::Err(ErrorResponse {
                code: "unknown_skill".to_string(),
                message: format!("unknown skill: {skill_id}"),
            }),
        )
        .await;
    };
    if let Err(error) = apply_skill_model_policy(state, session_id, &skill_id).await {
        return send_response(writer, request_id, Response::Err(error)).await;
    }
    state
        .active_skills
        .lock()
        .await
        .entry(session_id)
        .or_default()
        .insert(skill_id.clone());
    let event = state
        .sessions
        .append_event(
            session_id,
            SessionEventKind::SkillActivated {
                skill_id,
                source: Some(summary.source),
                mode: SkillActivationMode::Explicit,
                activated_at_ms: current_time_ms(),
            },
        )
        .await?;
    publish_session_event(state, &event).await;
    send_response(
        writer,
        request_id,
        Response::Ok(ResponsePayload::SessionAgentSet),
    )
    .await
}

async fn is_skill_active(state: &ServerState, session_id: SessionId, skill_id: &SkillId) -> bool {
    state
        .active_skills
        .lock()
        .await
        .get(&session_id)
        .is_some_and(|skills| skills.contains(skill_id))
}

async fn append_skill_invocation_failed_event(
    state: &ServerState,
    session_id: SessionId,
    skill_id: SkillId,
    error: String,
) {
    if let Ok(event) = state
        .sessions
        .append_event(
            session_id,
            SessionEventKind::SkillInvocationFailed {
                skill_id,
                error,
                failed_at_ms: current_time_ms(),
            },
        )
        .await
    {
        publish_session_event(state, &event).await;
    }
}

async fn required_model_active_skill(
    state: &ServerState,
    session_id: SessionId,
) -> Option<SkillId> {
    let registry = state.skills.as_ref()?;
    let active_skill_ids = state.active_skills.lock().await.get(&session_id)?.clone();
    for skill_id in active_skill_ids {
        if registry
            .describe(&skill_id)
            .is_ok_and(|manifest| manifest.model_policy.required.is_some())
        {
            return Some(skill_id);
        }
    }
    None
}

async fn apply_skill_model_policy(
    state: &ServerState,
    session_id: SessionId,
    skill_id: &SkillId,
) -> Result<(), ErrorResponse> {
    let Some(registry) = &state.skills else {
        return Ok(());
    };
    let manifest = registry.describe(skill_id).map_err(|error| {
        ErrorResponse::new(
            "skill_describe_failed",
            format!("failed to load skill model policy for {skill_id}: {error}"),
        )
    })?;
    if let Some(required) = manifest.model_policy.required.as_ref() {
        apply_skill_model_request(state, session_id, skill_id, required, true).await?;
    } else if let Some(preferred) = manifest.model_policy.preferred.as_ref()
        && skill_preferred_model_can_apply(state, session_id).await
    {
        apply_skill_model_request(state, session_id, skill_id, preferred, false).await?;
    } else {
        // Skill declares no required or preferred model.
        // Explicitly ensure the turn uses the user's currently selected model
        // and does not fall back to provider defaults such as default_codex_model_id.
        ensure_skill_turn_respects_active_selection(state, session_id).await?;
    }
    Ok(())
}

async fn skill_preferred_model_can_apply(state: &ServerState, session_id: SessionId) -> bool {
    matches!(
        state
            .session_model_selection_origins
            .lock()
            .await
            .get(&session_id)
            .cloned()
            .unwrap_or_default(),
        SessionModelSelectionOrigin::Default
    )
}

/// When a skill declares neither required nor preferred model, ensure the
/// upcoming turn respects the user's active selection and does not resolve
/// through provider defaults such as `default_codex_model_id`.
async fn ensure_skill_turn_respects_active_selection(
    state: &ServerState,
    session_id: SessionId,
) -> Result<(), ErrorResponse> {
    // If the session already has an explicit user/model origin, nothing to do.
    let origin = state
        .session_model_selection_origins
        .lock()
        .await
        .get(&session_id)
        .cloned()
        .unwrap_or_default();

    if !matches!(origin, SessionModelSelectionOrigin::Default) {
        return Ok(());
    }

    // Re-assert the current selection by emitting a model-changed event
    // using the resolved provider/model from the active selection.
    // This guarantees that Codex/default surfaces are not consulted later.
    let selection = session_model_selection(state, session_id).await;
    let provider = selection
        .provider_plugin_id
        .clone()
        .unwrap_or_else(|| "<auto>".to_string());
    let model = selection
        .model_id
        .clone()
        .unwrap_or_else(|| "<default>".to_string());

    // Only emit if we have a concrete model id to anchor on.
    if selection.model_id.is_some()
        && let Ok(event) = state
            .sessions
            .append_model_changed(session_id, provider, model)
            .await
    {
        publish_session_event(state, &event).await;
    }
    Ok(())
}

async fn apply_skill_model_request(
    state: &ServerState,
    session_id: SessionId,
    skill_id: &SkillId,
    request: &SkillModelRequest,
    required: bool,
) -> Result<(), ErrorResponse> {
    let Some((provider, model_id)) = resolve_skill_model_request(state, skill_id, request).await
    else {
        handle_unresolved_skill_model(state, skill_id, request, required)?;
        return Ok(());
    };
    if required {
        let previous_selection = session_model_selection(state, session_id).await;
        let previous_origin = state
            .session_model_selection_origins
            .lock()
            .await
            .get(&session_id)
            .cloned()
            .unwrap_or_default();
        state
            .required_skill_model_overrides
            .lock()
            .await
            .entry((session_id, skill_id.clone()))
            .or_insert(RequiredSkillModelOverride {
                selection: previous_selection,
                origin: previous_origin,
            });
    }
    let event = state
        .sessions
        .append_model_changed(session_id, provider.clone(), model_id.clone())
        .await
        .map_err(|error| session_error_response(&error))?;
    let mut selection = SessionModelSelection {
        provider_plugin_id: provider_to_selection(&provider),
        requested_model_id: None,
        model_id: model_to_selection(&model_id),
        thinking_level: None,
        reasoning_effort: state.selected_reasoning.effort.clone(),
        reasoning_summary: state.selected_reasoning.summary.clone(),
        reasoning_capabilities: state.selected_reasoning_capabilities.clone(),
        provider_context: state.selected_provider_context.clone(),
    };
    if let Some(effort) = request.thinking_effort.as_ref() {
        selection.reasoning_effort = effort.provider_value.clone().or_else(|| {
            effort
                .normalized_level
                .map(|level| format!("{level:?}").to_lowercase())
        });
    }
    state
        .session_model_selections
        .lock()
        .await
        .insert(session_id, selection);
    let origin = if required {
        SessionModelSelectionOrigin::SkillRequired(skill_id.clone())
    } else {
        SessionModelSelectionOrigin::SkillPreferred(skill_id.clone())
    };
    state
        .session_model_selection_origins
        .lock()
        .await
        .insert(session_id, origin);
    publish_session_event(state, &event).await;
    if required {
        tracing::warn!(
            "skill required model applied for session {session_id}: {} via {}",
            request.model,
            provider
        );
    }
    Ok(())
}

fn handle_unresolved_skill_model(
    state: &ServerState,
    skill_id: &SkillId,
    request: &SkillModelRequest,
    required: bool,
) -> Result<(), ErrorResponse> {
    match unresolved_model_behavior(state, skill_id, required) {
        bcode_config::SkillUnresolvedModelBehavior::Deny => {
            let kind = if required { "required" } else { "preferred" };
            Err(ErrorResponse::new(
                "skill_model_unresolved",
                format!(
                    "{kind} model '{}' for skill {skill_id} could not be resolved",
                    request.model
                ),
            ))
        }
        bcode_config::SkillUnresolvedModelBehavior::Warn => {
            let message = if required {
                "continuing by configuration"
            } else {
                "keeping current session model"
            };
            tracing::warn!(
                "{} model '{}' for skill {skill_id} could not be resolved; {message}",
                if required { "required" } else { "preferred" },
                request.model
            );
            Ok(())
        }
        bcode_config::SkillUnresolvedModelBehavior::Ignore => Ok(()),
    }
}

async fn resolve_skill_model_request(
    state: &ServerState,
    skill_id: &SkillId,
    request: &SkillModelRequest,
) -> Option<(String, String)> {
    let provider_candidates = skill_model_provider_candidates(state, skill_id, request);
    for provider in provider_candidates {
        if skill_model_exists(state, provider.as_deref(), &request.model).await {
            return Some((
                provider.unwrap_or_else(|| "<auto>".to_string()),
                request.model.clone(),
            ));
        }
    }
    None
}

fn skill_model_provider_candidates(
    state: &ServerState,
    skill_id: &SkillId,
    request: &SkillModelRequest,
) -> Vec<Option<String>> {
    if let Some(provider) = request.provider.clone() {
        return vec![Some(provider)];
    }
    let mut providers = Vec::new();
    for provider in provider_fallback_for_skill(state, skill_id) {
        push_unique_provider(&mut providers, Some(provider));
    }
    if let Some(provider) = state.selected_provider_plugin_id.clone() {
        push_unique_provider(&mut providers, Some(provider));
    }
    push_unique_provider(&mut providers, None);
    providers
}

fn push_unique_provider(providers: &mut Vec<Option<String>>, provider: Option<String>) {
    if !providers.contains(&provider) {
        providers.push(provider);
    }
}

fn provider_fallback_for_skill(state: &ServerState, skill_id: &SkillId) -> Vec<String> {
    state
        .skill_model_policy
        .skill
        .get(skill_id.as_str())
        .filter(|policy| !policy.provider_fallback.is_empty())
        .map_or_else(
            || state.skill_model_policy.provider_fallback.clone(),
            |policy| policy.provider_fallback.clone(),
        )
}

fn required_model_override_behavior(
    state: &ServerState,
    skill_id: &SkillId,
) -> bcode_config::SkillRequiredModelOverride {
    state
        .skill_model_policy
        .skill
        .get(skill_id.as_str())
        .and_then(|policy| policy.required_override)
        .unwrap_or(state.skill_model_policy.required_override)
}

fn unresolved_model_behavior(
    state: &ServerState,
    skill_id: &SkillId,
    required: bool,
) -> bcode_config::SkillUnresolvedModelBehavior {
    let skill_policy = state.skill_model_policy.skill.get(skill_id.as_str());
    if required {
        skill_policy
            .and_then(|policy| policy.required_unresolved)
            .unwrap_or(state.skill_model_policy.required_unresolved)
    } else {
        skill_policy
            .and_then(|policy| policy.preferred_unresolved)
            .unwrap_or(state.skill_model_policy.preferred_unresolved)
    }
}

async fn skill_model_exists(
    state: &ServerState,
    provider_plugin_id: Option<&str>,
    model_id: &str,
) -> bool {
    resolved_provider_models(
        state,
        provider_plugin_id.map(ToOwned::to_owned),
        bcode_model::ModelListRequest {
            provider_context: state.selected_provider_context.clone(),
            selected_model_id: Some(model_id.to_string()),
        },
    )
    .await
    .is_ok_and(|models| models.models.iter().any(|model| model.model_id == model_id))
}

async fn handle_deactivate_skill(
    request_id: u64,
    state: &ServerState,
    writer: &SharedWriter,
    session_id: SessionId,
    skill_id: SkillId,
) -> Result<(), ServerError> {
    if let Some(skills) = state.active_skills.lock().await.get_mut(&session_id) {
        skills.remove(&skill_id);
    }
    restore_skill_model_override(state, session_id, &skill_id).await?;
    let event = state
        .sessions
        .append_event(
            session_id,
            SessionEventKind::SkillDeactivated {
                skill_id,
                deactivated_at_ms: current_time_ms(),
            },
        )
        .await?;
    publish_session_event(state, &event).await;
    send_response(
        writer,
        request_id,
        Response::Ok(ResponsePayload::SessionAgentSet),
    )
    .await
}

async fn restore_skill_model_override(
    state: &ServerState,
    session_id: SessionId,
    skill_id: &SkillId,
) -> Result<(), ServerError> {
    restore_required_skill_model_override(state, session_id, skill_id).await?;
    restore_preferred_skill_model_override(state, session_id, skill_id).await
}

async fn restore_required_skill_model_override(
    state: &ServerState,
    session_id: SessionId,
    skill_id: &SkillId,
) -> Result<(), ServerError> {
    let Some(previous_override) = state
        .required_skill_model_overrides
        .lock()
        .await
        .remove(&(session_id, skill_id.clone()))
    else {
        return Ok(());
    };
    let provider = previous_override
        .selection
        .provider_plugin_id
        .clone()
        .unwrap_or_else(|| "<auto>".to_string());
    let model = previous_override
        .selection
        .model_id
        .clone()
        .unwrap_or_else(|| "<default>".to_string());
    let event = state
        .sessions
        .append_model_changed(session_id, provider, model)
        .await?;
    state
        .session_model_selections
        .lock()
        .await
        .insert(session_id, previous_override.selection);
    state
        .session_model_selection_origins
        .lock()
        .await
        .insert(session_id, previous_override.origin);
    publish_session_event(state, &event).await;
    Ok(())
}

async fn restore_preferred_skill_model_override(
    state: &ServerState,
    session_id: SessionId,
    skill_id: &SkillId,
) -> Result<(), ServerError> {
    let origin = state
        .session_model_selection_origins
        .lock()
        .await
        .get(&session_id)
        .cloned()
        .unwrap_or_default();
    if origin != SessionModelSelectionOrigin::SkillPreferred(skill_id.clone()) {
        return Ok(());
    }
    let provider = state
        .selected_provider_plugin_id
        .clone()
        .unwrap_or_else(|| "<auto>".to_string());
    let model = state
        .selected_model_id
        .clone()
        .unwrap_or_else(|| "<default>".to_string());
    let event = state
        .sessions
        .append_model_changed(session_id, provider, model)
        .await?;
    state
        .session_model_selections
        .lock()
        .await
        .remove(&session_id);
    state
        .session_model_selection_origins
        .lock()
        .await
        .insert(session_id, SessionModelSelectionOrigin::Default);
    publish_session_event(state, &event).await;
    Ok(())
}

