fn dispatch_provider_turn_cleanup(
    plugins: bcode_plugin::PluginRuntimeHost,
    metrics: MetricsRegistry,
    provider_plugin_id: String,
    request: CancelTurnRequest,
    scope: PluginInvocationScope,
) {
    tokio::spawn(async move {
        let started_at = Instant::now();
        let result = plugins
            .invoke_service_json_scoped::<_, bcode_model::AckResponse>(
                &provider_plugin_id,
                MODEL_PROVIDER_INTERFACE_ID,
                OP_CANCEL_TURN,
                &request,
                scope,
            )
            .await;
        let outcome = if result.is_ok() {
            "completed"
        } else {
            "failed"
        };
        let mut labels = MetricLabels::new();
        labels.insert("cleanup_kind".to_owned(), "provider_turn".to_owned());
        labels.insert("outcome".to_owned(), outcome.to_owned());
        metrics.add_counter_with_labels("provider.cleanup_total", 1, labels.clone());
        metrics.record_histogram_with_labels(
            "provider.cleanup_duration_ms",
            elapsed_ms(started_at),
            labels,
        );
        match result {
            Ok(_) => tracing::debug!(
                target: "bcode_server::cleanup",
                plugin_id = %provider_plugin_id,
                provider_turn_id = %request.provider_turn_id,
                "detached provider cleanup completed"
            ),
            Err(error) => tracing::warn!(
                target: "bcode_server::cleanup",
                plugin_id = %provider_plugin_id,
                provider_turn_id = %request.provider_turn_id,
                %error,
                "detached provider cleanup failed"
            ),
        }
    });
}

async fn finish_session_turn_cancellation(
    state: &ServerState,
    session_id: SessionId,
    current_turn: RuntimeCurrentTurn,
    requested_by: Option<ClientId>,
) {
    current_turn.cancel_state.wait_for_commit_boundary().await;
    if current_turn.kind == RuntimeOperationKind::ModelTurn
        && let Some(model) = current_turn.model.as_ref()
    {
        let provider_plugin_id = Some(model.identity.provider_plugin_id.clone()).or_else(|| {
            state
                .plugins
                .registry()
                .service_registry()
                .unique_provider(MODEL_PROVIDER_INTERFACE_ID)
                .ok()
                .map(ToString::to_string)
        });
        if let Some(provider_plugin_id) = provider_plugin_id {
            dispatch_provider_turn_cleanup(
                state.plugins.clone(),
                state.metrics.clone(),
                provider_plugin_id,
                CancelTurnRequest {
                    provider_turn_id: model.provider_turn_id.clone(),
                },
                current_turn.plugin_scope_for_provider(session_id),
            );
        }
    }
    let turn_id = current_turn.turn_id;
    if current_turn.kind == RuntimeOperationKind::ModelTurn {
        append_model_turn_cancel_requested_event(state, session_id, turn_id.clone(), requested_by)
            .await;
        cancel_registered_runtime_work(
            state,
            session_id,
            WorkId::new(format!("model_{turn_id}")),
            requested_by,
        )
        .await;
    }
}

