async fn update_provider_usage_state(
    state: &ServerState,
    session_id: SessionId,
    usage: &TokenUsage,
) {
    let reuse_key = state
        .active_model_turn_snapshot(session_id)
        .await
        .and_then(|turn| turn.reuse_key);
    let Some(reuse_key) = reuse_key else {
        return;
    };

    let mut provider_state = state.provider_state.lock().await;
    let record = provider_state.records.entry(reuse_key).or_default();
    record.session_id = Some(session_id);
    record.telemetry = ProviderTelemetryState {
        input: usage.input_tokens,
        cached: usage.cached_input_tokens,
        cache_write: usage.cache_write_input_tokens,
        uncached: usage.uncached_input_tokens(),
    };
    provider_state.save();
}

async fn update_provider_metadata_state(
    state: &ServerState,
    session_id: SessionId,
    key: &str,
    value: String,
    reusable_message_count: Option<usize>,
    rebase_on_next_projection: bool,
) {
    let reuse_key = state
        .active_model_turn_snapshot(session_id)
        .await
        .and_then(|turn| turn.reuse_key);
    let Some(reuse_key) = reuse_key else {
        return;
    };

    if key == "provider_state" {
        let Ok(provider_state_value) = serde_json::from_str::<serde_json::Value>(&value) else {
            return;
        };
        let mut provider_state = state.provider_state.lock().await;
        let record = provider_state.records.entry(reuse_key).or_default();
        record.session_id = Some(session_id);
        record.provider_state = Some(provider_state_value);
        provider_state.save();
        drop(provider_state);
        return;
    }

    if key != "provider_response_id" {
        return;
    }
    let reusable_message_count = match reusable_message_count {
        Some(message_count) => message_count,
        None => state
            .active_model_turn_snapshot(session_id)
            .await
            .map_or(0, |turn| turn.request_message_count.saturating_add(1)),
    };

    let mut provider_state = state.provider_state.lock().await;
    let record = provider_state.records.entry(reuse_key).or_default();
    record.session_id = Some(session_id);
    record.continuation = Some(ProviderContinuationState {
        provider_response_id: value,
        reusable_message_count,
        updated_sequence: reusable_message_count.try_into().unwrap_or(u64::MAX),
        rebase_on_next_projection,
    });
    provider_state.save();
}

async fn agent_policy_status(state: &ServerState) -> Option<PolicyStatusResponse> {
    let mut status = state
        .plugins
        .invoke_service_by_interface_json::<_, PolicyStatusResponse>(
            AGENT_PROFILE_INTERFACE_ID,
            OP_POLICY_STATUS,
            &serde_json::json!({}),
        )
        .await
        .ok()?;
    let discovered_tools = collect_available_tool_names(state).await;
    append_missing_enabled_tool_diagnostics(&mut status, &discovered_tools);
    Some(status)
}

async fn collect_available_tool_names(state: &ServerState) -> BTreeSet<String> {
    collect_tool_definitions(state)
        .await
        .into_iter()
        .map(|tool| tool.name)
        .collect()
}

fn append_missing_enabled_tool_diagnostics(
    status: &mut PolicyStatusResponse,
    discovered_tools: &BTreeSet<String>,
) {
    for (agent_id, enabled_tools) in [
        ("build", &status.build_enabled_tools),
        ("plan", &status.plan_enabled_tools),
    ] {
        for tool_id in enabled_tools {
            if !discovered_tools.contains(tool_id) {
                status.diagnostics.push(format!(
                    "agent '{agent_id}' enables tool '{tool_id}' but no loaded tool plugin provides it"
                ));
            }
        }
    }
}

async fn list_agent_profiles(state: &ServerState) -> Vec<AgentInfo> {
    state
        .plugins
        .invoke_service_by_interface_json::<_, AgentList>(
            AGENT_PROFILE_INTERFACE_ID,
            OP_LIST_AGENTS,
            &serde_json::json!({}),
        )
        .await
        .ok()
        .map_or_else(default_agent_profiles, |list| list.agents)
}

async fn warn_on_unregistered_agent_ids(state: &ServerState, configured_agent_ids: &[String]) {
    if configured_agent_ids.is_empty() {
        return;
    }
    let registered: BTreeSet<String> = list_agent_profiles(state)
        .await
        .into_iter()
        .flat_map(|agent| std::iter::once(agent.id).chain(agent.aliases))
        .collect();
    for agent_id in configured_agent_ids {
        if !registered.contains(agent_id) {
            tracing::warn!(
                target: "bcode_server::startup",
                agent_id = %agent_id,
                "agent defined in bcode.toml but not registered by any agent-profile plugin; it will be usable via /agent {agent_id} but won't appear in agent pickers"
            );
        }
    }
}

fn default_agent_profiles() -> Vec<AgentInfo> {
    vec![AgentInfo {
        id: "build".to_string(),
        name: "Build".to_string(),
        description: "Default implementation agent".to_string(),
        badge: Some("build".to_string()),
        accent: None,
        aliases: vec!["build".to_string()],
        is_default: true,
    }]
}

async fn resolve_agent_id(state: &ServerState, agent_id: &str) -> Option<String> {
    list_agent_profiles(state)
        .await
        .into_iter()
        .find_map(|agent| {
            (agent.id == agent_id || agent.aliases.iter().any(|alias| alias == agent_id))
                .then_some(agent.id)
        })
}

async fn session_agent_selection(state: &ServerState, session_id: SessionId) -> String {
    if let Some(agent_id) = state.session_agent_selections.lock().await.get(&session_id) {
        return agent_id.clone();
    }
    let selected =
        if let Ok(Some(agent_id)) = state.sessions.current_agent_selection(session_id).await {
            agent_id
        } else {
            default_agent_id(&list_agent_profiles(state).await)
        };
    state
        .session_agent_selections
        .lock()
        .await
        .insert(session_id, selected.clone());
    selected
}

fn default_agent_id(agents: &[AgentInfo]) -> String {
    agents
        .iter()
        .find(|agent| agent.is_default)
        .or_else(|| agents.first())
        .map_or_else(|| "build".to_string(), |agent| agent.id.clone())
}

async fn agent_context(
    state: &ServerState,
    session_id: SessionId,
    agent_id: &str,
) -> Option<AgentContextResponse> {
    let request = AgentContextRequest {
        session_id,
        agent_id: agent_id.to_string(),
        available_tools: collect_tool_definitions(state).await,
    };
    state
        .plugins
        .invoke_service_by_interface_json::<_, AgentContextResponse>(
            AGENT_PROFILE_INTERFACE_ID,
            OP_AGENT_CONTEXT,
            &request,
        )
        .await
        .ok()
}

async fn session_model_selection_with_runtime_context(
    state: &ServerState,
    session_id: SessionId,
    runtime_context: Option<ClientRuntimeContext>,
) -> SessionModelSelection {
    let mut selection = session_model_selection(state, session_id).await;
    if let Some(context) = runtime_context {
        if selection.provider_plugin_id.is_none() {
            selection.provider_plugin_id = context.selected_provider_plugin_id;
        }
        if selection.model_id.is_none() {
            selection.model_id = context.selected_model_id;
        }
        if selection.requested_model_id.is_none() {
            selection.requested_model_id = context.requested_model_id;
        }
        selection.provider_context = context.provider_context;
    }
    selection
}

fn default_model_selection_with_runtime_context(
    state: &ServerState,
    runtime_context: Option<ClientRuntimeContext>,
) -> SessionModelSelection {
    if let Some(context) = runtime_context {
        return model_selection_from_runtime_context(state, context);
    }
    SessionModelSelection {
        provider_plugin_id: state.selected_provider_plugin_id.clone(),
        requested_model_id: None,
        model_id: state.selected_model_id.clone(),
        thinking_level: None,
        reasoning_effort: state.selected_reasoning.effort.clone(),
        reasoning_summary: state.selected_reasoning.summary.clone(),
        reasoning_capabilities: state.selected_reasoning_capabilities.clone(),
        provider_context: state.selected_provider_context.clone(),
    }
}

fn model_selection_from_runtime_context(
    state: &ServerState,
    context: ClientRuntimeContext,
) -> SessionModelSelection {
    SessionModelSelection {
        provider_plugin_id: context.selected_provider_plugin_id,
        requested_model_id: context.requested_model_id,
        model_id: context.selected_model_id,
        thinking_level: None,
        reasoning_effort: state.selected_reasoning.effort.clone(),
        reasoning_summary: state.selected_reasoning.summary.clone(),
        reasoning_capabilities: state.selected_reasoning_capabilities.clone(),
        provider_context: context.provider_context,
    }
}

async fn session_model_selection(
    state: &ServerState,
    session_id: SessionId,
) -> SessionModelSelection {
    if let Some(selection) = state.session_model_selections.lock().await.get(&session_id) {
        return selection.clone();
    }
    let fallback_runtime_selection = || bcode_session::SessionRuntimeSelection {
        agent_id: None,
        provider_plugin_id: state.selected_provider_plugin_id.clone(),
        model_id: state.selected_model_id.clone(),
        reasoning_effort: state.selected_reasoning.effort.clone(),
        reasoning_summary: state.selected_reasoning.summary.clone(),
    };
    let runtime_selection = state
        .sessions
        .current_runtime_selection(session_id)
        .await
        .unwrap_or_else(|_| fallback_runtime_selection());
    let selection = SessionModelSelection {
        provider_plugin_id: runtime_selection
            .provider_plugin_id
            .as_deref()
            .and_then(provider_to_selection)
            .or_else(|| state.selected_provider_plugin_id.clone()),
        requested_model_id: runtime_selection
            .model_id
            .as_deref()
            .and_then(model_to_selection),
        model_id: runtime_selection
            .model_id
            .as_deref()
            .and_then(model_to_selection)
            .or_else(|| state.selected_model_id.clone()),
        thinking_level: None,
        reasoning_effort: runtime_selection
            .reasoning_effort
            .or_else(|| state.selected_reasoning.effort.clone()),
        reasoning_summary: runtime_selection
            .reasoning_summary
            .or_else(|| state.selected_reasoning.summary.clone()),
        reasoning_capabilities: state.selected_reasoning_capabilities.clone(),
        provider_context: state.selected_provider_context.clone(),
    };
    let origin = if runtime_selection
        .model_id
        .as_deref()
        .and_then(model_to_selection)
        .is_some()
        || runtime_selection
            .provider_plugin_id
            .as_deref()
            .and_then(provider_to_selection)
            .is_some()
    {
        SessionModelSelectionOrigin::User
    } else {
        SessionModelSelectionOrigin::Default
    };
    state
        .session_model_selections
        .lock()
        .await
        .insert(session_id, selection.clone());
    state
        .session_model_selection_origins
        .lock()
        .await
        .entry(session_id)
        .or_insert(origin);
    selection
}

fn provider_to_selection(provider: &str) -> Option<String> {
    if provider == "<auto>" || provider.is_empty() {
        None
    } else {
        Some(provider.to_string())
    }
}

fn model_to_selection(model: &str) -> Option<String> {
    if model == "<default>" || model.is_empty() {
        None
    } else {
        Some(model.to_string())
    }
}

async fn session_runtime_selection_payload(
    state: &ServerState,
    session_id: SessionId,
) -> bcode_ipc::SessionRuntimeSelection {
    state
        .sessions
        .current_runtime_selection(session_id)
        .await
        .map(|selection| bcode_ipc::SessionRuntimeSelection {
            agent_id: selection.agent_id,
            provider_plugin_id: selection
                .provider_plugin_id
                .as_deref()
                .and_then(provider_to_selection),
            requested_model_id: selection.model_id.as_deref().and_then(model_to_selection),
            effective_model_id: selection.model_id.as_deref().and_then(model_to_selection),
            model_id: selection.model_id.as_deref().and_then(model_to_selection),
            reasoning_effort: selection.reasoning_effort,
            reasoning_summary: selection.reasoning_summary,
        })
        .unwrap_or_default()
}

fn has_model_provider(state: &ServerState, provider_plugin_id: Option<&str>) -> bool {
    if let Some(provider_plugin_id) = provider_plugin_id {
        return state
            .plugins
            .registry()
            .manifests()
            .get(provider_plugin_id)
            .is_some_and(|manifest| {
                manifest
                    .services
                    .iter()
                    .any(|service| service.interface_id == MODEL_PROVIDER_INTERFACE_ID)
            });
    }
    state
        .plugins
        .registry()
        .service_registry()
        .providers_for(MODEL_PROVIDER_INTERFACE_ID)
        .is_some()
}

async fn invoke_model_provider_json_blocking<Q, R>(
    state: &ServerState,
    provider_plugin_id: Option<String>,
    operation: &'static str,
    request: Q,
) -> Result<R, String>
where
    Q: serde::Serialize + Send + Sync + 'static,
    R: serde::de::DeserializeOwned + Send + 'static,
{
    invoke_model_provider_json_blocking_scoped(
        state,
        provider_plugin_id,
        operation,
        request,
        PluginInvocationScope::Global,
    )
    .await
}

async fn invoke_model_provider_json_blocking_scoped<Q, R>(
    state: &ServerState,
    provider_plugin_id: Option<String>,
    operation: &'static str,
    request: Q,
    scope: PluginInvocationScope,
) -> Result<R, String>
where
    Q: serde::Serialize + Send + Sync + 'static,
    R: serde::de::DeserializeOwned + Send + 'static,
{
    let provider_plugin_id = if let Some(provider_plugin_id) = provider_plugin_id.as_deref() {
        provider_plugin_id
    } else {
        state
            .plugins
            .registry()
            .service_registry()
            .unique_provider(MODEL_PROVIDER_INTERFACE_ID)
            .map_err(|error| error.to_string())?
    };
    let mut labels = MetricLabels::new();
    labels.insert(
        "provider_plugin_id".to_owned(),
        provider_plugin_id.to_owned(),
    );
    labels.insert("operation".to_owned(), operation.to_owned());
    labels.insert("scope".to_owned(), plugin_scope_kind(&scope).to_owned());
    state
        .metrics
        .time_result_async(
            "model.provider.service",
            labels,
            state.plugins.invoke_service_json_scoped::<_, R>(
                provider_plugin_id,
                MODEL_PROVIDER_INTERFACE_ID,
                operation,
                &request,
                scope,
            ),
        )
        .await
        .map_err(|error| error.to_string())
}

const fn plugin_scope_kind(scope: &PluginInvocationScope) -> &'static str {
    match scope {
        PluginInvocationScope::Global => "global",
        PluginInvocationScope::Session { .. } => "session",
    }
}

fn provider_managed_context_request(
    decision: CompactionDecision,
    context_window: Option<u32>,
    proactive_threshold_percent: u8,
    requested_max_output_tokens: Option<u32>,
    provider_max_output_tokens: Option<u32>,
) -> bcode_model::ContextManagementRequest {
    if decision.strategy != AutomaticCompactionStrategy::ProviderManaged {
        return bcode_model::ContextManagementRequest::default();
    }
    bcode_model::ContextManagementRequest {
        compact_threshold: context_window.map(|window| {
            compaction_capacity_tokens(
                window,
                proactive_threshold_percent,
                requested_max_output_tokens,
                provider_max_output_tokens,
            )
            .threshold_tokens
        }),
    }
}

#[derive(Debug, Clone)]
struct PreparedModelRequest {
    request: ModelTurnRequest,
    context_projection: bcode_session_models::RequestContextObservation,
}

#[derive(Clone)]
struct StaticModelTurnContext {
    system_prompt: String,
    system_messages: Vec<ModelMessage>,
    tools: Vec<bcode_model::ToolDefinition>,
}

fn turn_execution_options(
    trigger_event: &bcode_session_models::SessionEvent,
) -> bcode_session_models::TurnExecutionOptions {
    match &trigger_event.kind {
        SessionEventKind::UserMessage { admission, .. } => admission.execution.clone(),
        _ => bcode_session_models::TurnExecutionOptions::default(),
    }
}

fn apply_turn_model_selection(
    selection: &mut SessionModelSelection,
    execution: &bcode_session_models::TurnExecutionOptions,
) {
    if let Some(provider_plugin_id) = &execution.provider_plugin_id {
        selection.provider_plugin_id = Some(provider_plugin_id.clone());
    }
    if let Some(model_id) = &execution.model_id {
        selection.requested_model_id = Some(model_id.clone());
        selection.model_id = Some(model_id.clone());
    }
}

async fn prepare_static_model_turn_context(
    state: &ServerState,
    session_id: SessionId,
    trigger_event_sequence: u64,
    execution: &bcode_session_models::TurnExecutionOptions,
) -> Result<StaticModelTurnContext, bcode_session::SessionError> {
    let agent_id = execution
        .agent_profile
        .clone()
        .unwrap_or(session_agent_selection(state, session_id).await);
    let agent_context = agent_context(state, session_id, &agent_id).await;
    let working_directory = state.sessions.session_working_directory(session_id).await?;
    let skill_catalog = if state.system_prompt.sections.skill_catalog {
        state.skills.as_ref().map_or_else(String::new, |registry| {
            format_skill_catalog_for_prompt(&registry.list(), &state.skill_prompt_options)
        })
    } else {
        String::new()
    };
    let (system_prompt, dynamic_system_context) = build_coding_system_prompt_parts(
        &working_directory,
        &state.system_prompt,
        agent_context
            .as_ref()
            .and_then(|context| context.system_prompt_suffix.as_deref()),
        Some(&skill_catalog),
    );
    let mut system_messages = Vec::new();
    if !dynamic_system_context.is_empty() {
        system_messages.push(ModelMessage {
            role: MessageRole::System,
            content: vec![ContentBlock::Text {
                text: dynamic_system_context,
            }],
        });
    }
    for skill_context in turn_skill_contexts(state, session_id, trigger_event_sequence).await {
        let preview = skill_context_preview(&skill_context.context);
        system_messages.push(ModelMessage {
            role: MessageRole::System,
            content: vec![ContentBlock::Text {
                text: skill_context.context,
            }],
        });
        let _ = state
            .sessions
            .append_event(
                session_id,
                SessionEventKind::SkillContextLoaded {
                    skill_id: skill_context.skill_id,
                    bytes_loaded: skill_context.bytes_loaded,
                    truncated: skill_context.truncated,
                    loaded_at_ms: current_time_ms(),
                    preview: Some(preview),
                    source: Some(skill_context.source),
                },
            )
            .await;
    }
    let enabled_tools = intersect_tool_allowlists(
        agent_context
            .as_ref()
            .and_then(|context| context.enabled_tools.clone()),
        execution.tool_allowlist.as_ref(),
    );
    let tools = collect_model_tools(state, session_id, enabled_tools, execution.tools).await;
    Ok(StaticModelTurnContext {
        system_prompt,
        system_messages,
        tools,
    })
}

#[allow(clippy::too_many_arguments, clippy::too_many_lines)]
async fn build_model_turn_request(
    state: &ServerState,
    session_id: SessionId,
    trigger_event: &bcode_session_models::SessionEvent,
    execution: &bcode_session_models::TurnExecutionOptions,
    round: u32,
    provider_plugin_id: Option<&str>,
    selected_model_id: Option<&str>,
    retry_instruction: Option<&str>,
    selection: &SessionModelSelection,
    compaction_policy: &AutomaticCompactionPolicy,
    static_context: &StaticModelTurnContext,
) -> Result<PreparedModelRequest, bcode_session::SessionError> {
    let metric_labels =
        model_request_metric_labels(session_id, provider_plugin_id, selected_model_id, round);
    let build_timer = state.metrics.timer();
    let history_timer = state.metrics.timer();
    let history = state.sessions.model_context_events(session_id).await?;
    let context_through_sequence = history
        .iter()
        .map(|event| event.sequence)
        .max()
        .unwrap_or(trigger_event.sequence);
    state.metrics.record_histogram_with_labels(
        "model.request_build.load_context_events_duration_ms",
        history_timer.elapsed_ms(),
        metric_labels.clone(),
    );
    state.metrics.record_histogram_with_labels(
        "model.context.event_count",
        history.len() as u64,
        metric_labels.clone(),
    );
    let context_format = compaction_policy
        .capabilities
        .as_ref()
        .and_then(|capabilities| capabilities.context_format.as_ref());
    let convert_timer = state.metrics.timer();
    let mut messages = session_events_to_model_messages_for_target(
        &history,
        state.tool_output_context_chars,
        provider_plugin_id,
        Some(&model_id_for_provider_request(selected_model_id)),
        selection.provider_context.auth_profile.as_deref(),
        context_format.map(|format| format.version),
        context_format.map(|format| format.compatibility_key.as_str()),
    );
    state.metrics.record_histogram_with_labels(
        "model.request_build.convert_events_duration_ms",
        convert_timer.elapsed_ms(),
        metric_labels.clone(),
    );
    state.metrics.record_histogram_with_labels(
        "model.context.message_count",
        messages.len() as u64,
        metric_labels.clone(),
    );
    state.metrics.record_histogram_with_labels(
        "model.context.message_chars",
        messages
            .iter()
            .map(model_message_context_chars)
            .sum::<usize>() as u64,
        metric_labels.clone(),
    );
    let prompt_cache_timer = state.metrics.timer();
    let prompt_cache = plan_prompt_cache(&mut messages, state.prompt_cache_mode);
    state.metrics.record_histogram_with_labels(
        "model.request_build.prompt_cache_plan_duration_ms",
        prompt_cache_timer.elapsed_ms(),
        metric_labels.clone(),
    );
    let mut system_prefix_len = 0;
    for message in static_context.system_messages.iter().cloned() {
        messages.insert(system_prefix_len, message);
        system_prefix_len += 1;
    }
    if let Some(instruction) = retry_instruction
        && !instruction.trim().is_empty()
    {
        messages.insert(
            system_prefix_len,
            ModelMessage {
                role: MessageRole::System,
                content: vec![ContentBlock::Text {
                    text: instruction.to_string(),
                }],
            },
        );
    }
    let system_prompt = static_context.system_prompt.clone();
    let tools = static_context.tools.clone();
    let model_id = effective_model_id(state, selection)
        .await
        .unwrap_or_else(|_| model_id_for_provider_request(selected_model_id));
    let reasoning_capabilities = resolve_model_reasoning_info(
        state,
        provider_plugin_id,
        selected_model_id,
        &selection.provider_context,
    )
    .await;
    let parameters_timer = state.metrics.timer();
    let parameters = {
        let mut p = ModelParameters::default();
        if let Some(level) = &selection.thinking_level {
            p.reasoning_effort = Some(*level);
        }
        if let Some(reasoning) = reasoning_capabilities.as_ref() {
            if let Some(effort) = supported_reasoning_value(
                selection.reasoning_effort.as_deref(),
                &reasoning.effort_values,
            ) {
                p.reasoning_effort_value = Some(effort.to_owned());
            }
            if let Some(summary) = requested_reasoning_summary(selection, reasoning) {
                p.reasoning_summary = Some(summary.to_owned());
            }
        }
        p
    };
    state.metrics.record_histogram_with_labels(
        "model.request_build.parameters_duration_ms",
        parameters_timer.elapsed_ms(),
        metric_labels.clone(),
    );
    let mut provider_context = selection.provider_context.clone();
    select_host_auth_pool_candidate(state, provider_plugin_id, &mut provider_context).await;
    let projection_timer = state.metrics.timer();
    let context_format = compaction_policy
        .capabilities
        .as_ref()
        .and_then(|capabilities| capabilities.context_format.as_ref())
        .filter(|format| format.version > 0 && !format.compatibility_key.trim().is_empty());
    let projection = ConversationProjection::new(&ConversationProjectionInput {
        session_id,
        provider_plugin_id: provider_plugin_id.unwrap_or("<auto>"),
        model_id: &model_id,
        auth_profile: provider_context.auth_profile.as_deref(),
        context_format_version: context_format.map(|format| format.version),
        compatibility_key: context_format.map(|format| format.compatibility_key.as_str()),
        system_prompt: &system_prompt,
        tools: &tools,
        parameters: &parameters,
        messages: &messages,
    });
    state.metrics.record_histogram_with_labels(
        "model.request_build.conversation_projection_duration_ms",
        projection_timer.elapsed_ms(),
        metric_labels.clone(),
    );
    let model_cache_info = resolve_model_cache_info(
        state,
        provider_plugin_id,
        Some(&model_id),
        &provider_context,
    )
    .await;
    let conversation_reuse_timer = state.metrics.timer();
    let conversation_reuse = plan_conversation_reuse(
        state,
        &projection,
        messages.len(),
        model_cache_info.as_ref(),
    )
    .await;
    state.metrics.record_histogram_with_labels(
        "model.request_build.conversation_reuse_plan_duration_ms",
        conversation_reuse_timer.elapsed_ms(),
        metric_labels.clone(),
    );
    let metadata_timer = state.metrics.timer();
    let mut metadata = projection.metadata();
    insert_reasoning_metadata(&mut metadata, &parameters);
    if let Some(cache_info) = &model_cache_info {
        insert_model_cache_metadata(&mut metadata, cache_info);
    }
    metadata.insert(
        "bcode_context_through_sequence".to_string(),
        context_through_sequence.to_string(),
    );
    if let Some(format) = compaction_policy
        .capabilities
        .as_ref()
        .and_then(|capabilities| capabilities.context_format.as_ref())
        .filter(|format| format.version > 0 && !format.compatibility_key.trim().is_empty())
    {
        metadata.insert(
            "bcode_context_format_version".to_string(),
            format.version.to_string(),
        );
        metadata.insert(
            "bcode_compatibility_key".to_string(),
            format.compatibility_key.clone(),
        );
    }
    state.metrics.record_histogram_with_labels(
        "model.request_build.metadata_duration_ms",
        metadata_timer.elapsed_ms(),
        metric_labels.clone(),
    );
    let request_assembly_timer = state.metrics.timer();
    let context_management = if compaction_policy.decision.strategy
        == AutomaticCompactionStrategy::ProviderManaged
    {
        let status = model_status_for_selection(state, selection.clone(), Some(session_id)).await;
        provider_managed_context_request(
            compaction_policy.decision,
            status.context_window,
            state.auto_compaction.proactive_threshold_percent,
            parameters.max_output_tokens,
            status.max_output_tokens,
        )
    } else {
        bcode_model::ContextManagementRequest::default()
    };
    if let Some(selected_model_id) = selection
        .requested_model_id
        .as_deref()
        .or(selected_model_id)
    {
        metadata.insert(
            "bcode_requested_model_id".to_string(),
            selected_model_id.to_string(),
        );
    }
    let parallel_capabilities = resolve_parallel_tool_call_capabilities(
        state,
        provider_plugin_id,
        &model_id,
        &selection.provider_context,
        true,
    )
    .await;
    let request = ModelTurnRequest {
        session_id,
        turn_id: format!("{}-{}-{round}", session_id, trigger_event.sequence),
        model_id,
        provider_context,
        system_prompt: Some(system_prompt),
        messages,
        tools,
        tool_call_policy: parallel_capabilities
            .negotiate(state.tool_execution.parallel, bcode_model::ToolChoice::Auto),
        structured_output: execution.structured_output.as_ref().map(|request| {
            bcode_model::StructuredOutputRequest {
                name: request.name.clone(),
                schema: request.schema.clone(),
                strict: request.strict,
            }
        }),
        context_management,
        parameters,
        prompt_cache,
        conversation_reuse,
        metadata,
    };
    state.metrics.record_histogram_with_labels(
        "model.request_build.request_assembly_duration_ms",
        request_assembly_timer.elapsed_ms(),
        metric_labels.clone(),
    );
    state.metrics.record_histogram_with_labels(
        "model.request_build_duration_ms",
        build_timer.elapsed_ms(),
        metric_labels,
    );
    let context_projection =
        projected_request_context(state, session_id, provider_plugin_id, &request).await;
    Ok(PreparedModelRequest {
        request,
        context_projection,
    })
}

async fn publish_context_occupancy(state: &ServerState, session_id: SessionId) {
    let Ok(occupancy) = state.sessions.current_context_occupancy(session_id).await else {
        return;
    };
    let _ = state
        .sessions
        .publish_live_event(
            session_id,
            SessionLiveEventKind::RequestContextOccupancyChanged {
                occupancy: Box::new(occupancy),
            },
        )
        .await;
}

async fn projected_request_context(
    state: &ServerState,
    session_id: SessionId,
    provider_plugin_id: Option<&str>,
    request: &ModelTurnRequest,
) -> bcode_session_models::RequestContextObservation {
    let context_epoch = state
        .sessions
        .current_context_epoch(session_id)
        .await
        .unwrap_or_default();
    let local_estimate = local_request_estimate(request);
    let context_through_sequence = request
        .metadata
        .get("bcode_context_through_sequence")
        .and_then(|value| value.parse().ok())
        .unwrap_or_default();
    let request_id = request.turn_id.clone();
    let invocation = bcode_session_models::ModelRequestIdentity {
        provider_plugin_id: provider_plugin_id.unwrap_or("<auto>").to_string(),
        requested_model_id: request.metadata.get("bcode_requested_model_id").cloned(),
        effective_model_id: request.model_id.clone(),
        request_id: request_id.clone(),
        model_turn_id: request_id
            .rsplit_once('-')
            .map_or_else(|| request_id.clone(), |(turn, _)| turn.to_string()),
        round: model_round_from_turn_id(&request_id).unwrap_or_default(),
        request_fingerprint: stable_json_hash(request),
        effective_auth_profile: request.provider_context.auth_profile.clone(),
        context_format_version: request
            .metadata
            .get("bcode_context_format_version")
            .and_then(|value| value.parse().ok()),
        compatibility_key: request.metadata.get("bcode_compatibility_key").cloned(),
        context_epoch,
    };
    let current = state
        .sessions
        .current_context_occupancy(session_id)
        .await
        .ok()
        .flatten();
    bcode_session_models::RequestContextOccupancy::project_estimate(
        current.as_ref(),
        invocation,
        context_through_sequence,
        local_estimate,
    )
}

async fn append_estimated_request_context(
    state: &ServerState,
    session_id: SessionId,
    snapshot: bcode_session_models::RequestContextObservation,
) {
    if let Ok(event) = state
        .sessions
        .append_request_context_observed(session_id, snapshot)
        .await
    {
        publish_session_event(state, &event).await;
        publish_context_occupancy(state, session_id).await;
    }
}

fn bounded_portable_context(messages: &[ModelMessage]) -> String {
    let text = messages
        .iter()
        .filter_map(|message| {
            let content = message
                .content
                .iter()
                .map(portable_content_block)
                .filter(|block| !block.is_empty())
                .collect::<Vec<_>>()
                .join("\n");
            (!content.is_empty()).then(|| format!("{:?}: {content}", message.role))
        })
        .collect::<Vec<_>>()
        .join("\n\n");
    text.chars()
        .take(COMPACTION_MAX_CARRIED_SUMMARY_CHARS)
        .collect()
}

fn portable_content_block(block: &ContentBlock) -> String {
    match block {
        ContentBlock::Text { text } => text.clone(),
        ContentBlock::Image { image } => format!(
            "[image: mime_type={}, dimensions={}, bytes={}, source={}]",
            image.mime_type,
            image.metadata.width.zip(image.metadata.height).map_or_else(
                || "unknown".to_string(),
                |(width, height)| format!("{width}x{height}")
            ),
            image
                .metadata
                .byte_len
                .map_or_else(|| "unknown".to_string(), |bytes| bytes.to_string()),
            image.metadata.source_path.as_deref().unwrap_or("unknown"),
        ),
        ContentBlock::ToolCall { call } => format!(
            "[tool call: id={}, name={}, arguments={}]",
            call.id, call.name, call.arguments
        ),
        ContentBlock::ToolResult { result } => format!(
            "[tool result: call_id={}, error={}]\n{}",
            result.call_id, result.is_error, result.output
        ),
        ContentBlock::CachePoint { .. } => String::new(),
        ContentBlock::ProviderExtension { .. } => {
            "[provider-specific context omitted from portable fallback]".to_string()
        }
    }
}

fn model_request_metric_labels(
    session_id: SessionId,
    provider_plugin_id: Option<&str>,
    selected_model_id: Option<&str>,
    round: u32,
) -> MetricLabels {
    let mut labels = MetricLabels::new();
    labels.insert("session_id".to_owned(), session_id.to_string());
    labels.insert(
        "provider_plugin_id".to_owned(),
        provider_plugin_id.unwrap_or("<auto>").to_owned(),
    );
    labels.insert(
        "model_id".to_owned(),
        selected_model_id.unwrap_or("<default>").to_owned(),
    );
    labels.insert("round".to_owned(), round.to_string());
    labels
}

async fn select_host_auth_pool_candidate(
    state: &ServerState,
    provider_plugin_id: Option<&str>,
    context: &mut bcode_model::ProviderRequestContext,
) {
    if context.auth_candidates.is_empty() {
        return;
    }
    refresh_auth_usage_windows_for_priming(state, provider_plugin_id, context).await;
    let Some(selection) = bcode_provider_auth::auth_pool_routing::select_auth_pool_candidate(
        &bcode_provider_auth::auth_pool_routing::AuthPoolSelectionInput {
            pool: context.auth_pool.as_deref(),
            primary_profile: context.auth_profile.as_deref(),
            routing: &context.auth_pool_routing,
            candidates: &context.auth_candidates,
        },
    ) else {
        return;
    };
    let Some(candidate) = context
        .auth_candidates
        .iter()
        .find(|candidate| candidate.profile == selection.profile)
    else {
        return;
    };
    context.auth_profile.clone_from(&candidate.profile);
    context.auth = Some(candidate.auth.clone());
    context.env = candidate.env.clone();
    context.auth_pool_selection_reason = Some(
        match selection.reason {
            bcode_provider_auth::auth_pool_routing::AuthPoolSelectionReason::Priming => "priming",
            bcode_provider_auth::auth_pool_routing::AuthPoolSelectionReason::Strategy => "strategy",
        }
        .to_string(),
    );
}

async fn refresh_auth_usage_windows_for_priming(
    state: &ServerState,
    provider_plugin_id: Option<&str>,
    context: &bcode_model::ProviderRequestContext,
) {
    if !context.auth_pool_routing.priming_enabled
        || !context.auth_pool_routing.priming_provider_windows
    {
        return;
    }
    let provider_plugin_id = provider_plugin_id.map(str::to_string);
    for candidate in &context.auth_candidates {
        let fallback_reprime_after = context
            .auth_pool_routing
            .priming_reprime_after
            .as_deref()
            .or(context
                .auth_pool_routing
                .priming_fallback_reprime_after
                .as_deref())
            .and_then(parse_duration);
        if !bcode_provider_auth::auth_pool_state::profile_needs_priming_with_windows(
            context.auth_pool.as_deref(),
            candidate.profile.as_deref(),
            &context.auth_pool_routing.priming_required_windows,
            fallback_reprime_after,
        ) {
            continue;
        }
        let mut candidate_context = context.clone();
        candidate_context
            .auth_profile
            .clone_from(&candidate.profile);
        candidate_context.auth = Some(candidate.auth.clone());
        candidate_context.env = candidate.env.clone();
        let request = bcode_model::AuthUsageRequest {
            provider_context: candidate_context,
            meter_ids: context
                .auth_pool_routing
                .priming_required_windows
                .keys()
                .cloned()
                .collect(),
        };
        let Ok(response) =
            invoke_model_provider_json_blocking::<_, bcode_model::AuthUsageResponse>(
                state,
                provider_plugin_id.clone(),
                OP_AUTH_USAGE,
                request,
            )
            .await
        else {
            continue;
        };
        if response.supported {
            bcode_provider_auth::auth_pool_state::record_profile_usage_windows(
                context.auth_pool.as_deref(),
                candidate.profile.as_deref(),
                &response.meters,
            );
        }
    }
}

fn parse_duration(value: &str) -> Option<std::time::Duration> {
    let trimmed = value.trim();
    let (number, multiplier) = trimmed
        .strip_suffix('d')
        .map_or_else(|| (trimmed, 1), |number| (number, 86_400));
    let (number, multiplier) = number
        .strip_suffix('h')
        .map_or((number, multiplier), |number| (number, 3_600));
    let (number, multiplier) = number
        .strip_suffix('m')
        .map_or((number, multiplier), |number| (number, 60));
    let (number, multiplier) = number
        .strip_suffix('s')
        .map_or((number, multiplier), |number| (number, 1));
    number
        .parse::<u64>()
        .ok()
        .map(|seconds| std::time::Duration::from_secs(seconds.saturating_mul(multiplier)))
}

fn insert_reasoning_metadata(
    metadata: &mut BTreeMap<String, String>,
    parameters: &ModelParameters,
) {
    if let Some(effort) = &parameters.reasoning_effort_value {
        metadata.insert("reasoning_effort".to_string(), effort.clone());
    } else if let Some(effort) = parameters.reasoning_effort {
        metadata.insert("reasoning_effort".to_string(), format!("{effort:?}"));
    }
    if let Some(summary) = &parameters.reasoning_summary {
        metadata.insert("reasoning_summary".to_string(), summary.clone());
    }
}

fn requested_reasoning_summary<'a>(
    selection: &'a SessionModelSelection,
    reasoning: &'a bcode_model::ModelReasoningInfo,
) -> Option<&'a str> {
    let requested = selection
        .reasoning_summary
        .as_deref()
        .or(reasoning.default_summary.as_deref());
    supported_reasoning_value(requested, &reasoning.summary_values)
}

fn supported_reasoning_value<'a>(
    requested: Option<&'a str>,
    supported: &[String],
) -> Option<&'a str> {
    let requested = requested?.trim();
    if requested.is_empty() {
        return None;
    }
    (supported.is_empty() || supported.iter().any(|value| value == requested)).then_some(requested)
}

async fn resolve_parallel_tool_call_capabilities(
    state: &ServerState,
    provider_plugin_id: Option<&str>,
    selected_model_id: &str,
    provider_context: &bcode_model::ProviderRequestContext,
    runtime: bool,
) -> bcode_model::ParallelToolCallCapabilities {
    let provider = if let Some(provider_plugin_id) = provider_plugin_id {
        state
            .plugins
            .invoke_service_json::<(), bcode_model::ProviderCapabilities>(
                provider_plugin_id,
                bcode_model::MODEL_PROVIDER_INTERFACE_ID,
                bcode_model::OP_CAPABILITIES,
                &(),
            )
            .await
            .ok()
    } else {
        None
    };
    let model = resolved_provider_models(
        state,
        provider_plugin_id.map(ToOwned::to_owned),
        bcode_model::ModelListRequest {
            provider_context: provider_context.clone(),
            selected_model_id: Some(selected_model_id.to_owned()),
        },
    )
    .await
    .ok()
    .and_then(|models| {
        models
            .models
            .into_iter()
            .find(|model| model.model_id == selected_model_id)
    });
    let feature =
        bcode_model::RequestedModelFeature::ToolChoice(bcode_model::ToolChoiceMode::Parallel);
    let support = provider
        .as_ref()
        .zip(model.as_ref())
        .map(|(provider, model)| {
            provider
                .feature_support
                .negotiate(&model.feature_support, feature)
        });
    let supported = match support {
        Some(bcode_model::NegotiatedFeatureSupport::Guaranteed { .. }) => Some(true),
        Some(bcode_model::NegotiatedFeatureSupport::Unsupported { .. }) => Some(false),
        Some(bcode_model::NegotiatedFeatureSupport::Unknown { .. }) | None => None,
    };
    bcode_model::ParallelToolCallCapabilities {
        provider: supported,
        model: supported,
        runtime,
    }
}

async fn resolve_model_reasoning_info(
    state: &ServerState,
    provider_plugin_id: Option<&str>,
    selected_model_id: Option<&str>,
    provider_context: &bcode_model::ProviderRequestContext,
) -> Option<bcode_model::ModelReasoningInfo> {
    let provider_reasoning = resolve_model_reasoning_info_from_provider(
        state,
        provider_plugin_id,
        selected_model_id,
        provider_context.clone(),
    )
    .await
    .or_else(|| state.selected_reasoning_capabilities.clone());
    let override_ =
        selected_model_id.and_then(|model_id| model_reasoning_override(provider_context, model_id));
    merge_reasoning_override(provider_reasoning, override_)
}

async fn resolve_model_reasoning_info_from_provider(
    state: &ServerState,
    provider_plugin_id: Option<&str>,
    selected_model_id: Option<&str>,
    provider_context: bcode_model::ProviderRequestContext,
) -> Option<bcode_model::ModelReasoningInfo> {
    let models = resolved_provider_models(
        state,
        provider_plugin_id.map(ToOwned::to_owned),
        bcode_model::ModelListRequest {
            provider_context,
            selected_model_id: selected_model_id.map(ToOwned::to_owned),
        },
    )
    .await
    .ok()?;
    select_model_info(&models.models, selected_model_id).and_then(|model| model.reasoning)
}

fn insert_model_cache_metadata(
    metadata: &mut BTreeMap<String, String>,
    cache_info: &bcode_model::ModelCacheInfo,
) {
    let capabilities = cache_info
        .capabilities
        .iter()
        .map(|x| model_cache_capability_name(*x))
        .collect::<Vec<_>>()
        .join(",");
    metadata.insert("model_cache_capabilities".to_string(), capabilities);
}

const fn model_cache_capability_name(
    capability: bcode_model::ModelCacheCapability,
) -> &'static str {
    match capability {
        bcode_model::ModelCacheCapability::PromptCacheKey => "prompt_cache_key",
        bcode_model::ModelCacheCapability::AutomaticPrefixCache => "automatic_prefix_cache",
        bcode_model::ModelCacheCapability::ExplicitCachePoints => "explicit_cache_points",
        bcode_model::ModelCacheCapability::CacheUsageReporting => "cache_usage_reporting",
        bcode_model::ModelCacheCapability::ProviderState => "provider_state",
        bcode_model::ModelCacheCapability::PreviousResponseId => "previous_response_id",
    }
}

async fn resolve_model_cache_info(
    state: &ServerState,
    provider_plugin_id: Option<&str>,
    selected_model_id: Option<&str>,
    provider_context: &bcode_model::ProviderRequestContext,
) -> Option<bcode_model::ModelCacheInfo> {
    let models = provider_models(
        state,
        provider_plugin_id.map(ToOwned::to_owned),
        bcode_model::ModelListRequest {
            provider_context: provider_context.clone(),
            selected_model_id: selected_model_id.map(ToOwned::to_owned),
        },
    )
    .await
    .ok()?;
    select_model_info(&models.models, selected_model_id).map(|model| model.cache)
}

async fn append_model_request_trace(
    state: &ServerState,
    session_id: SessionId,
    request: &ModelTurnRequest,
    provider_plugin_id: Option<&str>,
    round: u32,
) {
    if !state.observability.enabled() {
        return;
    }
    let request_blob = model_request_trace_blob(state, session_id, request, round);
    let metadata = model_request_trace_metadata(request, provider_plugin_id);
    append_trace_event(
        state,
        session_id,
        Some(request.turn_id.clone()),
        SessionTracePhase::ModelRequestBuilt,
        SessionTracePayload::ModelRequestBuilt {
            provider: provider_plugin_id.unwrap_or("<auto>").to_string(),
            model: if request.model_id.is_empty() {
                "<provider-default>".to_string()
            } else {
                request.model_id.clone()
            },
            agent_id: session_agent_selection(state, session_id).await,
            message_count: request.messages.len(),
            tool_count: request.tools.len(),
            system_prompt_chars: request.system_prompt.as_ref().map_or(0, String::len),
            prompt_cache_mode: prompt_cache_mode_name(request.prompt_cache.mode).to_string(),
            conversation_reuse_mode: conversation_reuse_mode_name(request.conversation_reuse.mode)
                .to_string(),
            uses_previous_provider_response: request
                .conversation_reuse
                .previous_provider_response_id
                .is_some(),
            metadata,
            request: request_blob,
        },
    )
    .await;
}

fn model_request_trace_blob(
    state: &ServerState,
    session_id: SessionId,
    request: &ModelTurnRequest,
    round: u32,
) -> Option<bcode_session_models::TraceBlobRef> {
    (state.observability.persist_model_requests || state.observability.debug_enabled())
        .then(|| {
            let mut redacted_request = request.clone();
            redacted_request.provider_context.env = redacted_request
                .provider_context
                .env
                .keys()
                .cloned()
                .map(|key| (key, "<redacted>".to_string()))
                .collect();
            if let Some(auth) = &mut redacted_request.provider_context.auth {
                auth.credentials = auth
                    .credentials
                    .keys()
                    .cloned()
                    .map(|key| {
                        (
                            key,
                            bcode_model::ProviderAuthCredential {
                                value: "<redacted>".to_string(),
                                source: None,
                            },
                        )
                    })
                    .collect();
            }
            state.trace_store.write_json_blob(
                session_id,
                &format!("model-request-round-{round}"),
                &redacted_request,
                state.observability.max_blob_bytes,
            )
        })
        .flatten()
}

fn model_request_trace_metadata(
    request: &ModelTurnRequest,
    provider_plugin_id: Option<&str>,
) -> BTreeMap<String, String> {
    let prompt_cache_points = prompt_cache_point_count(request);
    let mut metadata = request.metadata.clone();
    metadata.insert(
        "message_count".to_string(),
        request.messages.len().to_string(),
    );
    metadata.insert(
        "new_messages_start_index".to_string(),
        request
            .conversation_reuse
            .new_messages_start_index
            .map_or_else(|| "none".to_string(), |index| index.to_string()),
    );
    metadata.insert(
        "sent_message_count".to_string(),
        sent_message_count(request).to_string(),
    );
    metadata.insert(
        "prompt_cache_points".to_string(),
        prompt_cache_points.to_string(),
    );
    metadata.insert(
        "cache_system_prompt".to_string(),
        request.prompt_cache.cache_system_prompt.to_string(),
    );
    metadata.insert(
        "cache_tools".to_string(),
        request.prompt_cache.cache_tools.to_string(),
    );
    metadata.insert(
        "cache_conversation_prefix".to_string(),
        (prompt_cache_points > 0).to_string(),
    );
    let cache_capabilities = request
        .metadata
        .get("model_cache_capabilities")
        .cloned()
        .unwrap_or_else(|| cache_capability(provider_plugin_id));
    metadata.insert("cache_capability".to_string(), cache_capabilities.clone());
    metadata.insert(
        "cache_point_projection".to_string(),
        cache_point_projection(&cache_capabilities, provider_plugin_id, prompt_cache_points),
    );
    metadata.insert(
        "provider_reuse_capability".to_string(),
        provider_reuse_capability(&cache_capabilities, provider_plugin_id),
    );
    metadata
}

fn cache_capability(provider_plugin_id: Option<&str>) -> String {
    match provider_plugin_id {
        Some("bcode.openai-compatible") => "prompt_cache_key_automatic_prefix".to_string(),
        Some("bcode.bedrock") => "provider_specific_cache_control".to_string(),
        Some(_) => "unknown".to_string(),
        None => "auto_provider_unknown".to_string(),
    }
}

fn cache_point_projection(
    cache_capabilities: &str,
    provider_plugin_id: Option<&str>,
    prompt_cache_points: usize,
) -> String {
    if prompt_cache_points == 0 {
        return "none".to_string();
    }
    if cache_capabilities
        .split(',')
        .any(|capability| capability == "explicit_cache_points")
    {
        return "provider_declared_explicit_cache_points".to_string();
    }
    match provider_plugin_id {
        Some("bcode.openai-compatible") => "unsupported_dropped".to_string(),
        Some(_) => "unsupported_or_unknown".to_string(),
        None => "auto_provider_unknown".to_string(),
    }
}

fn provider_reuse_capability(cache_capabilities: &str, provider_plugin_id: Option<&str>) -> String {
    if cache_capabilities
        .split(',')
        .any(|capability| capability == "previous_response_id")
    {
        return "provider_declared_previous_response_id".to_string();
    }
    match provider_plugin_id {
        Some(_) => "unsupported_or_unknown".to_string(),
        None => "auto_provider_unknown".to_string(),
    }
}

fn sent_message_count(request: &ModelTurnRequest) -> usize {
    request
        .conversation_reuse
        .new_messages_start_index
        .filter(|_| {
            request
                .conversation_reuse
                .previous_provider_response_id
                .is_some()
        })
        .map_or(request.messages.len(), |start| {
            request
                .messages
                .len()
                .saturating_sub(start.min(request.messages.len()))
        })
}

fn prompt_cache_point_count(request: &ModelTurnRequest) -> usize {
    request
        .messages
        .iter()
        .flat_map(|message| &message.content)
        .filter(|block| matches!(block, ContentBlock::CachePoint { .. }))
        .count()
}

fn model_round_from_turn_id(turn_id: &str) -> Option<u32> {
    turn_id
        .rsplit('-')
        .next()
        .and_then(|round| round.parse().ok())
}

#[derive(Debug, Clone)]
struct ConversationProjection {
    key: ProviderStateKey,
    conversation_hash: String,
}

struct ConversationProjectionInput<'a> {
    session_id: SessionId,
    provider_plugin_id: &'a str,
    model_id: &'a str,
    auth_profile: Option<&'a str>,
    context_format_version: Option<u16>,
    compatibility_key: Option<&'a str>,
    system_prompt: &'a str,
    tools: &'a [bcode_model::ToolDefinition],
    parameters: &'a ModelParameters,
    messages: &'a [ModelMessage],
}

impl ConversationProjection {
    fn new(input: &ConversationProjectionInput<'_>) -> Self {
        let stable_prompt_hash = stable_hash(input.system_prompt);
        let tools_hash = stable_json_hash(input.tools);
        let parameters_hash = stable_json_hash(input.parameters);
        let conversation_hash = stable_json_hash(input.messages);
        Self {
            key: ProviderStateKey {
                session_id: input.session_id,
                provider_plugin_id: input.provider_plugin_id.to_string(),
                model_id: input.model_id.to_string(),
                auth_profile: input.auth_profile.map(ToString::to_string),
                context_format_version: input.context_format_version,
                compatibility_key: input.compatibility_key.map(ToString::to_string),
                stable_prompt_hash,
                tools_hash,
                parameters_hash,
            },
            conversation_hash,
        }
    }

    fn reuse_key(&self) -> String {
        stable_json_hash(&self.key)
    }

    fn metadata(&self) -> BTreeMap<String, String> {
        BTreeMap::from([
            (
                "stable_prompt_hash".to_string(),
                self.key.stable_prompt_hash.clone(),
            ),
            ("tools_hash".to_string(), self.key.tools_hash.clone()),
            (
                "parameters_hash".to_string(),
                self.key.parameters_hash.clone(),
            ),
            (
                "auth_profile".to_string(),
                self.key
                    .auth_profile
                    .clone()
                    .unwrap_or_else(|| "-".to_string()),
            ),
            (
                "context_format_version".to_string(),
                self.key
                    .context_format_version
                    .map_or_else(|| "-".to_string(), |version| version.to_string()),
            ),
            (
                "compatibility_key".to_string(),
                self.key
                    .compatibility_key
                    .clone()
                    .unwrap_or_else(|| "-".to_string()),
            ),
            (
                "conversation_hash".to_string(),
                self.conversation_hash.clone(),
            ),
            ("conversation_reuse_key".to_string(), self.reuse_key()),
        ])
    }
}

fn supports_provider_conversation_reuse(cache_info: Option<&bcode_model::ModelCacheInfo>) -> bool {
    cache_info.is_some_and(|info| {
        info.capabilities.iter().any(|capability| {
            matches!(
                capability,
                bcode_model::ModelCacheCapability::ProviderState
                    | bcode_model::ModelCacheCapability::PreviousResponseId
            )
        })
    })
}

async fn plan_conversation_reuse(
    state: &ServerState,
    projection: &ConversationProjection,
    message_count: usize,
    cache_info: Option<&bcode_model::ModelCacheInfo>,
) -> bcode_model::ConversationReuseHints {
    let mode = state.conversation_reuse_mode;
    if !mode.is_enabled() || !supports_provider_conversation_reuse(cache_info) {
        return bcode_model::ConversationReuseHints::default();
    }

    let reuse_key = projection.reuse_key();
    let (record, previous) = {
        let mut provider_state = state.provider_state.lock().await;
        let previous = provider_state.continuation_for_projection(&reuse_key, message_count);
        (provider_state.records.get(&reuse_key).cloned(), previous)
    };

    bcode_model::ConversationReuseHints {
        mode,
        key: Some(reuse_key),
        previous_provider_response_id: previous
            .as_ref()
            .map(|continuation| continuation.provider_response_id.clone()),
        new_messages_start_index: previous
            .as_ref()
            .map(|continuation| continuation.reusable_message_count),
        provider_state: record.and_then(|record| record.provider_state),
    }
}

fn stable_json_hash(value: &(impl serde::Serialize + ?Sized)) -> String {
    serde_json::to_string(value).map_or_else(
        |_| stable_hash("<serialize-error>"),
        |json| stable_hash(&json),
    )
}

fn stable_hash(value: &str) -> String {
    let mut hasher = std::collections::hash_map::DefaultHasher::new();
    value.hash(&mut hasher);
    format!("{:016x}", hasher.finish())
}

fn plan_prompt_cache(
    messages: &mut [ModelMessage],
    mode: bcode_model::PromptCacheMode,
) -> bcode_model::PromptCacheHints {
    if !mode.is_enabled() {
        return bcode_model::PromptCacheHints::default();
    }

    if mode.cache_conversation_prefix()
        && let Some(index) = conversation_cache_point_index(messages)
    {
        messages[index].content.push(ContentBlock::CachePoint {
            hint: bcode_model::PromptCachePoint {
                label: Some("conversation_prefix".to_string()),
                ttl_seconds: None,
            },
        });
    }

    bcode_model::PromptCacheHints {
        mode,
        cache_system_prompt: true,
        cache_tools: true,
    }
}

fn conversation_cache_point_index(messages: &[ModelMessage]) -> Option<usize> {
    const MIN_MESSAGES_FOR_CONVERSATION_CACHE: usize = 6;
    if messages.len() < MIN_MESSAGES_FOR_CONVERSATION_CACHE {
        return None;
    }
    messages
        .iter()
        .enumerate()
        .rev()
        .skip(2)
        .find_map(|(index, message)| {
            matches!(
                message.role,
                MessageRole::User | MessageRole::Assistant | MessageRole::Tool
            )
            .then_some(index)
        })
}

fn model_id_for_provider_request(selected_model_id: Option<&str>) -> String {
    selected_model_id.map_or_else(String::new, ToString::to_string)
}

const DEFAULT_CODING_SYSTEM_PROMPT: &str = r"You are Bcode, a terminal-native coding agent running on the user's machine.

Operate like a careful pair programmer:
* Understand the user's goal before changing files.
* Prefer inspecting relevant files before editing them.
* Use filesystem tools for file reads/writes/edits instead of guessing file contents.
* Use shell tools for focused validation, discovery, and tests when useful.
* Keep edits minimal, domain-driven, and consistent with existing project conventions.
* Do not create speculative crates, packages, or placeholder files.
* Respect project instructions from AGENTS.md or similar repository guidance when provided.
* Treat discovered project instructions as binding for workflow and validation requirements.
* Before finishing a coding task, run the validation required by project instructions when practical; otherwise run the most relevant formatting, check, or test command.
* If validation cannot be run, explain why.
* Summarize what changed and exactly what validation ran.

Tool and safety rules:
* File writes, edits, and shell commands may require user permission. Ask through tools normally; do not claim a side effect happened unless a tool result confirms it.
* Prefer small, reviewable tool calls over broad destructive commands.
* Never run destructive commands such as deleting broad directories unless explicitly requested and permissioned.
* Treat tool output as potentially partial or truncated.
";

const MAX_REPOSITORY_CONTEXT_CHARS: usize = 12_000;
const MAX_CONTEXT_FILE_CHARS: usize = 6_000;
const MAX_GIT_STATUS_CHARS: usize = 4_000;

fn build_coding_system_prompt_parts(
    cwd: &Path,
    config: &bcode_config::SystemPromptConfig,
    agent_prompt_suffix: Option<&str>,
    skill_catalog: Option<&str>,
) -> (String, String) {
    let (stable_context, dynamic_context) = build_repository_context_parts(cwd);
    let mut stable = match config.mode {
        bcode_config::SystemPromptMode::Default => DEFAULT_CODING_SYSTEM_PROMPT.to_string(),
        bcode_config::SystemPromptMode::Replace => config.text.clone().unwrap_or_default(),
    };
    if config.sections.repository_context {
        stable.push_str("\n\n");
        stable.push_str(&truncate_text(
            &stable_context,
            MAX_REPOSITORY_CONTEXT_CHARS,
        ));
    }
    if config.sections.agent_suffix
        && let Some(suffix) = agent_prompt_suffix
        && !suffix.trim().is_empty()
    {
        stable.push_str("\n\nAgent-specific instructions:\n");
        stable.push_str(suffix.trim());
    }

    let mut dynamic = if config.sections.dynamic_repository_context {
        truncate_text(&dynamic_context, MAX_REPOSITORY_CONTEXT_CHARS)
    } else {
        String::new()
    };
    if let Some(skill_catalog) = skill_catalog
        && !skill_catalog.trim().is_empty()
    {
        dynamic.push_str(skill_catalog);
    }

    (stable, dynamic)
}

fn build_repository_context_parts(cwd: &Path) -> (String, String) {
    let repo_root = discover_git_root(cwd);
    let context_root = repo_root.as_deref().unwrap_or(cwd);

    let mut stable_lines = vec!["Stable repository context:".to_string()];
    stable_lines.push(format!(
        "* Detected project files: {}",
        detected_project_files(context_root).join(", ")
    ));
    if let Some(instructions) = read_nearest_agent_instructions(cwd, context_root) {
        stable_lines.push(format!("* Project instructions excerpt:\n{instructions}"));
    }

    let mut dynamic_lines = vec![
        "Dynamic repository context:".to_string(),
        format!("* Current directory: {}", display(cwd, cwd)),
    ];
    if let Some(repo_root) = &repo_root {
        dynamic_lines.push(format!("* Git root: {}", display(repo_root, cwd)));
    }
    if let Some(branch) = run_command(context_root, "git", &["branch", "--show-current"][..])
        && !branch.is_empty()
    {
        dynamic_lines.push(format!("* Git branch: {branch}"));
    }
    if let Some(status) = run_command(context_root, "git", &["status", "--short"][..]) {
        dynamic_lines.push(format!(
            "* Git status:\n{}",
            format_block_or_placeholder(&status, "clean")
        ));
    }

    (stable_lines.join("\n"), dynamic_lines.join("\n"))
}

fn discover_git_root(cwd: &Path) -> Option<PathBuf> {
    run_command(cwd, "git", &["rev-parse", "--show-toplevel"][..])
        .filter(|root| !root.is_empty())
        .map(PathBuf::from)
}

fn run_command(cwd: &Path, program: &str, args: &[&str]) -> Option<String> {
    let output = Command::new(program)
        .args(args)
        .current_dir(cwd)
        .output()
        .ok()?;
    if !output.status.success() {
        return None;
    }
    String::from_utf8(output.stdout)
        .ok()
        .map(|value| truncate_text(value.trim(), MAX_GIT_STATUS_CHARS))
}

fn detected_project_files(root: &Path) -> Vec<String> {
    let candidates = [
        "AGENTS.md",
        "Cargo.toml",
        "package.json",
        "pyproject.toml",
        "go.mod",
        "Makefile",
        "justfile",
        "README.md",
    ];
    let detected = candidates
        .into_iter()
        .filter(|candidate| root.join(candidate).exists())
        .map(ToString::to_string)
        .collect::<Vec<_>>();
    if detected.is_empty() {
        vec!["<none detected>".to_string()]
    } else {
        detected
    }
}

fn read_nearest_agent_instructions(cwd: &Path, stop_at: &Path) -> Option<String> {
    let mut current = Some(cwd);
    while let Some(directory) = current {
        let candidate = directory.join("AGENTS.md");
        if candidate.exists() {
            return read_file_excerpt(&candidate, MAX_CONTEXT_FILE_CHARS);
        }
        if directory == stop_at {
            break;
        }
        current = directory.parent();
    }
    None
}

fn read_file_excerpt(path: &Path, max_chars: usize) -> Option<String> {
    fs::read_to_string(path)
        .ok()
        .map(|text| truncate_text(text.trim(), max_chars))
}

fn truncate_text(text: &str, max_chars: usize) -> String {
    let mut truncated = text.chars().take(max_chars).collect::<String>();
    if text.chars().count() > max_chars {
        truncated.push_str("\n[truncated]");
    }
    truncated
}

fn project_tool_result_for_model_context(
    result: &str,
    full_output_path: Option<PathBuf>,
    max_context_chars: usize,
) -> String {
    let char_count = result.chars().count();
    if char_count <= max_context_chars {
        return result.to_string();
    }

    let path = full_output_path.map_or_else(
        || "the session trace blob store".to_string(),
        |path| display_from_current_dir(path).to_string(),
    );
    let footer = format!(
        "\n\n[tool output truncated for model context: original {char_count} chars / {} bytes. Full retained output saved at: {path}. Bcode already includes the beginning and end of long tool output when possible; do not rerun the same shell command with sed/head/tail just to inspect omitted output. Prefer artifact.metadata, artifact.grep, or artifact.read with max_bytes/from_end for saved tool-output artifacts; filesystem.grep or filesystem.read with offset/limit also work for regular files. Avoid reading the whole file unless necessary.]\n\n",
        result.len()
    );
    if max_context_chars == 0 {
        return footer.trim().to_string();
    }

    let omitted_chars = char_count.saturating_sub(max_context_chars);
    let omission_marker =
        format!("\n\n[... omitted {omitted_chars} chars from tool output ...]\n\n");
    let fixed_chars = omission_marker.chars().count() + footer.chars().count();
    if fixed_chars >= max_context_chars {
        return footer.chars().take(max_context_chars).collect();
    }

    let budget = max_context_chars.saturating_sub(fixed_chars);
    let head_chars = budget / 2;
    let tail_chars = budget.saturating_sub(head_chars);
    let head = result.chars().take(head_chars).collect::<String>();
    let tail = result
        .chars()
        .rev()
        .take(tail_chars)
        .collect::<Vec<_>>()
        .into_iter()
        .rev()
        .collect::<String>();
    format!("{head}{omission_marker}{tail}{footer}")
}

fn trace_blob_read_path(blob: &TraceBlobRef) -> PathBuf {
    let path = PathBuf::from(&blob.path);
    if path.is_absolute() {
        path
    } else {
        default_trace_store_dir().join(path)
    }
}

fn format_block_or_placeholder(value: &str, placeholder: &str) -> String {
    if value.is_empty() {
        format!("  {placeholder}")
    } else {
        value
            .lines()
            .map(|line| format!("  {line}"))
            .collect::<Vec<_>>()
            .join("\n")
    }
}

const fn tool_policy_allows_operation(
    policy: bcode_session_models::TurnToolPolicy,
    is_read_only: bool,
) -> bool {
    match policy {
        bcode_session_models::TurnToolPolicy::Enabled => true,
        bcode_session_models::TurnToolPolicy::ReadOnly => is_read_only,
        bcode_session_models::TurnToolPolicy::Disabled => false,
    }
}

fn tool_policy_denies_tool(
    policy: bcode_session_models::TurnToolPolicy,
    metadata: Option<&ToolPolicyAuthorizationMetadata>,
) -> bool {
    metadata.is_none_or(|metadata| !tool_policy_allows_operation(policy, metadata.is_read_only()))
}

fn intersect_tool_allowlists(
    profile_tools: Option<Vec<String>>,
    turn_tools: Option<&Vec<String>>,
) -> Option<Vec<String>> {
    match (profile_tools, turn_tools) {
        (None, None) => None,
        (Some(tools), None) => Some(tools),
        (None, Some(tools)) => Some(tools.clone()),
        (Some(profile), Some(turn)) => {
            let profile = profile.into_iter().collect::<BTreeSet<_>>();
            Some(
                turn.iter()
                    .filter(|tool| profile.contains(*tool))
                    .cloned()
                    .collect(),
            )
        }
    }
}

async fn collect_model_tools(
    state: &ServerState,
    session_id: SessionId,
    enabled_tools: Option<Vec<String>>,
    policy: bcode_session_models::TurnToolPolicy,
) -> Vec<bcode_model::ToolDefinition> {
    let enabled_tools = enabled_tools.map(|tools| tools.into_iter().collect::<BTreeSet<_>>());
    if policy == bcode_session_models::TurnToolPolicy::Disabled {
        return Vec::new();
    }
    let mut tools = Vec::new();
    for tool in collect_tool_definitions(state).await {
        if enabled_tools
            .as_ref()
            .is_some_and(|enabled| !enabled.contains(&tool.name))
        {
            continue;
        }
        if !tool_policy_allows_operation(policy, false) {
            let call = bcode_model::ToolCall {
                id: format!("catalog-{}", tool.name),
                name: tool.name.clone(),
                arguments: serde_json::Value::Null,
            };
            let Ok((_, preparation)) = prepare_server_tool(state, session_id, &call).await else {
                continue;
            };
            let Ok(metadata) =
                tool_policy_authorization_metadata(&preparation.authorization, &tool.name)
            else {
                continue;
            };
            if !metadata.is_read_only() {
                continue;
            }
        }
        tools.push(bcode_model::ToolDefinition {
            name: tool.name,
            description: tool.description,
            input_schema: tool.input_schema,
        });
    }
    tools
}

async fn collect_tool_definitions(state: &ServerState) -> Vec<ServiceToolDefinition> {
    let mut tools = Vec::new();
    for plugin_id in tool_provider_plugin_ids(state) {
        let response = state
            .plugins
            .invoke_service_json::<_, ToolList>(
                &plugin_id,
                TOOL_SERVICE_INTERFACE_ID,
                OP_LIST_TOOLS,
                &ListToolsRequest::default(),
            )
            .await;
        match response {
            Ok(list) => tools.extend(list.tools),
            Err(error) => tracing::warn!("failed to list tools from {plugin_id}: {error}"),
        }
    }
    tools
}

fn tool_error(output: impl Into<String>) -> ToolInvocationResponse {
    ToolInvocationResponse {
        output: output.into(),
        is_error: true,
        content: Vec::new(),
        full_output: None,
        result: None,
    }
}

const MAX_INVOCATION_SERVICE_OPERATIONS: usize = 32;
const MAX_INVOCATION_SERVICE_IDENTIFIER_BYTES: usize = 128;

async fn invocation_service_routes(
    state: &ServerState,
    session_id: SessionId,
) -> Vec<ServerInvocationServiceRoute> {
    let selection = session_model_selection(state, session_id).await;
    let target_plugin_id = selection.provider_plugin_id.or_else(|| {
        state
            .plugins
            .registry()
            .service_registry()
            .unique_provider(MODEL_PROVIDER_INTERFACE_ID)
            .ok()
            .map(str::to_owned)
    });
    let Some(target_plugin_id) = target_plugin_id else {
        return Vec::new();
    };
    let operations = state
        .plugins
        .registry()
        .manifests()
        .get(&target_plugin_id)
        .and_then(|manifest| {
            manifest
                .services
                .iter()
                .find(|service| service.interface_id == MODEL_PROVIDER_INTERFACE_ID)
        })
        .map(|service| service.invocation_operations.clone())
        .unwrap_or_default();
    if operations.is_empty()
        || operations.len() > MAX_INVOCATION_SERVICE_OPERATIONS
        || operations.iter().any(|operation| {
            operation.is_empty() || operation.len() > MAX_INVOCATION_SERVICE_IDENTIFIER_BYTES
        })
        || operations.iter().collect::<BTreeSet<_>>().len() != operations.len()
    {
        return Vec::new();
    }
    vec![ServerInvocationServiceRoute {
        advertised: bcode_tool::ToolInvocationServiceRoute {
            route_id: format!("service-route:{target_plugin_id}:{MODEL_PROVIDER_INTERFACE_ID}"),
            interface_id: MODEL_PROVIDER_INTERFACE_ID.to_owned(),
            operations,
        },
        target_plugin_id: Some(target_plugin_id),
        payload_overlay: serde_json::json!({
            "provider_context": selection.provider_context,
        }),
    }]
}

#[derive(Debug)]
struct ServerInvocationServiceRoute {
    advertised: bcode_tool::ToolInvocationServiceRoute,
    target_plugin_id: Option<String>,
    payload_overlay: serde_json::Value,
}

async fn invocation_service_host_context(
    state: &ServerState,
    session_id: SessionId,
) -> Vec<bcode_tool::ToolHostContextEntry> {
    let routes = invocation_service_routes(state, session_id)
        .await
        .into_iter()
        .map(|route| route.advertised)
        .collect::<Vec<_>>();
    vec![bcode_tool::ToolHostContextEntry {
        schema: bcode_tool::TOOL_INVOCATION_SERVICE_ROUTES_SCHEMA.to_owned(),
        schema_version: 1,
        payload: serde_json::to_value(routes).unwrap_or(serde_json::Value::Null),
    }]
}

#[derive(Debug)]
struct ServerToolInvoker<'a> {
    state: &'a ServerState,
    session_id: SessionId,
    working_directory: &'a Path,
    cancel_state: &'a TurnCancelState,
}

impl<'a> ServerToolInvoker<'a> {
    const fn new(
        state: &'a ServerState,
        session_id: SessionId,
        working_directory: &'a Path,
        cancel_state: &'a TurnCancelState,
    ) -> Self {
        Self {
            state,
            session_id,
            working_directory,
            cancel_state,
        }
    }
}

impl ToolInvoker for ServerToolInvoker<'_> {
    fn prepare_tool<'a>(
        &'a self,
        tool: &'a RegisteredTool,
        request: &'a ToolPreparationRequest,
        scope: &'a PreparationScope,
    ) -> RuntimeFuture<'a, ToolPreparationResponse> {
        Box::pin(async move {
            let ToolSource::Plugin { plugin_id } = &tool.source else {
                return Err(RuntimeError::ToolPreparation {
                    tool_name: request.invocation.tool_name.clone(),
                    message: "server cannot prepare a non-plugin tool".to_owned(),
                });
            };
            if !scope.accepts_work() || self.cancel_state.is_cancelled() {
                return Err(RuntimeError::Cancelled);
            }
            let request = ToolPreparationRequest {
                invocation: request.invocation.clone(),
                host_context: scope.host_context().to_vec(),
            };
            self.state
                .plugins
                .invoke_service_json_scoped::<_, ToolPreparationResponse>(
                    plugin_id,
                    TOOL_SERVICE_INTERFACE_ID,
                    OP_PREPARE_TOOL,
                    &request,
                    active_plugin_scope_for_tool_call(
                        self.state,
                        self.session_id,
                        &request.invocation.invocation_id,
                    )
                    .await,
                )
                .await
                .map_err(|error| RuntimeError::ToolPreparation {
                    tool_name: request.invocation.tool_name,
                    message: error.to_string(),
                })
        })
    }

    fn invoke_tool<'a>(
        &'a self,
        tool: &'a RegisteredTool,
        invocation: &'a PreparedToolInvocation,
        scope: &'a InvocationScope,
    ) -> RuntimeFuture<'a, ToolInvocationResponse> {
        Box::pin(async move {
            let ToolSource::Plugin { plugin_id } = &tool.source else {
                return Err(RuntimeError::ToolExecution {
                    tool_name: invocation.invocation.tool_name.clone(),
                    message: "server cannot invoke a non-plugin tool".to_owned(),
                });
            };
            let policy_metadata = tool_policy_authorization_metadata(
                &invocation.preparation.authorization,
                &invocation.invocation.tool_name,
            )
            .map_err(|message| RuntimeError::ToolExecution {
                tool_name: invocation.invocation.tool_name.clone(),
                message,
            })?;
            let call = bcode_model::ToolCall {
                id: invocation.invocation.invocation_id.clone(),
                name: invocation.invocation.tool_name.clone(),
                arguments: invocation.invocation.arguments.clone(),
            };
            invoke_model_tool(
                self.state,
                self.session_id,
                &call,
                self.working_directory,
                plugin_id,
                &policy_metadata,
                invocation.preparation.descriptor.clone(),
                self.cancel_state,
                Some(scope),
                None,
            )
            .await
            .map_err(|message| RuntimeError::ToolExecution {
                tool_name: call.name,
                message,
            })
        })
    }
}

async fn collect_server_tool_catalog(state: &ServerState) -> Result<UnifiedToolCatalog, String> {
    let mut catalog = UnifiedToolCatalog::new();
    let mut registered_names = BTreeSet::new();
    for plugin_id in tool_provider_plugin_ids(state) {
        let list = state
            .plugins
            .invoke_service_json::<_, ToolList>(
                &plugin_id,
                TOOL_SERVICE_INTERFACE_ID,
                OP_LIST_TOOLS,
                &ListToolsRequest::default(),
            )
            .await
            .map_err(|error| error.to_string())?;
        for definition in list.tools {
            if registered_names.insert(definition.name.clone()) {
                catalog.insert(RegisteredTool::plugin(definition, plugin_id.clone()));
            }
        }
    }
    Ok(catalog)
}

async fn registered_server_tool(
    state: &ServerState,
    tool_name: &str,
) -> Result<RegisteredTool, String> {
    collect_server_tool_catalog(state)
        .await?
        .find_tool(tool_name)
        .ok_or_else(|| format!("tool not found: {tool_name}"))
}

async fn prepare_registered_server_tool(
    state: &ServerState,
    session_id: SessionId,
    tool: RegisteredTool,
    call: &bcode_model::ToolCall,
    cancel_state: &TurnCancelState,
) -> Result<ToolPreparationResponse, String> {
    let host_context = invocation_service_host_context(state, session_id).await;
    let request = ToolPreparationRequest {
        invocation: ToolInvocationDescriptor {
            invocation_id: call.id.clone(),
            tool_name: call.name.clone(),
            arguments: call.arguments.clone(),
        },
        host_context: host_context.clone(),
    };
    let scope = PreparationScope::new(
        TurnScope::without_events(
            format!("server-tool-preparation:{session_id}"),
            TurnGeneration::new(0),
        ),
        host_context,
    );
    let working_directory = state
        .sessions
        .session_working_directory(session_id)
        .await
        .map_err(|error| error.to_string())?;
    let invoker = ServerToolInvoker::new(state, session_id, &working_directory, cancel_state);
    let preparation = invoker
        .prepare_tool(&tool, &request, &scope)
        .await
        .map_err(|error| error.to_string())?;
    Ok(preparation)
}

async fn prepare_server_tool_with_cancel(
    state: &ServerState,
    session_id: SessionId,
    call: &bcode_model::ToolCall,
    cancel_state: &TurnCancelState,
) -> Result<(RegisteredTool, ToolPreparationResponse), String> {
    let tool = registered_server_tool(state, &call.name).await?;
    let preparation =
        prepare_registered_server_tool(state, session_id, tool.clone(), call, cancel_state).await?;
    Ok((tool, preparation))
}

async fn prepare_server_tool(
    state: &ServerState,
    session_id: SessionId,
    call: &bcode_model::ToolCall,
) -> Result<(RegisteredTool, ToolPreparationResponse), String> {
    prepare_server_tool_with_cancel(state, session_id, call, &TurnCancelState::default()).await
}

#[derive(Clone, Copy)]
struct ServerAuthorizationCoordinator<'a> {
    state: &'a ServerState,
    session_id: SessionId,
    cancel_state: &'a TurnCancelState,
    call_count: usize,
    tool_policy: bcode_session_models::TurnToolPolicy,
    agent_id: &'a str,
}

impl<'a> ServerAuthorizationCoordinator<'a> {
    const fn new(
        state: &'a ServerState,
        session_id: SessionId,
        cancel_state: &'a TurnCancelState,
        call_count: usize,
        tool_policy: bcode_session_models::TurnToolPolicy,
        agent_id: &'a str,
    ) -> Self {
        Self {
            state,
            session_id,
            cancel_state,
            call_count,
            tool_policy,
            agent_id,
        }
    }

    #[allow(clippy::too_many_lines)]
    async fn authorize_one(
        self,
        request: &ToolAuthorizationRequest,
        batch: Option<PermissionBatchCorrelation>,
    ) -> ToolAuthorizationDecision {
        let policy_metadata =
            match tool_policy_authorization_metadata(&request.facts, &request.call.name) {
                Ok(metadata) => metadata,
                Err(message) => {
                    return ToolAuthorizationDecision::Deny(format!(
                        "tool authorization facts invalid: {message}"
                    ));
                }
            };
        if tool_policy_denies_tool(self.tool_policy, Some(&policy_metadata)) {
            return ToolAuthorizationDecision::Deny(
                "tool denied by read-only inspection policy".to_string(),
            );
        }
        let ToolSource::Plugin { plugin_id } = &request.tool.source else {
            return ToolAuthorizationDecision::Deny(
                "server cannot authorize a non-plugin tool".to_string(),
            );
        };
        let agent_decision = evaluate_agent_tool_policy_with_metadata(
            self.state,
            self.session_id,
            self.agent_id,
            &request.call,
            &policy_metadata,
        )
        .await;
        append_trace_event(
            self.state,
            self.session_id,
            None,
            SessionTracePhase::ToolPolicyEvaluated,
            SessionTracePayload::ToolPolicyEvaluated {
                tool_call_id: request.call.id.clone(),
                agent_id: self.agent_id.to_string(),
                decision: agent_decision_name(agent_decision.decision).to_string(),
                reason: agent_decision.reason.clone(),
            },
        )
        .await;
        let skill_decision = evaluate_active_skill_tool_policy_with_metadata(
            self.state,
            self.session_id,
            &request.call.name,
            &policy_metadata,
        )
        .await;
        append_trace_event(
            self.state,
            self.session_id,
            None,
            SessionTracePhase::ToolPolicyEvaluated,
            SessionTracePayload::ToolPolicyEvaluated {
                tool_call_id: request.call.id.clone(),
                agent_id: self.agent_id.to_string(),
                decision: skill_tool_policy_decision_name(&skill_decision).to_string(),
                reason: skill_tool_policy_reason(&skill_decision),
            },
        )
        .await;
        if let SkillToolPolicyOutcome::Deny { reason } = skill_decision {
            return ToolAuthorizationDecision::Deny(reason);
        }
        if agent_decision.decision == AgentDecision::Deny {
            return ToolAuthorizationDecision::Deny(
                agent_decision
                    .reason
                    .unwrap_or_else(|| "tool denied by active agent policy".to_string()),
            );
        }

        let skill_requests_permission =
            matches!(skill_decision, SkillToolPolicyOutcome::Ask { .. });
        let mut policy_context = PermissionPolicyContext {
            source: None,
            reason: agent_decision.reason,
            skill_decision_key: None,
            batch: None,
        };
        let should_ask = if agent_decision.decision == AgentDecision::Ask {
            true
        } else if skill_requests_permission {
            let key =
                skill_tool_decision_key(self.state, self.session_id, &request.call.name).await;
            match key.as_ref().and_then(remembered_skill_tool_decision) {
                Some(SkillToolDecision::Allow) => {
                    append_trace_event(
                        self.state,
                        self.session_id,
                        None,
                        SessionTracePhase::ToolPolicyEvaluated,
                        SessionTracePayload::ToolPolicyEvaluated {
                            tool_call_id: request.call.id.clone(),
                            agent_id: self.agent_id.to_string(),
                            decision: "remembered_skill_allow".to_string(),
                            reason: Some(
                                "remembered skill tool decision allowed prompt skip".to_string(),
                            ),
                        },
                    )
                    .await;
                    return ToolAuthorizationDecision::Allow;
                }
                Some(SkillToolDecision::Deny) => {
                    append_trace_event(
                        self.state,
                        self.session_id,
                        None,
                        SessionTracePhase::ToolPolicyEvaluated,
                        SessionTracePayload::ToolPolicyEvaluated {
                            tool_call_id: request.call.id.clone(),
                            agent_id: self.agent_id.to_string(),
                            decision: "remembered_skill_deny".to_string(),
                            reason: Some(
                                "remembered skill tool decision denied tool call".to_string(),
                            ),
                        },
                    )
                    .await;
                    return ToolAuthorizationDecision::Deny(
                        "tool denied by remembered skill policy decision".to_string(),
                    );
                }
                None => {
                    policy_context = PermissionPolicyContext {
                        source: Some("skill".to_string()),
                        reason: skill_tool_policy_reason(&skill_decision),
                        skill_decision_key: key,
                        batch: None,
                    };
                    true
                }
            }
        } else {
            false
        };

        if !should_ask {
            return ToolAuthorizationDecision::Allow;
        }
        policy_context.batch = batch;
        if request_tool_permission(
            self.state,
            self.session_id,
            &request.call,
            &request.call.name,
            plugin_id,
            self.cancel_state,
            policy_context,
        )
        .await
        {
            ToolAuthorizationDecision::Allow
        } else {
            ToolAuthorizationDecision::Deny("permission denied".to_string())
        }
    }
}

impl ToolAuthorizationCoordinator for ServerAuthorizationCoordinator<'_> {
    fn authorize_batch<'a>(
        &'a self,
        requests: &'a [ToolAuthorizationRequest],
        _scope: &'a TurnScope,
    ) -> RuntimeFuture<'a, Vec<ToolAuthorizationDecision>> {
        Box::pin(async move {
            let batch_id = next_permission_batch_id(self.state).await;
            let batch_state = Arc::new(PendingPermissionBatch::new(self.session_id));
            let _registration = PendingPermissionBatchRegistration::register(
                Arc::clone(&self.state.pending_permission_batches),
                batch_id.clone(),
                batch_state,
            );
            let decisions = futures::future::join_all(requests.iter().map(|request| {
                self.authorize_one(
                    request,
                    Some(PermissionBatchCorrelation {
                        batch_id: batch_id.clone(),
                        call_index: request.index,
                        call_count: self.call_count,
                    }),
                )
            }))
            .await;
            Ok(decisions)
        })
    }
}

#[allow(clippy::too_many_lines)]
async fn execute_model_tool_batch(
    state: &ServerState,
    session_id: SessionId,
    calls: Vec<bcode_model::ToolCall>,
    cancel_state: Arc<TurnCancelState>,
    command_context: &mut RuntimeCommandContext<'_>,
    execution: &bcode_session_models::TurnExecutionOptions,
) -> bool {
    let tool_policy = execution.tools;
    let tool_allowlist = execution
        .tool_allowlist
        .as_ref()
        .map(|tools| tools.iter().cloned().collect::<BTreeSet<_>>());
    let call_count = calls.len();
    let catalog = match tokio::select! {
        biased;
        () = cancel_state.cancelled() => return false,
        catalog = tokio::time::timeout(
            Duration::from_millis(state.tool_execution.preparation_timeout_ms.get()),
            collect_server_tool_catalog(state),
        ) => catalog,
    } {
        Ok(Ok(catalog)) => catalog,
        Ok(Err(message)) => {
            tracing::warn!(%message, "failed to build server tool registry");
            return false;
        }
        Err(_) => {
            tracing::warn!("timed out building server tool registry");
            return false;
        }
    };
    let mut ready = Vec::new();
    let mut results = Vec::new();
    for (index, call) in calls.into_iter().enumerate() {
        if cancel_state.is_cancelled() {
            return false;
        }
        if tool_allowlist
            .as_ref()
            .is_some_and(|allowed| !allowed.contains(&call.name))
        {
            results.push((
                index,
                Some(ToolFinishedEventInput {
                    tool_call_id: call.id,
                    result: format!("tool denied by turn allowlist: {}", call.name),
                    is_error: true,
                    content: Vec::new(),
                    semantic_result: None,
                }),
            ));
            continue;
        }
        let Some(tool) = catalog.find_tool(&call.name) else {
            results.push((
                index,
                Some(ToolFinishedEventInput {
                    tool_call_id: call.id,
                    result: format!("tool not found: {}", call.name),
                    is_error: true,
                    content: Vec::new(),
                    semantic_result: None,
                }),
            ));
            continue;
        };
        let preparation = tokio::select! {
            biased;
            () = cancel_state.cancelled() => return false,
            preparation = tokio::time::timeout(
                Duration::from_millis(state.tool_execution.preparation_timeout_ms.get()),
                prepare_registered_server_tool(
                    state,
                    session_id,
                    tool.clone(),
                    &call,
                    cancel_state.as_ref(),
                ),
            ) => preparation,
        };
        let preparation = match preparation {
            Ok(Ok(prepared)) => prepared,
            Ok(Err(message)) => {
                results.push((
                    index,
                    Some(ToolFinishedEventInput {
                        tool_call_id: call.id,
                        result: format!("tool preparation failed: {message}"),
                        is_error: true,
                        content: Vec::new(),
                        semantic_result: None,
                    }),
                ));
                continue;
            }
            Err(_) => {
                results.push((
                    index,
                    Some(ToolFinishedEventInput {
                        tool_call_id: call.id,
                        result: "tool preparation timed out".to_string(),
                        is_error: true,
                        content: Vec::new(),
                        semantic_result: None,
                    }),
                ));
                continue;
            }
        };
        let policy_metadata =
            match tool_policy_authorization_metadata(&preparation.authorization, &call.name) {
                Ok(metadata) => metadata,
                Err(message) => {
                    results.push((
                        index,
                        Some(ToolFinishedEventInput {
                            tool_call_id: call.id,
                            result: format!("tool authorization facts invalid: {message}"),
                            is_error: true,
                            content: Vec::new(),
                            semantic_result: None,
                        }),
                    ));
                    continue;
                }
            };
        let Ok(working_directory) = state.sessions.session_working_directory(session_id).await
        else {
            return false;
        };
        append_tool_request_event(
            state,
            session_id,
            call.id.clone(),
            call.name.clone(),
            serde_json::to_string(&call.arguments).unwrap_or_default(),
            match &tool.source {
                ToolSource::Plugin { plugin_id } => Some(plugin_id.clone()),
                ToolSource::Inline => None,
            },
            &working_directory,
        )
        .await;
        ready.push((
            index,
            call,
            working_directory,
            tool,
            policy_metadata,
            preparation,
        ));
    }

    if !ready.is_empty() {
        let agent_id = execution
            .agent_profile
            .clone()
            .unwrap_or(session_agent_selection(state, session_id).await);
        let permission_context = bcode_agent_runtime::RuntimePermissionContext {
            session_id,
            agent_id: agent_id.clone(),
        };
        let authorization_requests = ready
            .iter()
            .map(
                |(index, call, _, tool, _, preparation)| ToolAuthorizationRequest {
                    index: *index,
                    call: call.clone(),
                    tool: tool.clone(),
                    facts: preparation.authorization.clone(),
                    context: permission_context.clone(),
                },
            )
            .collect::<Vec<_>>();
        let authorization_scope = TurnScope::without_events(
            format!("server-tool-batch:{session_id}"),
            TurnGeneration::new(0),
        );
        let coordinator = ServerAuthorizationCoordinator::new(
            state,
            session_id,
            cancel_state.as_ref(),
            call_count,
            tool_policy,
            &agent_id,
        );
        let authorization =
            coordinator.authorize_batch(&authorization_requests, &authorization_scope);
        let ProviderCallWait::Completed(Ok(decisions)) = wait_for_provider_call(
            state,
            session_id,
            command_context,
            cancel_state.as_ref(),
            Box::pin(authorization),
        )
        .await
        else {
            return false;
        };
        if decisions.len() != ready.len() {
            return false;
        }
        let mut approved = Vec::new();
        for ((index, call, working_directory, tool, _policy_metadata, preparation), decision) in
            ready.into_iter().zip(decisions)
        {
            match decision {
                ToolAuthorizationDecision::Allow => {
                    approved.push((index, call, working_directory, tool, preparation));
                }
                ToolAuthorizationDecision::Ask(reason)
                | ToolAuthorizationDecision::Deny(reason) => results.push((
                    index,
                    Some(ToolFinishedEventInput {
                        tool_call_id: call.id,
                        result: reason,
                        is_error: true,
                        content: Vec::new(),
                        semantic_result: None,
                    }),
                )),
            }
        }
        if approved.is_empty() {
            results.sort_by_key(|(index, _)| *index);
            for (_, result) in results {
                if let Some(result) = result {
                    append_tool_finished_event(state, session_id, result).await;
                }
            }
            return !cancel_state.is_cancelled();
        }
        let invocation_permits = if state.tool_execution.parallel {
            state
                .tool_execution
                .max_concurrency
                .map(|limit| Arc::new(Semaphore::new(limit.get())))
        } else {
            Some(Arc::new(Semaphore::new(1)))
        };
        let execution_count = approved.len();
        let executions = stream::iter(approved.into_iter().map(
            |(index, call, working_directory, tool, preparation)| {
                let cancel_state = Arc::clone(&cancel_state);
                let invocation_permits = invocation_permits.clone();
                async move {
                    (
                        index,
                        execute_model_tool(
                            state,
                            session_id,
                            call,
                            working_directory,
                            tool,
                            preparation,
                            cancel_state,
                            invocation_permits,
                        )
                        .await,
                    )
                }
            },
        ))
        .buffer_unordered(execution_count)
        .collect::<Vec<_>>();
        let finalized = wait_for_finalizable_provider_call(
            state,
            session_id,
            command_context,
            cancel_state.as_ref(),
            Box::pin(executions),
        )
        .await;
        let executed = match finalized {
            FinalizedProviderCall::Completed(executed)
            | FinalizedProviderCall::Cancelled(executed) => executed,
        };
        results.extend(executed);
    }

    results.sort_by_key(|(index, _)| *index);
    for (_, result) in results {
        if let Some(result) = result {
            append_tool_finished_event(state, session_id, result).await;
        }
    }
    !cancel_state.is_cancelled()
}

#[allow(clippy::too_many_arguments, clippy::too_many_lines)]
async fn execute_model_tool(
    state: &ServerState,
    session_id: SessionId,
    call: bcode_model::ToolCall,
    working_directory: std::path::PathBuf,
    tool: RegisteredTool,
    preparation: ToolPreparationResponse,
    cancel_state: Arc<TurnCancelState>,
    invocation_permits: Option<Arc<Semaphore>>,
) -> Option<ToolFinishedEventInput> {
    let producer_plugin_id = match &tool.source {
        ToolSource::Plugin { plugin_id } => Some(plugin_id.clone()),
        ToolSource::Inline => None,
    };
    if cancel_state.is_cancelled() {
        cancel_registered_runtime_work(
            state,
            session_id,
            WorkId::new(format!("tool_{}", call.id)),
            None,
        )
        .await;
        return None;
    }
    let _invocation_permit = if let Some(permits) = invocation_permits {
        Some(tokio::select! {
            biased;
            () = cancel_state.cancelled() => {
                cancel_registered_runtime_work(
                    state,
                    session_id,
                    WorkId::new(format!("tool_{}", call.id)),
                    None,
                )
                .await;
                return None;
            }
            permit = permits.acquire_owned() => {
                match permit {
                    Ok(permit) => permit,
                    Err(_) => return None,
                }
            }
        })
    } else {
        None
    };
    if cancel_state.is_cancelled() {
        return None;
    }
    append_tool_invocation_lifecycle_event(
        state,
        session_id,
        bcode_session_models::ToolInvocationLifecycleEvent {
            invocation_id: call.id.clone(),
            sequence: 0,
            stage: bcode_session_models::ToolInvocationLifecycleStage::Started,
            message: None,
            metadata: serde_json::Value::Null,
        },
    )
    .await;
    let tool_labels =
        tool_invocation_metric_labels(session_id, &call.name, producer_plugin_id.as_deref());
    let tool_span = state
        .metrics
        .span("tool.invocation")
        .labels(tool_labels.clone());
    let tool_start = Instant::now();
    let invocation = PreparedToolInvocation {
        invocation: ToolInvocationDescriptor {
            invocation_id: call.id.clone(),
            tool_name: call.name.clone(),
            arguments: call.arguments.clone(),
        },
        preparation,
    };
    let invocation_scope = InvocationScope::new(
        TurnScope::without_events(
            format!("server-tool-invocation:{session_id}"),
            TurnGeneration::new(0),
        ),
        call.id.clone(),
    );
    let invoker =
        ServerToolInvoker::new(state, session_id, &working_directory, cancel_state.as_ref());
    let result = invoker
        .invoke_tool(&tool, &invocation, &invocation_scope)
        .await
        .unwrap_or_else(|error| ToolInvocationResponse {
            output: error.to_string(),
            is_error: true,
            content: Vec::new(),
            full_output: None,
            result: None,
        });
    if cancel_state.is_cancelled() {
        append_tool_invocation_terminal_event(
            state,
            session_id,
            &call.id,
            bcode_session_models::ToolInvocationLifecycleStage::Cancelled,
        )
        .await;
        tool_span.finish_err();
        return None;
    }
    let lifecycle_stage = if result.is_error {
        bcode_session_models::ToolInvocationLifecycleStage::Failed
    } else {
        bcode_session_models::ToolInvocationLifecycleStage::Completed
    };
    append_tool_invocation_terminal_event(state, session_id, &call.id, lifecycle_stage).await;
    let semantic_result = result.result.clone().map(service_tool_result_to_session);
    let artifact_output = result.full_output.as_deref().unwrap_or(&result.output);
    let output_bytes = artifact_output.len();
    state.metrics.record_histogram_with_labels(
        "tool.invocation.output_bytes",
        usize_to_u64(output_bytes),
        tool_labels.clone(),
    );
    if result.is_error {
        state.metrics.add_counter_with_labels(
            "tool.invocation.errors_total",
            1,
            tool_labels.clone(),
        );
        tool_span.finish_err();
    } else {
        tool_span.finish_ok();
    }
    let output_blob = (state.observability.persist_tool_io || state.observability.debug_enabled())
        .then(|| {
            state.trace_store.write_text_blob(
                session_id,
                &format!("tool-output-{}", call.id),
                artifact_output,
                0,
            )
        })
        .flatten();
    append_trace_event(
        state,
        session_id,
        None,
        SessionTracePhase::ToolInvocationFinished,
        SessionTracePayload::ToolInvocationFinished {
            tool_call_id: call.id.clone(),
            duration_ms: elapsed_ms(tool_start),
            is_error: result.is_error,
            output_bytes,
            output: output_blob.clone(),
        },
    )
    .await;
    Some(ToolFinishedEventInput {
        tool_call_id: call.id,
        result: result.output,
        is_error: result.is_error,
        content: result.content,
        semantic_result,
    })
}

fn tool_invocation_metric_labels(
    session_id: SessionId,
    tool_name: &str,
    plugin_id: Option<&str>,
) -> MetricLabels {
    let mut labels = MetricLabels::new();
    labels.insert("session_id".to_owned(), session_id.to_string());
    labels.insert("tool_name".to_owned(), tool_name.to_owned());
    if let Some(plugin_id) = plugin_id {
        labels.insert("plugin_id".to_owned(), plugin_id.to_owned());
    }
    labels
}

struct ServerPluginBridgeCall {
    request: ServiceBridgeRequest,
    response: std::sync::mpsc::SyncSender<Result<ServiceBridgeResponse, String>>,
}

fn server_plugin_bridge() -> (
    PluginInvocationBridge,
    mpsc::UnboundedReceiver<ServerPluginBridgeCall>,
) {
    let (sender, receiver) = mpsc::unbounded_channel::<ServerPluginBridgeCall>();
    let bridge = PluginInvocationBridge::new(move |request, cancellation| {
        request_server_plugin_bridge(&sender, request, &cancellation)
    });
    (bridge, receiver)
}

fn request_server_plugin_bridge(
    sender: &mpsc::UnboundedSender<ServerPluginBridgeCall>,
    request: ServiceBridgeRequest,
    cancellation: &bcode_plugin_sdk::ServiceCancellation,
) -> Result<ServiceBridgeResponse, String> {
    let (response, response_receiver) = std::sync::mpsc::sync_channel(1);
    sender
        .send(ServerPluginBridgeCall { request, response })
        .map_err(|_| "server invocation bridge closed".to_string())?;
    loop {
        if cancellation.is_cancelled() {
            return Err("server invocation bridge cancelled".to_string());
        }
        match response_receiver.recv_timeout(Duration::from_millis(10)) {
            Ok(response) => return response,
            Err(std::sync::mpsc::RecvTimeoutError::Timeout) => {}
            Err(std::sync::mpsc::RecvTimeoutError::Disconnected) => {
                return Err("server invocation bridge response closed".to_string());
            }
        }
    }
}

struct ServerInputRouter<'a> {
    invocation_id: &'a str,
    inputs: &'a Mutex<mpsc::Receiver<ToolInvocationInput>>,
    cancel_state: &'a TurnCancelState,
}

impl<'a> ServerInputRouter<'a> {
    const fn new(
        invocation_id: &'a str,
        inputs: &'a Mutex<mpsc::Receiver<ToolInvocationInput>>,
        cancel_state: &'a TurnCancelState,
    ) -> Self {
        Self {
            invocation_id,
            inputs,
            cancel_state,
        }
    }
}

impl InvocationInputRouter for ServerInputRouter<'_> {
    fn receive(
        &self,
        invocation_id: &str,
    ) -> InvocationCapabilityFuture<'_, ToolInvocationInputResolution> {
        let identity_matches = invocation_id == self.invocation_id;
        Box::pin(async move {
            if !identity_matches {
                return ToolInvocationInputResolution::Failed {
                    code: "invocation_id_mismatch".to_string(),
                    message: "input request does not belong to the active invocation".to_string(),
                };
            }
            if self.cancel_state.is_cancelled() {
                return ToolInvocationInputResolution::Cancelled;
            }
            let mut inputs = self.inputs.lock().await;
            let resolution = tokio::select! {
                input = inputs.recv() => input.map_or(
                    ToolInvocationInputResolution::Closed,
                    |input| ToolInvocationInputResolution::Received { input },
                ),
                () = self.cancel_state.cancelled() => ToolInvocationInputResolution::Cancelled,
            };
            drop(inputs);
            resolution
        })
    }
}

const SESSION_ARTIFACT_WRITE_MAX_BYTES: u64 = 1024 * 1024;

struct SessionArtifactSink<'a> {
    root: PathBuf,
    invocation_id: &'a str,
    cancel_state: &'a TurnCancelState,
}

impl<'a> SessionArtifactSink<'a> {
    const fn new(root: PathBuf, invocation_id: &'a str, cancel_state: &'a TurnCancelState) -> Self {
        Self {
            root,
            invocation_id,
            cancel_state,
        }
    }
}

impl InvocationArtifactSink for SessionArtifactSink<'_> {
    fn write(
        &self,
        request: ToolArtifactWriteRequest,
        commit: ArtifactCommitGuard,
    ) -> InvocationCapabilityFuture<'_, ToolArtifactWriteResolution> {
        Box::pin(async move {
            if request.invocation_id != self.invocation_id {
                return ToolArtifactWriteResolution::Failed {
                    code: "invocation_id_mismatch".to_string(),
                    message: "artifact does not belong to the active invocation".to_string(),
                };
            }
            if self.cancel_state.is_cancelled() {
                return ToolArtifactWriteResolution::Cancelled;
            }
            let Ok(byte_len) = u64::try_from(request.bytes.len()) else {
                return ToolArtifactWriteResolution::TooLarge {
                    max_bytes: SESSION_ARTIFACT_WRITE_MAX_BYTES,
                };
            };
            if byte_len > SESSION_ARTIFACT_WRITE_MAX_BYTES {
                return ToolArtifactWriteResolution::TooLarge {
                    max_bytes: SESSION_ARTIFACT_WRITE_MAX_BYTES,
                };
            }
            if request.artifact_id.trim().is_empty() || request.content_type.trim().is_empty() {
                return ToolArtifactWriteResolution::Failed {
                    code: "invalid_request".to_string(),
                    message: "artifact id and content type must not be empty".to_string(),
                };
            }
            match write_session_invocation_artifact(
                &self.root,
                self.invocation_id,
                &request,
                self.cancel_state,
                commit,
            ) {
                Ok(reference) => ToolArtifactWriteResolution::Written {
                    artifact_id: request.artifact_id,
                    byte_len,
                    reference,
                },
                Err((code, _)) if code == "cancelled" => ToolArtifactWriteResolution::Cancelled,
                Err((code, message)) => ToolArtifactWriteResolution::Failed { code, message },
            }
        })
    }
}

fn write_session_invocation_artifact(
    root: &Path,
    invocation_id: &str,
    request: &ToolArtifactWriteRequest,
    cancel_state: &TurnCancelState,
    commit: ArtifactCommitGuard,
) -> Result<serde_json::Value, (String, String)> {
    write_session_invocation_artifact_with_publish_hook(
        root,
        invocation_id,
        request,
        cancel_state,
        commit,
        || {},
    )
}

fn write_session_invocation_artifact_with_publish_hook<F>(
    root: &Path,
    invocation_id: &str,
    request: &ToolArtifactWriteRequest,
    cancel_state: &TurnCancelState,
    commit: ArtifactCommitGuard,
    after_publish: F,
) -> Result<serde_json::Value, (String, String)>
where
    F: FnOnce(),
{
    use sha2::{Digest as _, Sha256};

    let invocation_key = format!("{:x}", Sha256::digest(invocation_id.as_bytes()));
    let artifact_key = format!("{:x}", Sha256::digest(request.artifact_id.as_bytes()));
    std::fs::create_dir_all(root)
        .map_err(|error| ("create_directory_failed".to_string(), error.to_string()))?;
    let canonical_root = root
        .canonicalize()
        .map_err(|error| ("invalid_artifact_root".to_string(), error.to_string()))?;
    let directory = root.join("invocation-artifacts").join(&invocation_key);
    std::fs::create_dir_all(&directory)
        .map_err(|error| ("create_directory_failed".to_string(), error.to_string()))?;
    let canonical_directory = directory
        .canonicalize()
        .map_err(|error| ("invalid_artifact_directory".to_string(), error.to_string()))?;
    if !canonical_directory.starts_with(&canonical_root) {
        return Err((
            "invalid_artifact_directory".to_string(),
            "artifact directory is outside the session artifact root".to_string(),
        ));
    }
    let destination = canonical_directory.join(format!("{artifact_key}.bin"));
    if destination.exists() {
        return Err((
            "duplicate_artifact".to_string(),
            "artifact id is already written for this invocation".to_string(),
        ));
    }
    let temporary = canonical_directory.join(format!(".{artifact_key}.tmp"));
    let write_result = (|| -> std::io::Result<()> {
        let mut file = std::fs::OpenOptions::new()
            .write(true)
            .create_new(true)
            .open(&temporary)?;
        file.write_all(&request.bytes)?;
        file.sync_all()
    })();
    if let Err(error) = write_result {
        let _ = std::fs::remove_file(&temporary);
        return Err(("artifact_write_failed".to_string(), error.to_string()));
    }
    if cancel_state.is_cancelled() {
        let _ = std::fs::remove_file(&temporary);
        return Err((
            "cancelled".to_string(),
            "artifact write cancelled".to_string(),
        ));
    }
    let publication = commit.commit(|| {
        let result = std::fs::hard_link(&temporary, &destination);
        if result.is_ok() {
            after_publish();
        }
        result
    });
    let Some(publication) = publication else {
        let _ = std::fs::remove_file(&temporary);
        return Err((
            "cancelled".to_string(),
            "artifact publication rejected by closed turn scope".to_string(),
        ));
    };
    if let Err(error) = publication {
        let _ = std::fs::remove_file(&temporary);
        return if error.kind() == std::io::ErrorKind::AlreadyExists {
            Err((
                "duplicate_artifact".to_string(),
                "artifact id is already written for this invocation".to_string(),
            ))
        } else {
            Err(("artifact_publish_failed".to_string(), error.to_string()))
        };
    }
    if cancel_state.is_cancelled() {
        let _ = std::fs::remove_file(&temporary);
        let _ = std::fs::remove_file(&destination);
        return Err((
            "cancelled".to_string(),
            "artifact publication cancelled".to_string(),
        ));
    }
    let _ = std::fs::remove_file(&temporary);
    if let Err(error) = sync_artifact_directory(&canonical_directory) {
        let _ = std::fs::remove_file(&destination);
        return Err(("artifact_sync_failed".to_string(), error.to_string()));
    }
    Ok(serde_json::json!({
        "uri": format!("bcode-artifact://invocation/{invocation_key}/{artifact_key}"),
        "content_type": request.content_type,
        "metadata": request.metadata,
    }))
}

fn sync_artifact_directory(directory: &Path) -> std::io::Result<()> {
    #[cfg(unix)]
    {
        std::fs::File::open(directory)?.sync_all()
    }
    #[cfg(not(unix))]
    {
        let _ = directory;
        Ok(())
    }
}

struct ServerServiceRouter<'a> {
    state: &'a ServerState,
    session_id: SessionId,
    call: &'a bcode_model::ToolCall,
    cancel_state: &'a TurnCancelState,
}

impl<'a> ServerServiceRouter<'a> {
    const fn new(
        state: &'a ServerState,
        session_id: SessionId,
        call: &'a bcode_model::ToolCall,
        cancel_state: &'a TurnCancelState,
    ) -> Self {
        Self {
            state,
            session_id,
            call,
            cancel_state,
        }
    }
}

impl InvocationServiceRouter for ServerServiceRouter<'_> {
    fn invoke(
        &self,
        request: ToolInvocationServiceRequest,
    ) -> InvocationCapabilityFuture<'_, ToolInvocationServiceResolution> {
        Box::pin(async move {
            if request.invocation_id != self.call.id {
                return ToolInvocationServiceResolution::Failed {
                    code: "invocation_id_mismatch".to_string(),
                    message: "service request does not belong to the active invocation".to_string(),
                };
            }
            if self.cancel_state.is_cancelled() {
                return ToolInvocationServiceResolution::Cancelled;
            }
            let Some(route_id) = request.route_id.as_deref() else {
                return ToolInvocationServiceResolution::Unsupported;
            };
            let Some(route) = invocation_service_routes(self.state, self.session_id)
                .await
                .into_iter()
                .find(|route| {
                    route.advertised.route_id == route_id
                        && route.advertised.interface_id == request.interface_id
                        && route
                            .advertised
                            .operations
                            .iter()
                            .any(|operation| operation == &request.operation)
                })
            else {
                return ToolInvocationServiceResolution::Unsupported;
            };
            let Some(mut payload) = request.payload.as_object().cloned() else {
                return ToolInvocationServiceResolution::Failed {
                    code: "invalid_request".to_owned(),
                    message: "routed service payload must be a JSON object".to_owned(),
                };
            };
            if let Some(overlay) = route.payload_overlay.as_object() {
                payload.extend(overlay.clone());
            }
            let target_plugin_id = match route.target_plugin_id {
                Some(plugin_id) => plugin_id,
                None => match self
                    .state
                    .plugins
                    .registry()
                    .service_registry()
                    .unique_provider(&request.interface_id)
                {
                    Ok(plugin_id) => plugin_id.to_owned(),
                    Err(_) => return ToolInvocationServiceResolution::Unsupported,
                },
            };
            let routed_payload = serde_json::Value::Object(payload);
            let service = self
                .state
                .plugins
                .invoke_service_json_scoped::<_, serde_json::Value>(
                    &target_plugin_id,
                    &request.interface_id,
                    &request.operation,
                    &routed_payload,
                    active_plugin_scope_for_tool_call(self.state, self.session_id, &self.call.id)
                        .await,
                );
            let response = tokio::select! {
                biased;
                () = self.cancel_state.cancelled() => {
                    return ToolInvocationServiceResolution::Cancelled;
                }
                response = service => response,
            };
            if self.cancel_state.is_cancelled() {
                return ToolInvocationServiceResolution::Cancelled;
            }
            match response {
                Ok(payload) => ToolInvocationServiceResolution::Responded { payload },
                Err(message) => ToolInvocationServiceResolution::Failed {
                    code: "service_failed".to_string(),
                    message: message.to_string(),
                },
            }
        })
    }
}

struct ServerExchangeBroker<'a> {
    state: &'a ServerState,
    session_id: SessionId,
    call: &'a bcode_model::ToolCall,
    cancel_state: &'a TurnCancelState,
}

impl<'a> ServerExchangeBroker<'a> {
    const fn new(
        state: &'a ServerState,
        session_id: SessionId,
        call: &'a bcode_model::ToolCall,
        cancel_state: &'a TurnCancelState,
    ) -> Self {
        Self {
            state,
            session_id,
            call,
            cancel_state,
        }
    }
}

impl InvocationExchangeBroker for ServerExchangeBroker<'_> {
    fn request(
        &self,
        request: ToolExchangeRequest,
    ) -> InvocationCapabilityFuture<'_, ToolExchangeResolution> {
        Box::pin(async move {
            if self.cancel_state.is_cancelled() {
                return ToolExchangeResolution::Cancelled;
            }
            if request.invocation_id != self.call.id {
                return ToolExchangeResolution::Failed {
                    code: "invocation_id_mismatch".to_owned(),
                    message: "exchange does not belong to the active invocation".to_owned(),
                };
            }
            if request.exchange_id.trim().is_empty() {
                return ToolExchangeResolution::Failed {
                    code: "invalid_exchange_id".to_owned(),
                    message: "exchange ID must not be empty".to_owned(),
                };
            }
            append_tool_exchange_requested_event(self.state, self.session_id, request.clone())
                .await;
            let resolution = resolve_server_exchange(
                self.state,
                self.session_id,
                self.call,
                request.clone(),
                self.cancel_state,
            )
            .await
            .unwrap_or_else(|message| ToolExchangeResolution::Failed {
                code: "server_exchange_failed".to_string(),
                message,
            });
            append_tool_exchange_resolved_event(
                self.state,
                self.session_id,
                bcode_session_models::ToolExchangeResolutionEvent {
                    invocation_id: request.invocation_id,
                    exchange_id: request.exchange_id,
                    resolution: resolution.clone(),
                },
            )
            .await;
            resolution
        })
    }
}

async fn resolve_server_plugin_bridge_request(
    state: &ServerState,
    session_id: SessionId,
    call: &bcode_model::ToolCall,
    _plugin_id: &str,
    request: ServiceBridgeRequest,
    inputs: &Mutex<mpsc::Receiver<ToolInvocationInput>>,
    cancel_state: &TurnCancelState,
) -> Result<ServiceBridgeResponse, String> {
    Ok(match request {
        ServiceBridgeRequest::Exchange(request) => {
            let broker = ServerExchangeBroker::new(state, session_id, call, cancel_state);
            ServiceBridgeResponse::Exchange(broker.request(request).await)
        }
        ServiceBridgeRequest::ReceiveInput {
            invocation_id,
            timeout_ms,
        } => {
            let router = ServerInputRouter::new(&call.id, inputs, cancel_state);
            let receive = router.receive(&invocation_id);
            ServiceBridgeResponse::Input(if let Some(timeout_ms) = timeout_ms {
                tokio::time::timeout(Duration::from_millis(timeout_ms), receive)
                    .await
                    .unwrap_or(ToolInvocationInputResolution::TimedOut)
            } else {
                receive.await
            })
        }
        ServiceBridgeRequest::InvokeService(request) => {
            let router = ServerServiceRouter::new(state, session_id, call, cancel_state);
            ServiceBridgeResponse::Service(router.invoke(request).await)
        }
        ServiceBridgeRequest::WriteArtifact(request) => {
            let sink = SessionArtifactSink::new(
                default_session_artifact_dir(session_id),
                &call.id,
                cancel_state,
            );
            let scope = InvocationScope::new(
                TurnScope::without_events(
                    format!("server-artifact:{session_id}"),
                    TurnGeneration::new(0),
                ),
                call.id.clone(),
            );
            ServiceBridgeResponse::Artifact(
                sink.write(request, scope.artifact_commit_guard()).await,
            )
        }
    })
}

async fn resolve_server_exchange(
    state: &ServerState,
    session_id: SessionId,
    call: &bcode_model::ToolCall,
    request: ToolExchangeRequest,
    cancel_state: &TurnCancelState,
) -> Result<ToolExchangeResolution, String> {
    if request.invocation_id != call.id {
        return Ok(ToolExchangeResolution::Failed {
            code: "invocation_id_mismatch".to_string(),
            message: "exchange does not belong to the active tool invocation".to_string(),
        });
    }
    if !state.has_exchange_consumer(&request).await {
        return Ok(ToolExchangeResolution::NoCompatibleConsumer);
    }
    let resolution = resolve_tool_exchange(state, session_id, call, &request, cancel_state).await?;
    Ok(resolution)
}

#[derive(Debug)]
struct ServerPluginInvocationCancellation(bcode_plugin::PluginInvocationCancelHandle);

impl InvocationCancellation for ServerPluginInvocationCancellation {
    fn request_cancel(&self) {
        self.0.cancel();
    }
}

#[allow(clippy::too_many_arguments, clippy::too_many_lines)]
async fn invoke_model_tool(
    state: &ServerState,
    session_id: SessionId,
    call: &bcode_model::ToolCall,
    working_directory: &std::path::Path,
    plugin_id: &str,
    policy_metadata: &ToolPolicyAuthorizationMetadata,
    preparation_descriptor: serde_json::Value,
    cancel_state: &TurnCancelState,
    invocation_scope: Option<&InvocationScope>,
    invocation_permits: Option<Arc<Semaphore>>,
) -> Result<ToolInvocationResponse, String> {
    if cancel_state.is_cancelled() {
        return Ok(ToolInvocationResponse {
            output: "tool cancelled before invocation".to_string(),
            is_error: true,
            content: Vec::new(),
            full_output: None,
            result: None,
        });
    }
    let _invocation_permit = if let Some(permits) = invocation_permits {
        Some(tokio::select! {
            biased;
            () = cancel_state.cancelled() => {
                return Ok(tool_error("tool cancelled before invocation admission"));
            }
            permit = permits.acquire_owned() => {
                permit.map_err(|_| "tool invocation admission closed".to_string())?
            }
        })
    } else {
        None
    };
    if cancel_state.is_cancelled() {
        return Ok(tool_error("tool cancelled before invocation"));
    }
    let argument_blob = (state.observability.persist_tool_io
        || state.observability.debug_enabled())
    .then(|| {
        state.trace_store.write_json_blob(
            session_id,
            &format!("tool-arguments-{}", call.id),
            &call.arguments,
            state.observability.max_blob_bytes,
        )
    })
    .flatten();
    append_trace_event(
        state,
        session_id,
        None,
        SessionTracePhase::ToolInvocationStarted,
        SessionTracePayload::ToolInvocationStarted {
            tool_call_id: call.id.clone(),
            plugin_id: plugin_id.to_string(),
            tool_name: call.name.clone(),
            side_effect: policy_metadata.operation_name().to_string(),
            requires_permission: policy_metadata.requires_permission,
            arguments: argument_blob,
        },
    )
    .await;
    let working_directory = working_directory.to_path_buf();
    let (input_sender, input_receiver) = mpsc::channel(ACTIVE_INVOCATION_INPUT_QUEUE_CAPACITY);
    let input_receiver = Mutex::new(input_receiver);
    let _action_registration = ActivePluginInvocationRegistration::register(
        Arc::clone(&state.active_plugin_invocations),
        Arc::clone(&state.active_artifacts),
        Arc::clone(&state.active_plugin_visuals),
        session_id,
        &call.id,
        ActivePluginInvocation {
            producer_plugin_id: plugin_id.to_string(),
            inputs: input_sender,
        },
    )?;
    let request = ToolInvocationRequest {
        tool_call_id: call.id.clone(),
        name: call.name.clone(),
        arguments: call.arguments.clone(),
        preparation_descriptor,
        cwd: Some(working_directory),
        artifact_dir: Some(default_session_artifact_dir(session_id)),
    };
    let payload = serde_json::to_vec(&request).map_err(|error| error.to_string())?;
    let scope = active_plugin_scope_for_tool_call(state, session_id, &call.id).await;
    let (bridge, bridge_requests) = server_plugin_bridge();
    let mut bridge_requests = Some(bridge_requests);
    let mut bridge_resolutions = futures::stream::FuturesUnordered::new();
    let mut invocation = state
        .plugins
        .invoke_service_with_events_and_bridge_scoped(
            plugin_id,
            TOOL_SERVICE_INTERFACE_ID,
            OP_INVOKE_TOOL,
            payload,
            scope,
            Some(bridge),
        )
        .await
        .map_err(|error| error.to_string())?;
    let tool_work_id = WorkId::new(format!("tool_{}", call.id));
    let _ = state
        .runtime_work
        .replace_cancellation(
            session_id,
            &tool_work_id,
            CancellationHandle::PluginInvocation(invocation.cancel.clone()),
        )
        .await;
    let scope_cancellation = invocation_scope.map(InvocationScope::cancellation);
    if invocation_scope.is_some_and(|scope| {
        !scope.register_cancellation(Arc::new(ServerPluginInvocationCancellation(
            invocation.cancel.clone(),
        )))
    }) {
        invocation.cancel.cancel();
        return Ok(tool_error("tool cancelled before invocation became active"));
    }
    let mut tool_output_publisher = ToolOutputLivePublisher::new();
    let mut stream_sequences: BTreeMap<String, u64> = BTreeMap::new();
    let response = loop {
        tokio::select! {
            biased;
            () = cancel_state.cancelled() => {
                invocation.cancel.cancel();
                drop(bridge_resolutions);
                input_receiver.lock().await.close();
                return Ok(tool_error("tool invocation cancelled"));
            }
            () = async {
                if let Some(cancellation) = &scope_cancellation {
                    cancellation.cancelled().await;
                } else {
                    std::future::pending::<()>().await;
                }
            } => {
                invocation.cancel.cancel();
                drop(bridge_resolutions);
                input_receiver.lock().await.close();
                return Ok(tool_error("tool invocation cancelled"));
            }
            publisher_event = tool_output_publisher.next_event() => {
                if let Some(publisher_event) = publisher_event {
                    tool_output_publisher.handle_event(state, session_id, publisher_event).await;
                }
            }
            bridge_call = async {
                bridge_requests
                    .as_mut()
                    .expect("guarded bridge receiver")
                    .recv()
                    .await
            }, if bridge_requests.is_some() => {
                if let Some(bridge_call) = bridge_call {
                    let plugin_id = &plugin_id;
                    let input_receiver = &input_receiver;
                    bridge_resolutions.push(async move {
                        let resolution = resolve_server_plugin_bridge_request(
                            state,
                            session_id,
                            call,
                            plugin_id,
                            bridge_call.request,
                            input_receiver,
                            cancel_state,
                        ).await;
                        let _ = bridge_call.response.send(resolution);
                    });
                } else {
                    bridge_requests = None;
                }
            }
            _ = bridge_resolutions.next(), if !bridge_resolutions.is_empty() => {}
            event = invocation.next_event() => {
                match event.map_err(|error| error.to_string())? {
                    StreamingServiceInvocationEvent::Event(payload) => {
                        if !cancel_state.is_cancelled() {
                            if let Ok(lifecycle) = serde_json::from_slice::<
                                bcode_session_models::ToolInvocationLifecycleEvent,
                            >(&payload)
                            {
                                append_plugin_tool_lifecycle_event(
                                    state,
                                    session_id,
                                    &call.id,
                                    lifecycle,
                                )
                                .await;
                            } else if let Ok(envelope) = serde_json::from_slice::<
                                bcode_session_models::ToolContributionEnvelope,
                            >(&payload)
                            {
                                append_tool_contribution_envelope(
                                    state,
                                    session_id,
                                    &call.id,
                                    plugin_id,
                                    envelope,
                                )
                                .await;
                            } else if let Ok(contribution) = serde_json::from_slice::<
                                bcode_session_models::ToolContributionEvent,
                            >(&payload)
                            {
                                append_tool_contribution_event(
                                    state,
                                    session_id,
                                    &call.id,
                                    plugin_id,
                                    contribution,
                                )
                                .await;
                            } else if let Ok(event) = serde_json::from_slice::<
                                ServiceToolInvocationStreamEvent,
                            >(&payload)
                            {
                                let event = normalize_tool_stream_event_sequence(
                                    event,
                                    &mut stream_sequences,
                                );
                                tool_output_publisher
                                    .push_stream_event(state, session_id, event)
                                    .await;
                            }
                        }
                    }
                    StreamingServiceInvocationEvent::Response(response) => {
                        break response.map_err(|error| error.to_string())?;
                    }
                }
            }
        }
    };
    drop(bridge_resolutions);
    input_receiver.lock().await.close();
    while !cancel_state.is_cancelled()
        && let Some(payload) = invocation.try_recv_event()
    {
        if let Ok(lifecycle) =
            serde_json::from_slice::<bcode_session_models::ToolInvocationLifecycleEvent>(&payload)
        {
            append_plugin_tool_lifecycle_event(state, session_id, &call.id, lifecycle).await;
        } else if let Ok(envelope) =
            serde_json::from_slice::<bcode_session_models::ToolContributionEnvelope>(&payload)
        {
            append_tool_contribution_envelope(state, session_id, &call.id, plugin_id, envelope)
                .await;
        } else if let Ok(contribution) =
            serde_json::from_slice::<bcode_session_models::ToolContributionEvent>(&payload)
        {
            append_tool_contribution_event(state, session_id, &call.id, plugin_id, contribution)
                .await;
        } else if let Ok(event) =
            serde_json::from_slice::<ServiceToolInvocationStreamEvent>(&payload)
        {
            let event = normalize_tool_stream_event_sequence(event, &mut stream_sequences);
            tool_output_publisher
                .push_stream_event(state, session_id, event)
                .await;
        }
    }
    tool_output_publisher.finish(state, session_id).await;
    if let Some(scope) = invocation_scope {
        let _ = scope.unregister_cancellation();
    }
    let response: ToolInvocationResponse =
        bcode_plugin::decode_service_response(response).map_err(|error| error.to_string())?;
    Ok(response)
}

async fn append_tool_exchange_requested_event(
    state: &ServerState,
    session_id: SessionId,
    request: bcode_session_models::ToolExchangeRequest,
) {
    match state
        .sessions
        .append_event(
            session_id,
            SessionEventKind::ToolExchangeRequested { request },
        )
        .await
    {
        Ok(event) => publish_session_event(state, &event).await,
        Err(error) => tracing::warn!(%error, "failed to append tool exchange request"),
    }
}

async fn append_tool_exchange_resolved_event(
    state: &ServerState,
    session_id: SessionId,
    event: bcode_session_models::ToolExchangeResolutionEvent,
) {
    match state
        .sessions
        .append_event(session_id, SessionEventKind::ToolExchangeResolved { event })
        .await
    {
        Ok(event) => publish_session_event(state, &event).await,
        Err(error) => tracing::warn!(%error, "failed to append tool exchange resolution"),
    }
}

async fn append_plugin_tool_lifecycle_event(
    state: &ServerState,
    session_id: SessionId,
    invocation_id: &str,
    event: bcode_session_models::ToolInvocationLifecycleEvent,
) {
    if event.invocation_id == invocation_id
        && matches!(
            event.stage,
            bcode_session_models::ToolInvocationLifecycleStage::Progress
                | bcode_session_models::ToolInvocationLifecycleStage::Waiting
        )
    {
        append_tool_invocation_lifecycle_event(state, session_id, event).await;
    }
}

const MAX_ACTIVE_CONTRIBUTION_BYTES: usize = 256 * 1024;
const MAX_ACTIVE_CONTRIBUTIONS_PER_SESSION: usize = 256;

fn update_active_contribution(
    state: &ServerState,
    session_id: SessionId,
    event: &ToolContributionEvent,
) -> Result<bool, String> {
    if event.invocation_id.trim().is_empty()
        || event.contribution_id.trim().is_empty()
        || event.producer_id.trim().is_empty()
        || event.schema.trim().is_empty()
        || event.schema_version == 0
        || event.sequence == 0
        || event.sequence == u64::MAX
    {
        return Err("active contribution identity, schema, and sequence must be valid".to_owned());
    }
    let encoded_bytes = serde_json::to_vec(event)
        .map_err(|error| format!("failed to encode active contribution: {error}"))?
        .len();
    if encoded_bytes > MAX_ACTIVE_CONTRIBUTION_BYTES {
        return Err(format!(
            "active contribution exceeds {MAX_ACTIVE_CONTRIBUTION_BYTES} bytes"
        ));
    }
    let key = ActiveContributionKey {
        session: session_id,
        invocation: event.invocation_id.clone(),
        contribution: event.contribution_id.clone(),
    };
    let mut contributions = state
        .active_contributions
        .lock()
        .map_err(|_| "active contribution registry poisoned".to_owned())?;
    if let Some(current) = contributions.get(&key) {
        if event.sequence <= current.sequence {
            return Ok(false);
        }
        if event.producer_id != current.producer_id
            || event.schema != current.schema
            || event.schema_version != current.schema_version
            || event.persistence != current.persistence
        {
            return Err("active contribution immutable identity changed".to_owned());
        }
    }
    if event.operation == bcode_session_models::ToolContributionOperation::Remove {
        contributions.remove(&key);
        return Ok(true);
    }
    let session_count = contributions
        .keys()
        .filter(|existing| existing.session == session_id)
        .count();
    if !contributions.contains_key(&key) && session_count >= MAX_ACTIVE_CONTRIBUTIONS_PER_SESSION {
        return Err(format!(
            "session has reached {MAX_ACTIVE_CONTRIBUTIONS_PER_SESSION} active contributions"
        ));
    }
    contributions.insert(key, event.clone());
    drop(contributions);
    Ok(true)
}

fn active_contribution_snapshot_events(
    state: &ServerState,
    session_id: SessionId,
) -> Result<Vec<bcode_session_models::SessionLiveEvent>, String> {
    let contributions = state
        .active_contributions
        .lock()
        .map_err(|_| "active contribution registry poisoned".to_owned())?;
    Ok(contributions
        .iter()
        .filter(|(key, _)| key.session == session_id)
        .map(|(_, event)| bcode_session_models::SessionLiveEvent {
            session_id,
            kind: SessionLiveEventKind::ToolContribution {
                event: event.clone(),
            },
        })
        .collect())
}

async fn clear_active_contributions(
    state: &ServerState,
    session_id: SessionId,
    invocation_id: &str,
) {
    let removed = state.active_contributions.lock().map_or_else(
        |_| Vec::new(),
        |mut contributions| {
            let mut removed = Vec::new();
            contributions.retain(|key, event| {
                let keep = key.session != session_id || key.invocation != invocation_id;
                if !keep {
                    removed.push(event.clone());
                }
                keep
            });
            removed
        },
    );
    for mut event in removed {
        event.sequence = event.sequence.saturating_add(1);
        event.operation = bcode_session_models::ToolContributionOperation::Remove;
        event.payload = serde_json::Value::Null;
        state
            .sessions
            .publish_live_event(session_id, SessionLiveEventKind::ToolContribution { event })
            .await;
    }
}

fn contribution_artifact_stream_event(
    event: &ToolContributionEvent,
) -> Option<ToolInvocationStreamEvent> {
    let artifact = event.artifact.as_ref()?;
    Some(ToolInvocationStreamEvent::ArtifactUpdate {
        tool_call_id: event.invocation_id.clone(),
        sequence: event.sequence,
        artifact_id: artifact.artifact_id.clone(),
        reference_key: artifact.reference_key.clone(),
        producer_plugin_id: event.producer_id.clone(),
        schema: event.schema.clone(),
        schema_version: event.schema_version,
        content_type: artifact.content_type.clone(),
        storage_uri: artifact.storage_uri.clone(),
        committed_bytes: artifact.committed_bytes,
        revision: artifact.revision,
        availability: None,
        finalized: artifact.finalized,
    })
}

async fn append_tool_contribution_envelope(
    state: &ServerState,
    session_id: SessionId,
    invocation_id: &str,
    producer_id: &str,
    envelope: bcode_session_models::ToolContributionEnvelope,
) {
    if envelope.schema_version != bcode_session_models::ToolContributionEnvelope::SCHEMA_VERSION {
        tracing::warn!(
            schema_version = envelope.schema_version,
            "discarded unsupported tool contribution envelope"
        );
        return;
    }
    let event = &envelope.contribution;
    if event.invocation_id != invocation_id || event.producer_id != producer_id {
        tracing::warn!(
            expected_invocation_id = invocation_id,
            actual_invocation_id = event.invocation_id,
            expected_producer_id = producer_id,
            actual_producer_id = event.producer_id,
            "discarded placed tool contribution with mismatched identity"
        );
        return;
    }
    if event.persistence == bcode_session_models::ToolContributionPersistence::Transient {
        if let Some(artifact_event) = contribution_artifact_stream_event(event)
            && let Err(error) =
                update_active_artifact(state, session_id, &artifact_event, Some(envelope.clone()))
        {
            tracing::warn!(%error, "discarded placed contribution with invalid artifact revision");
            return;
        }
        let _ = state
            .sessions
            .publish_live_event(
                session_id,
                SessionLiveEventKind::ToolContributionPlaced { envelope },
            )
            .await;
        return;
    }
    match state
        .sessions
        .append_event(
            session_id,
            SessionEventKind::ToolContributionPlaced { envelope },
        )
        .await
    {
        Ok(event) => publish_session_event(state, &event).await,
        Err(error) => tracing::warn!(%error, "failed to append placed tool contribution event"),
    }
}

async fn append_tool_contribution_event(
    state: &ServerState,
    session_id: SessionId,
    invocation_id: &str,
    producer_id: &str,
    event: bcode_session_models::ToolContributionEvent,
) {
    if event.invocation_id != invocation_id || event.producer_id != producer_id {
        tracing::warn!(
            expected_invocation_id = invocation_id,
            actual_invocation_id = event.invocation_id,
            expected_producer_id = producer_id,
            actual_producer_id = event.producer_id,
            "discarded tool contribution with mismatched invocation or producer identity"
        );
        return;
    }
    if event.persistence == bcode_session_models::ToolContributionPersistence::Transient {
        if let Some(artifact_event) = contribution_artifact_stream_event(&event)
            && let Err(error) = update_active_artifact(
                state,
                session_id,
                &artifact_event,
                Some(bcode_session_models::ToolContributionEnvelope::new(
                    bcode_session_models::ToolContributionPlacement::Hidden,
                    event.clone(),
                )),
            )
        {
            tracing::warn!(%error, "discarded tool contribution with invalid artifact revision");
            return;
        }
        match update_active_contribution(state, session_id, &event) {
            Ok(true) => {
                state
                    .sessions
                    .publish_live_event(
                        session_id,
                        SessionLiveEventKind::ToolContribution { event },
                    )
                    .await;
            }
            Ok(false) => {}
            Err(error) => tracing::warn!(%error, "discarded invalid active tool contribution"),
        }
        return;
    }
    match state
        .sessions
        .append_event(session_id, SessionEventKind::ToolContribution { event })
        .await
    {
        Ok(event) => publish_session_event(state, &event).await,
        Err(error) => tracing::warn!(%error, "failed to append tool contribution event"),
    }
}

async fn resolve_tool_exchange(
    state: &ServerState,
    session_id: SessionId,
    _call: &bcode_model::ToolCall,
    request: &ToolExchangeRequest,
    cancel_state: &TurnCancelState,
) -> Result<ToolExchangeResolution, String> {
    let pending = PendingToolExchange {
        summary: bcode_ipc::PendingToolExchangeSummary {
            session_id,
            request: request.clone(),
        },
        resolution: Arc::new(Mutex::new(None)),
        notify: Arc::new(Notify::new()),
    };
    let resolution_slot = pending.resolution.clone();
    let notify = pending.notify.clone();
    {
        let mut pending_interactions = state.pending_tool_exchanges.lock().await;
        if pending_interactions.contains_key(&request.exchange_id) {
            return Err(format!(
                "duplicate interactive tool request id: {}",
                request.exchange_id
            ));
        }
        pending_interactions.insert(request.exchange_id.clone(), pending);
    }
    if !state.has_exchange_consumer(request).await {
        let resolution = abort_tool_exchange(
            state,
            &request.exchange_id,
            ToolExchangeResolution::ConsumerDetached,
        )
        .await;
        return Ok(resolution);
    }

    Ok(wait_for_tool_exchange_resolution(
        state,
        &request.exchange_id,
        &resolution_slot,
        &notify,
        cancel_state,
    )
    .await)
}

#[allow(clippy::too_many_lines)] // Validates and commits one complete active-artifact state transition.
fn update_active_artifact(
    state: &ServerState,
    session_id: SessionId,
    event: &ToolInvocationStreamEvent,
    contribution_snapshot: Option<bcode_session_models::ToolContributionEnvelope>,
) -> Result<(), String> {
    let ToolInvocationStreamEvent::ArtifactUpdate {
        tool_call_id,
        artifact_id,
        reference_key,
        producer_plugin_id,
        schema,
        schema_version,
        content_type,
        storage_uri,
        committed_bytes,
        revision,
        finalized,
        ..
    } = event
    else {
        return Ok(());
    };
    if artifact_id.trim().is_empty()
        || reference_key.trim().is_empty()
        || producer_plugin_id.trim().is_empty()
        || schema.trim().is_empty()
        || *schema_version == 0
        || *revision == 0
    {
        return Err("active artifact identity, schema, and revision must be valid".to_owned());
    }
    let owner = state
        .active_plugin_invocations
        .lock()
        .map_err(|_| "active plugin invocation registry poisoned".to_owned())?
        .get(&(session_id, tool_call_id.clone()))
        .cloned()
        .ok_or_else(|| "active artifact invocation is not registered".to_owned())?;
    if owner.producer_plugin_id != *producer_plugin_id {
        return Err("active artifact producer does not own the invocation".to_owned());
    }
    let artifact_root = default_session_artifact_dir(session_id);
    let path = artifact_reference_path(storage_uri, &artifact_root)?;
    let canonical_root = artifact_root
        .canonicalize()
        .map_err(|error| format!("artifact root is unavailable: {error}"))?;
    let canonical_path = path
        .canonicalize()
        .map_err(|error| format!("active artifact is unavailable: {error}"))?;
    if !canonical_path.starts_with(&canonical_root) {
        return Err("active artifact path is outside the session artifact root".to_owned());
    }
    let file_bytes = std::fs::metadata(&canonical_path)
        .map_err(|error| error.to_string())?
        .len();
    if *committed_bytes > file_bytes {
        return Err(format!(
            "active artifact committed length {committed_bytes} exceeds file length {file_bytes}"
        ));
    }
    let key = ActiveArtifactKey {
        session_id,
        tool_call_id: tool_call_id.clone(),
        artifact_id: artifact_id.clone(),
        reference_key: reference_key.clone(),
    };
    let mut artifacts = state
        .active_artifacts
        .lock()
        .map_err(|_| "active artifact registry poisoned".to_owned())?;
    if let Some(existing) = artifacts.get(&key) {
        if existing.abandoned {
            return Err("active artifact producer is no longer available".to_owned());
        }
        let path_changed_on_finalization = *finalized
            && existing.path != canonical_path
            && existing.path.parent() == canonical_path.parent();
        if existing.producer_plugin_id != *producer_plugin_id
            || existing.schema != *schema
            || existing.schema_version != *schema_version
            || existing.content_type != *content_type
            || (existing.path != canonical_path && !path_changed_on_finalization)
        {
            return Err("active artifact immutable identity changed".to_owned());
        }
        if *revision <= existing.revision || *committed_bytes < existing.committed_bytes {
            return Err("active artifact revision and committed length must increase".to_owned());
        }
        if existing.finalized {
            return Err("active artifact is already finalized".to_owned());
        }
    }
    artifacts.insert(
        key,
        ActiveArtifactReference {
            producer_plugin_id: producer_plugin_id.clone(),
            schema: schema.clone(),
            schema_version: *schema_version,
            content_type: content_type.clone(),
            path: canonical_path,
            committed_bytes: *committed_bytes,
            revision: *revision,
            finalized: *finalized,
            abandoned: false,
            contribution_snapshot,
        },
    );
    drop(artifacts);
    Ok(())
}

fn active_artifact_snapshot_events(
    state: &ServerState,
    session_id: SessionId,
) -> Result<Vec<bcode_session_models::SessionLiveEvent>, String> {
    let artifacts = state
        .active_artifacts
        .lock()
        .map_err(|_| "active artifact registry poisoned".to_owned())?;
    let mut events = artifacts
        .iter()
        .filter(|(key, _)| key.session_id == session_id)
        .map(|(key, artifact)| {
            artifact.contribution_snapshot.as_ref().map_or_else(
                || bcode_session_models::SessionLiveEvent {
                    session_id,
                    kind: SessionLiveEventKind::ToolOutputDelta {
                        event: artifact.stream_event(key),
                    },
                },
                |envelope| bcode_session_models::SessionLiveEvent {
                    session_id,
                    kind: SessionLiveEventKind::ToolContributionPlaced {
                        envelope: envelope.clone(),
                    },
                },
            )
        })
        .collect::<Vec<_>>();
    drop(artifacts);
    let visuals = state
        .active_plugin_visuals
        .lock()
        .map_err(|_| "active plugin visual registry poisoned".to_owned())?;
    events.extend(
        visuals
            .iter()
            .filter(|((visual_session_id, _), _)| *visual_session_id == session_id)
            .map(|(_, event)| bcode_session_models::SessionLiveEvent {
                session_id,
                kind: SessionLiveEventKind::ToolOutputDelta {
                    event: event.clone(),
                },
            }),
    );
    drop(visuals);
    Ok(events)
}

fn update_active_plugin_visual(
    state: &ServerState,
    session_id: SessionId,
    tool_call_id: &str,
    event: &ToolInvocationStreamEvent,
) -> Result<(), String> {
    state
        .active_plugin_visuals
        .lock()
        .map_err(|_| "active plugin visual registry poisoned".to_owned())?
        .insert((session_id, tool_call_id.to_owned()), event.clone());
    Ok(())
}

fn remove_active_plugin_visual(state: &ServerState, session_id: SessionId, tool_call_id: &str) {
    if let Ok(mut visuals) = state.active_plugin_visuals.lock() {
        visuals.remove(&(session_id, tool_call_id.to_owned()));
    }
}

/// Publish ephemeral tool output and visuals, or append bounded lifecycle events.
///
/// `OutputDelta` carries raw live tool output, including PTY bytes. `VisualUpdate` carries
/// replaceable plugin presentation state. Both are transient and broadcast only to attached
/// clients; the latest active visual is retained in memory for reattach. Durable history stores
/// the request, bounded lifecycle metadata, final status, and bounded final result.
async fn append_tool_stream_event(
    state: &ServerState,
    session_id: SessionId,
    event: ToolInvocationStreamEvent,
) {
    if active_turn_cancel_state(state, session_id)
        .await
        .is_some_and(|cancel_state| cancel_state.is_cancelled())
    {
        return;
    }
    let progress = runtime_work_progress_from_tool_stream_event(&event);
    if let ToolInvocationStreamEvent::VisualUpdate { tool_call_id, .. } = &event {
        if let Err(error) = update_active_plugin_visual(state, session_id, tool_call_id, &event) {
            tracing::warn!("failed to update active plugin visual registry: {error}");
            return;
        }
        let _ = state
            .sessions
            .publish_live_event(session_id, SessionLiveEventKind::ToolOutputDelta { event })
            .await;
        return;
    }
    if let ToolInvocationStreamEvent::Finished { tool_call_id, .. } = &event {
        remove_active_plugin_visual(state, session_id, tool_call_id);
        return;
    }
    if matches!(event, ToolInvocationStreamEvent::Started { .. }) {
        return;
    }
    if matches!(event, ToolInvocationStreamEvent::ArtifactUpdate { .. }) {
        if let Err(error) = update_active_artifact(state, session_id, &event, None) {
            tracing::warn!("failed to update active artifact: {error}");
            return;
        }
        let _ = state
            .sessions
            .publish_live_event(session_id, SessionLiveEventKind::ToolOutputDelta { event })
            .await;
        return;
    }
    if matches!(event, ToolInvocationStreamEvent::OutputDelta { .. }) {
        let _ = state
            .sessions
            .publish_live_event(session_id, SessionLiveEventKind::ToolOutputDelta { event })
            .await;
        return;
    }
    if is_legacy_tool_presentation_stream_event(&event) {
        return;
    }
    if let Some((work_id, message)) = progress {
        append_runtime_work_progress_event(state, session_id, work_id, message, None, None).await;
    }
}

const fn is_legacy_tool_presentation_stream_event(event: &ToolInvocationStreamEvent) -> bool {
    matches!(event, ToolInvocationStreamEvent::LegacyPresentation { .. })
}

fn runtime_work_progress_from_tool_stream_event(
    event: &ToolInvocationStreamEvent,
) -> Option<(WorkId, String)> {
    match event {
        ToolInvocationStreamEvent::Status {
            tool_call_id,
            message,
            ..
        } => Some((WorkId::new(format!("tool_{tool_call_id}")), message.clone())),
        ToolInvocationStreamEvent::Started {
            tool_call_id,
            tool_name,
            ..
        } => Some((
            WorkId::new(format!("tool_{tool_call_id}")),
            format!("started {tool_name}"),
        )),
        ToolInvocationStreamEvent::Finished {
            tool_call_id,
            is_error,
            ..
        } => Some((
            WorkId::new(format!("tool_{tool_call_id}")),
            if *is_error {
                "finished with error"
            } else {
                "finished"
            }
            .to_string(),
        )),
        ToolInvocationStreamEvent::OutputDelta { .. }
        | ToolInvocationStreamEvent::VisualUpdate { .. }
        | ToolInvocationStreamEvent::ArtifactUpdate { .. }
        | ToolInvocationStreamEvent::LegacyPresentation { .. }
        | ToolInvocationStreamEvent::LegacyTransientPruned { .. } => None,
    }
}

fn normalize_tool_stream_event_sequence(
    event: ServiceToolInvocationStreamEvent,
    stream_sequences: &mut BTreeMap<String, u64>,
) -> ToolInvocationStreamEvent {
    let event = convert_tool_stream_event(event);
    let tool_call_id = match &event {
        ToolInvocationStreamEvent::Started { tool_call_id, .. }
        | ToolInvocationStreamEvent::OutputDelta { tool_call_id, .. }
        | ToolInvocationStreamEvent::VisualUpdate { tool_call_id, .. }
        | ToolInvocationStreamEvent::ArtifactUpdate { tool_call_id, .. }
        | ToolInvocationStreamEvent::Status { tool_call_id, .. }
        | ToolInvocationStreamEvent::LegacyPresentation { tool_call_id, .. }
        | ToolInvocationStreamEvent::LegacyTransientPruned { tool_call_id, .. }
        | ToolInvocationStreamEvent::Finished { tool_call_id, .. } => tool_call_id.clone(),
    };
    let next = stream_sequences
        .entry(tool_call_id)
        .and_modify(|sequence| *sequence = sequence.saturating_add(1))
        .or_insert(1);
    let sequence = *next;
    set_tool_stream_event_sequence(event, sequence)
}

#[allow(clippy::too_many_lines)] // Exhaustively rewrites every generic stream variant's sequence.
fn set_tool_stream_event_sequence(
    event: ToolInvocationStreamEvent,
    sequence: u64,
) -> ToolInvocationStreamEvent {
    match event {
        ToolInvocationStreamEvent::Started {
            tool_call_id,
            tool_name,
            terminal,
            columns,
            rows,
            started_at_ms,
            ..
        } => ToolInvocationStreamEvent::Started {
            tool_call_id,
            tool_name,
            sequence,
            terminal,
            columns,
            rows,
            started_at_ms,
        },
        ToolInvocationStreamEvent::OutputDelta {
            tool_call_id,
            stream,
            text,
            byte_len,
            ..
        } => ToolInvocationStreamEvent::OutputDelta {
            tool_call_id,
            stream,
            sequence,
            text,
            byte_len,
        },
        ToolInvocationStreamEvent::VisualUpdate {
            tool_call_id,
            visual,
            streaming,
            ..
        } => ToolInvocationStreamEvent::VisualUpdate {
            tool_call_id,
            sequence,
            visual,
            streaming,
        },
        ToolInvocationStreamEvent::ArtifactUpdate {
            tool_call_id,
            artifact_id,
            reference_key,
            producer_plugin_id,
            schema,
            schema_version,
            content_type,
            storage_uri,
            committed_bytes,
            revision,
            availability,
            finalized,
            ..
        } => ToolInvocationStreamEvent::ArtifactUpdate {
            tool_call_id,
            sequence,
            artifact_id,
            reference_key,
            producer_plugin_id,
            schema,
            schema_version,
            content_type,
            storage_uri,
            committed_bytes,
            revision,
            availability,
            finalized,
        },
        ToolInvocationStreamEvent::Status {
            tool_call_id,
            message,
            ..
        } => ToolInvocationStreamEvent::Status {
            tool_call_id,
            sequence,
            message,
        },
        ToolInvocationStreamEvent::LegacyPresentation {
            tool_call_id,
            presentation,
            ..
        } => ToolInvocationStreamEvent::LegacyPresentation {
            tool_call_id,
            sequence,
            presentation,
        },
        event @ ToolInvocationStreamEvent::LegacyTransientPruned { .. } => event,
        ToolInvocationStreamEvent::Finished {
            tool_call_id,
            is_error,
            finished_at_ms,
            ..
        } => ToolInvocationStreamEvent::Finished {
            tool_call_id,
            sequence,
            is_error,
            finished_at_ms,
        },
    }
}

fn convert_tool_stream_event(event: ServiceToolInvocationStreamEvent) -> ToolInvocationStreamEvent {
    match event {
        ServiceToolInvocationStreamEvent::Started {
            tool_call_id,
            tool_name,
            sequence,
            terminal,
            columns,
            rows,
            started_at_ms,
        } => ToolInvocationStreamEvent::Started {
            tool_call_id,
            tool_name,
            sequence,
            terminal,
            columns,
            rows,
            started_at_ms: started_at_ms.or_else(|| Some(current_unix_millis())),
        },
        ServiceToolInvocationStreamEvent::OutputDelta {
            tool_call_id,
            stream,
            sequence,
            text,
            byte_len,
        } => ToolInvocationStreamEvent::OutputDelta {
            tool_call_id,
            stream: convert_tool_output_stream(stream),
            sequence,
            text,
            byte_len,
        },
        ServiceToolInvocationStreamEvent::VisualUpdate {
            tool_call_id,
            sequence,
            visual,
            streaming,
        } => ToolInvocationStreamEvent::VisualUpdate {
            tool_call_id,
            sequence,
            visual: bcode_session_models::PluginVisualDescriptor {
                visual_id: visual.visual_id,
                producer_plugin_id: visual.producer_plugin_id,
                schema: visual.schema,
                schema_version: visual.schema_version,
                title: visual.title,
                subtitle: visual.subtitle,
                payload: visual.payload,
            },
            streaming,
        },
        ServiceToolInvocationStreamEvent::ArtifactUpdate {
            tool_call_id,
            sequence,
            artifact_id,
            reference_key,
            producer_plugin_id,
            schema,
            schema_version,
            content_type,
            storage_uri,
            committed_bytes,
            revision,
            finalized,
        } => ToolInvocationStreamEvent::ArtifactUpdate {
            tool_call_id,
            sequence,
            artifact_id,
            reference_key,
            producer_plugin_id,
            schema,
            schema_version,
            content_type,
            storage_uri,
            committed_bytes,
            revision,
            availability: None,
            finalized,
        },
        ServiceToolInvocationStreamEvent::Status {
            tool_call_id,
            sequence,
            message,
        } => ToolInvocationStreamEvent::Status {
            tool_call_id,
            sequence,
            message,
        },
        ServiceToolInvocationStreamEvent::Finished {
            tool_call_id,
            sequence,
            is_error,
            finished_at_ms,
        } => ToolInvocationStreamEvent::Finished {
            tool_call_id,
            sequence,
            is_error,
            finished_at_ms: finished_at_ms.or_else(|| Some(current_unix_millis())),
        },
    }
}

const fn convert_tool_output_stream(stream: ToolOutputStream) -> SessionToolOutputStream {
    match stream {
        ToolOutputStream::Stdout => SessionToolOutputStream::Stdout,
        ToolOutputStream::Stderr => SessionToolOutputStream::Stderr,
        ToolOutputStream::Pty => SessionToolOutputStream::Pty,
    }
}

async fn evaluate_agent_tool_policy_with_metadata(
    state: &ServerState,
    session_id: SessionId,
    agent_id: &str,
    call: &bcode_model::ToolCall,
    metadata: &ToolPolicyAuthorizationMetadata,
) -> EvaluateToolCallResponse {
    let cwd = state
        .sessions
        .session_working_directory(session_id)
        .await
        .ok()
        .map(|path| path.display().to_string());
    let aliases = std::iter::once(call.name.clone())
        .chain(metadata.permission_category.iter().cloned())
        .chain(metadata.aliases.iter().cloned())
        .collect();
    let request = EvaluateToolCallRequest {
        session_id,
        agent_id: agent_id.to_string(),
        tool_name: call.name.clone(),
        operation: metadata.operation.clone(),
        aliases,
        requires_permission: metadata.requires_permission,
        cwd,
    };
    state
        .plugins
        .invoke_service_by_interface_json::<_, EvaluateToolCallResponse>(
            AGENT_PROFILE_INTERFACE_ID,
            OP_EVALUATE_TOOL_CALL,
            &request,
        )
        .await
        .ok()
        .unwrap_or(EvaluateToolCallResponse {
            decision: if metadata.requires_permission {
                AgentDecision::Ask
            } else {
                AgentDecision::Allow
            },
            reason: None,
        })
}

fn remembered_skill_tool_decision(key: &SkillToolDecisionKey) -> Option<SkillToolDecision> {
    SettingsStore::default()
        .skill_tool_decisions()
        .ok()
        .and_then(|state| state.decision_for(key).map(|entry| entry.decision))
}

fn remember_skill_tool_decision(key: SkillToolDecisionKey, decision: SkillToolDecision) {
    let store = SettingsStore::default();
    let Ok(mut state) = store.skill_tool_decisions() else {
        return;
    };
    state.upsert(SkillToolDecisionEntry {
        key,
        decision,
        remembered_at_ms: current_time_ms(),
        reason: Some("remembered from permission dialog".to_string()),
    });
    let _ = store.save_skill_tool_decisions(&state, current_time_ms());
}

async fn skill_tool_decision_key(
    state: &ServerState,
    session_id: SessionId,
    tool_name: &str,
) -> Option<SkillToolDecisionKey> {
    let skill_ids = state
        .active_skills
        .lock()
        .await
        .get(&session_id)
        .cloned()
        .unwrap_or_default();
    if skill_ids.is_empty() {
        return None;
    }
    let working_directory = state
        .sessions
        .session_working_directory(session_id)
        .await
        .ok()?;
    Some(skill_tool_decision_key_for_working_directory(
        skill_ids,
        tool_name,
        &working_directory,
    ))
}

fn skill_tool_decision_key_for_working_directory(
    skill_ids: BTreeSet<SkillId>,
    tool_name: &str,
    working_directory: &Path,
) -> SkillToolDecisionKey {
    SkillToolDecisionKey {
        skill_ids,
        tool_name: tool_name.to_string(),
        scope: SkillToolDecisionScope::Workspace {
            workspace_id: workspace_identity(working_directory),
        },
    }
}

fn workspace_identity(working_directory: &Path) -> String {
    git_root_for_path(working_directory)
        .or_else(|| working_directory.canonicalize().ok())
        .unwrap_or_else(|| working_directory.to_path_buf())
        .to_string_lossy()
        .into_owned()
}

fn git_root_for_path(path: &Path) -> Option<PathBuf> {
    let output = Command::new("git")
        .arg("-C")
        .arg(path)
        .arg("rev-parse")
        .arg("--show-toplevel")
        .output()
        .ok()?;
    if !output.status.success() {
        return None;
    }
    let stdout = String::from_utf8(output.stdout).ok()?;
    let root = stdout.trim();
    if root.is_empty() {
        None
    } else {
        Some(PathBuf::from(root))
    }
}

async fn list_service_tools(state: &ServerState) -> Vec<ServiceToolDefinition> {
    let mut tools = Vec::new();
    for plugin_id in tool_provider_plugin_ids(state) {
        match state
            .plugins
            .invoke_service_json::<_, ToolList>(
                &plugin_id,
                TOOL_SERVICE_INTERFACE_ID,
                OP_LIST_TOOLS,
                &ListToolsRequest::default(),
            )
            .await
        {
            Ok(list) => tools.extend(list.tools),
            Err(error) => tracing::warn!("failed to list tools from {plugin_id}: {error}"),
        }
    }
    tools
}

async fn evaluate_active_skill_tool_policy_with_metadata(
    state: &ServerState,
    session_id: SessionId,
    tool_name: &str,
    metadata: &ToolPolicyAuthorizationMetadata,
) -> SkillToolPolicyOutcome {
    let Some(registry) = &state.skills else {
        return SkillToolPolicyOutcome::NoOpinion;
    };
    let skill_ids = state
        .active_skills
        .lock()
        .await
        .get(&session_id)
        .cloned()
        .unwrap_or_default();
    if skill_ids.is_empty() {
        return SkillToolPolicyOutcome::NoOpinion;
    }
    let available_tools = list_service_tools(state).await;
    let active_policies = skill_ids
        .into_iter()
        .filter_map(|skill_id| registry.describe(&skill_id).ok())
        .map(|manifest| {
            resolve_skill_permission_policy(&manifest.permission_policy, &available_tools)
        })
        .collect();
    let target = SkillToolPolicyTarget {
        name: tool_name.to_string(),
        aliases: metadata.aliases.clone(),
        compatibility_aliases: metadata.compatibility_aliases.clone(),
        capabilities: metadata.capabilities.clone(),
        permission_category: metadata.permission_category.clone(),
    };
    evaluate_skill_tool_call(&SkillToolPolicyRequest {
        tool: target,
        active_policies,
    })
}

const fn skill_tool_policy_decision_name(outcome: &SkillToolPolicyOutcome) -> &'static str {
    match outcome {
        SkillToolPolicyOutcome::NoOpinion => "skill_no_opinion",
        SkillToolPolicyOutcome::Allow { .. } => "skill_allow",
        SkillToolPolicyOutcome::Warn { .. } => "skill_warn",
        SkillToolPolicyOutcome::Ask { .. } => "skill_ask",
        SkillToolPolicyOutcome::Deny { .. } => "skill_deny",
    }
}

fn skill_tool_policy_reason(outcome: &SkillToolPolicyOutcome) -> Option<String> {
    match outcome {
        SkillToolPolicyOutcome::NoOpinion => None,
        SkillToolPolicyOutcome::Allow { reason }
        | SkillToolPolicyOutcome::Warn { reason }
        | SkillToolPolicyOutcome::Ask { reason }
        | SkillToolPolicyOutcome::Deny { reason } => Some(reason.clone()),
    }
}

fn tool_provider_plugin_ids(state: &ServerState) -> Vec<String> {
    state
        .plugins
        .registry()
        .manifests()
        .values()
        .filter(|manifest| {
            manifest
                .services
                .iter()
                .any(|service| service.interface_id == TOOL_SERVICE_INTERFACE_ID)
        })
        .map(|manifest| manifest.id.clone())
        .collect()
}

#[derive(Debug, Clone, Default)]
struct PermissionPolicyContext {
    source: Option<String>,
    reason: Option<String>,
    skill_decision_key: Option<SkillToolDecisionKey>,
    batch: Option<PermissionBatchCorrelation>,
}

async fn register_pending_permission(
    state: &ServerState,
    pending: &PendingPermission,
    event: SessionEventKind,
) -> Result<(), bool> {
    let batch_state = pending.summary.batch.as_ref().and_then(|batch| {
        state
            .pending_permission_batches
            .lock()
            .unwrap_or_else(std::sync::PoisonError::into_inner)
            .get(&batch.batch_id)
            .cloned()
    });
    if pending.summary.batch.is_some() && batch_state.is_none() {
        return Err(false);
    }
    let batch_decision = if let Some(batch_state) = batch_state.as_ref() {
        let decision = batch_state.decision.lock().await;
        if let Some(decision) = *decision {
            return Err(decision);
        }
        Some(decision)
    } else {
        None
    };
    state
        .pending_permissions
        .lock()
        .await
        .insert(pending.summary.permission_id.clone(), pending.clone());
    append_permission_requested_event(state, pending.summary.session_id, event).await;
    drop(batch_decision);
    Ok(())
}

#[allow(clippy::too_many_lines)]
async fn request_tool_permission(
    state: &ServerState,
    session_id: SessionId,
    call: &bcode_model::ToolCall,
    tool_name: &str,
    producer_plugin_id: &str,
    cancel_state: &TurnCancelState,
    policy_context: PermissionPolicyContext,
) -> bool {
    if cancel_state.is_cancelled() {
        return false;
    }
    let permission_id = next_permission_id(state).await;
    let arguments_json = serde_json::to_string(&call.arguments).unwrap_or_default();
    let agent_id = session_agent_selection(state, session_id).await;
    let pending = PendingPermission {
        summary: PermissionSummary {
            permission_id: permission_id.clone(),
            session_id,
            tool_call_id: call.id.clone(),
            tool_name: tool_name.to_string(),
            arguments_json: arguments_json.clone(),
            batch: policy_context.batch.clone(),
            agent_id,
            policy_source: policy_context.source.clone(),
            policy_reason: policy_context.reason.clone(),
            can_remember_policy: policy_context.skill_decision_key.is_some(),
        },
        decision: Arc::new(Mutex::new(None)),
        notify: Arc::new(Notify::new()),
        skill_decision_key: policy_context.skill_decision_key,
    };
    let event = SessionEventKind::PermissionRequested {
        permission_id: permission_id.clone(),
        tool_call_id: call.id.clone(),
        producer_plugin_id: Some(producer_plugin_id.to_owned()),
        tool_name: tool_name.to_string(),
        arguments_json,
        legacy_request_presentation: None,
        batch: policy_context.batch.clone(),
        policy_source: policy_context.source,
        policy_reason: policy_context.reason,
    };
    if let Err(decision) = register_pending_permission(state, &pending, event).await {
        return decision;
    }
    state.metrics.add_counter_with_labels(
        "tool.permission.request_total",
        1,
        tool_permission_metric_labels(tool_name, "requested"),
    );
    append_trace_event(
        state,
        session_id,
        None,
        SessionTracePhase::ToolPermissionWaitStarted,
        SessionTracePayload::ToolPermissionWait {
            permission_id: permission_id.clone(),
            tool_call_id: call.id.clone(),
            approved: None,
            duration_ms: None,
        },
    )
    .await;
    let wait_start = Instant::now();
    loop {
        let decision = *pending.decision.lock().await;
        if let Some(decision) = decision {
            let duration_ms = elapsed_ms(wait_start);
            state.metrics.record_histogram_with_labels(
                "tool.permission.wait_duration_ms",
                duration_ms,
                tool_permission_metric_labels(
                    &pending.summary.tool_name,
                    if decision { "approved" } else { "denied" },
                ),
            );
            state.metrics.add_counter_with_labels(
                "tool.permission.decision_total",
                1,
                tool_permission_metric_labels(
                    &pending.summary.tool_name,
                    if decision { "approved" } else { "denied" },
                ),
            );
            append_trace_event(
                state,
                session_id,
                None,
                SessionTracePhase::ToolPermissionWaitFinished,
                SessionTracePayload::ToolPermissionWait {
                    permission_id: pending.summary.permission_id.clone(),
                    tool_call_id: pending.summary.tool_call_id.clone(),
                    approved: Some(decision),
                    duration_ms: Some(duration_ms),
                },
            )
            .await;
            return decision;
        }
        tokio::select! {
            () = pending.notify.notified() => {}
            () = cancel_state.cancelled() => {
                let removed = state
                    .pending_permissions
                    .lock()
                    .await
                    .remove(&pending.summary.permission_id);
                if removed.is_none() {
                    continue;
                }
                let duration_ms = elapsed_ms(wait_start);
                state.metrics.record_histogram_with_labels(
                    "tool.permission.wait_duration_ms",
                    duration_ms,
                    tool_permission_metric_labels(&pending.summary.tool_name, "cancelled"),
                );
                state.metrics.add_counter_with_labels(
                    "tool.permission.decision_total",
                    1,
                    tool_permission_metric_labels(&pending.summary.tool_name, "cancelled"),
                );
                append_trace_event(
                    state,
                    session_id,
                    None,
                    SessionTracePhase::ToolPermissionWaitFinished,
                    SessionTracePayload::ToolPermissionWait {
                        permission_id: pending.summary.permission_id.clone(),
                        tool_call_id: pending.summary.tool_call_id.clone(),
                        approved: Some(false),
                        duration_ms: Some(duration_ms),
                    },
                )
                .await;
                append_permission_resolved_event(
                    state,
                    session_id,
                    pending.summary.permission_id.clone(),
                    false,
                )
                .await;
                return false;
            }
        }
    }
}

fn tool_permission_metric_labels(tool_name: &str, outcome: &str) -> MetricLabels {
    let mut labels = MetricLabels::new();
    labels.insert("tool_name".to_owned(), tool_name.to_owned());
    labels.insert("outcome".to_owned(), outcome.to_owned());
    labels
}

