    #[test]
    fn request_estimate_accounts_for_every_serialized_request_component() {
        let baseline = request_for_accounting_tests();
        let baseline_tokens = local_request_estimate(&baseline).tokens;
        let assert_increases = |mutate: fn(&mut ModelTurnRequest)| {
            let mut request = baseline.clone();
            mutate(&mut request);
            assert!(local_request_estimate(&request).tokens > baseline_tokens);
        };

        assert_increases(|request| {
            request.system_prompt = Some("system instructions ".repeat(100));
        });
        assert_increases(|request| {
            request.messages.push(ModelMessage {
                role: MessageRole::Assistant,
                content: vec![ContentBlock::Text {
                    text: "assistant context ".repeat(100),
                }],
            });
        });
        assert_increases(|request| {
            request.tools.push(bcode_model::ToolDefinition {
                name: "large_tool".to_string(),
                description: "tool description ".repeat(100),
                input_schema: serde_json::json!({
                    "type": "object",
                    "properties": {"large": {"description": "schema ".repeat(100)}}
                }),
            });
        });
        assert_increases(|request| {
            request.provider_context.request.insert(
                "extension".to_string(),
                serde_json::json!({"payload": "extension ".repeat(100)}).into(),
            );
        });
        assert_increases(|request| {
            request.parameters.stop_sequences = vec!["stop sequence ".repeat(100)];
        });
    }

    #[test]
    fn opaque_provider_state_does_not_affect_request_estimate() {
        let baseline = request_for_accounting_tests();
        let baseline_tokens = local_request_estimate(&baseline).tokens;
        let mut with_state = baseline;
        with_state.conversation_reuse.provider_state =
            Some(serde_json::json!({"opaque": "encrypted ".repeat(1_000)}));

        assert_eq!(local_request_estimate(&with_state).tokens, baseline_tokens);
    }

    #[test]
    fn tool_schema_and_provider_extension_can_cross_a_fit_threshold() {
        let baseline = request_for_accounting_tests();
        let baseline_tokens = local_request_estimate(&baseline).tokens;

        let mut with_tool = baseline.clone();
        with_tool.tools.push(bcode_model::ToolDefinition {
            name: "large_tool".to_string(),
            description: "tool description ".repeat(500),
            input_schema: serde_json::json!({
                "type": "object",
                "properties": {"large": {"description": "schema ".repeat(500)}}
            }),
        });
        let tool_tokens = local_request_estimate(&with_tool).tokens;
        assert!(baseline_tokens < tool_tokens);
        let tool_threshold = baseline_tokens + (tool_tokens - baseline_tokens) / 2;
        assert!(baseline_tokens <= tool_threshold && tool_tokens > tool_threshold);

        let mut with_extension = baseline;
        with_extension.provider_context.request.insert(
            "extension".to_string(),
            serde_json::json!({"payload": "extension ".repeat(1_000)}).into(),
        );
        let extension_tokens = local_request_estimate(&with_extension).tokens;
        assert!(baseline_tokens < extension_tokens);
        let extension_threshold = baseline_tokens + (extension_tokens - baseline_tokens) / 2;
        assert!(baseline_tokens <= extension_threshold && extension_tokens > extension_threshold);
    }

    #[test]
    fn proactive_policy_uses_complete_candidate_estimate_at_capacity_threshold() {
        let capacity = compaction_capacity_tokens(10_000, 90, Some(1_000), Some(4_000));
        assert!(!candidate_requires_proactive_compaction(
            capacity.threshold_tokens.saturating_sub(1),
            capacity
        ));
        assert!(candidate_requires_proactive_compaction(
            capacity.threshold_tokens,
            capacity
        ));
        assert!(candidate_requires_proactive_compaction(
            capacity.threshold_tokens.saturating_add(1),
            capacity
        ));
    }

    #[test]
    fn output_reserve_can_make_an_otherwise_fitting_request_oversized() {
        let without_reserve = compaction_capacity_tokens(10_000, 100, Some(0), Some(8_000));
        let with_reserve = compaction_capacity_tokens(10_000, 100, Some(4_000), Some(8_000));

        assert!(7_000 <= without_reserve.available_input_tokens);
        assert!(7_000 > with_reserve.available_input_tokens);
    }

    #[test]
    fn automatic_compaction_policy_routes_modes_and_capabilities() {
        let valid_capabilities = bcode_model::ContextManagementCapabilities {
            provider_managed: true,
            native_compaction: true,
            context_format: Some(bcode_model::ProviderContextFormat {
                version: 1,
                compatibility_key: "responses-v1".to_string(),
            }),
        };
        let invalid_capabilities = bcode_model::ContextManagementCapabilities {
            provider_managed: true,
            native_compaction: true,
            context_format: Some(bcode_model::ProviderContextFormat {
                version: 1,
                compatibility_key: String::new(),
            }),
        };

        assert_eq!(
            resolve_compaction_decision(
                bcode_config::CompactionMode::Auto,
                Some(&valid_capabilities),
            )
            .strategy,
            AutomaticCompactionStrategy::ProviderManaged
        );
        assert_eq!(
            resolve_compaction_decision(bcode_config::CompactionMode::Auto, None).strategy,
            AutomaticCompactionStrategy::OverflowOnly
        );
        assert_eq!(
            resolve_compaction_decision(
                bcode_config::CompactionMode::Auto,
                Some(&invalid_capabilities),
            )
            .strategy,
            AutomaticCompactionStrategy::OverflowOnly
        );
        assert_eq!(
            resolve_compaction_decision(bcode_config::CompactionMode::Proactive, None).strategy,
            AutomaticCompactionStrategy::LocalProactive
        );
        assert_eq!(
            resolve_compaction_decision(bcode_config::CompactionMode::Off, None).strategy,
            AutomaticCompactionStrategy::Disabled
        );
    }

