    #[tokio::test]
    #[allow(clippy::too_many_lines)]
    async fn manual_compaction_queues_behind_unrelated_active_turn() {
        let temp_dir = tempfile::tempdir().expect("temp dir");
        let sessions = SessionManager::persistent(temp_dir.path()).expect("persistent sessions");
        let summary = sessions
            .create_session(Some("manual queue".to_owned()), test_working_directory())
            .await
            .expect("session should be created");
        let session_id = summary.id;
        sessions
            .append_model_changed(
                session_id,
                "bcode.fake-provider".to_string(),
                "fake-echo".to_string(),
            )
            .await
            .expect("select fake provider");
        for index in 0..3 {
            sessions
                .append_event(
                    session_id,
                    SessionEventKind::UserMessage {
                        client_id: ClientId::new(),
                        text: format!("history user {index}"),
                        admission: bcode_session_models::TurnAdmissionMetadata::default(),
                    },
                )
                .await
                .expect("append history user");
            sessions
                .append_event(
                    session_id,
                    SessionEventKind::AssistantMessage {
                        text: format!("history assistant {index}"),
                    },
                )
                .await
                .expect("append history assistant");
        }
        let trigger_event = sessions
            .append_event(
                session_id,
                SessionEventKind::UserMessage {
                    client_id: ClientId::new(),
                    text: "active delayed turn".to_string(),
                    admission: bcode_session_models::TurnAdmissionMetadata::default(),
                },
            )
            .await
            .expect("append trigger event");
        let mut state = test_server_state_with_fake_provider(sessions);
        state.auto_compaction.keep_recent_tokens = 1;
        state.auto_compaction.backend = bcode_config::CompactionBackend::Local;
        state
            .selected_provider_context
            .settings
            .insert("fake_turn_delay_ms".to_string(), "100".to_string());
        state.session_model_selections.lock().await.insert(
            session_id,
            SessionModelSelection {
                provider_plugin_id: Some("bcode.fake-provider".to_string()),
                requested_model_id: None,
                model_id: Some("fake-echo".to_string()),
                provider_context: state.selected_provider_context.clone(),
                ..SessionModelSelection::default()
            },
        );
        let state = Arc::new(state);
        let client_id = ClientId::new();
        let (turn_tx, turn_rx) = oneshot::channel();
        enqueue_followup_command(
            &state,
            session_id,
            FollowupCommand::ExecuteTurn {
                client_id,
                runtime_context: None,
                user_event: Box::new(trigger_event),
                queued_steering: None,
                completion: Some(turn_tx),
            },
        )
        .await
        .expect("enqueue model turn");
        let handle = session_runtime_handle(&state, session_id).await;
        loop {
            if handle.current_turn.lock().await.is_some() {
                break;
            }
            tokio::task::yield_now().await;
        }
        assert!(handle.phase.lock().await.has_active_work());

        let selection = state
            .session_model_selections
            .lock()
            .await
            .get(&session_id)
            .cloned()
            .expect("selection");
        let (compact_tx, compact_rx) = oneshot::channel();
        let status = enqueue_followup_command(
            &state,
            session_id,
            FollowupCommand::CompactSession {
                client_id,
                selection,
                response: compact_tx,
            },
        )
        .await
        .expect("queue manual compaction");
        assert!(status.queued);
        assert!(
            handle
                .current_turn
                .lock()
                .await
                .as_ref()
                .is_some_and(|turn| { turn.kind == RuntimeOperationKind::ModelTurn })
        );

        let turn = turn_rx.await.expect("turn completion");
        assert_eq!(turn.outcome, ModelTurnOutcome::Completed);
        compact_rx
            .await
            .expect("manual response")
            .unwrap_or_else(|error| panic!("manual compaction failed: {error}"));
        assert!(handle.current_turn.lock().await.is_none());
        let history = state
            .sessions
            .session_history(session_id)
            .await
            .expect("history should read");
        assert_eq!(
            history
                .iter()
                .filter(|event| matches!(event.kind, SessionEventKind::ContextCompacted { .. }))
                .count(),
            1
        );
    }

    #[tokio::test]
    async fn manual_compaction_registers_exclusive_runtime_work_and_clears_it() {
        let sessions = SessionManager::default();
        let summary = sessions
            .create_session(
                Some("manual compaction".to_owned()),
                test_working_directory(),
            )
            .await
            .expect("session should be created");
        let session_id = summary.id;
        for text in ["first turn", "second turn", "active turn"] {
            sessions
                .append_event(
                    session_id,
                    SessionEventKind::UserMessage {
                        client_id: ClientId::new(),
                        text: text.to_string(),
                        admission: bcode_session_models::TurnAdmissionMetadata::default(),
                    },
                )
                .await
                .expect("append user turn");
            sessions
                .append_event(
                    session_id,
                    SessionEventKind::AssistantMessage {
                        text: format!("response to {text}"),
                    },
                )
                .await
                .expect("append assistant turn");
        }
        let mut state = test_server_state_with_fake_provider(sessions);
        state.auto_compaction.keep_recent_tokens = 1;
        state.auto_compaction.backend = bcode_config::CompactionBackend::Local;
        let (_followup_tx, mut followup_rx) = mpsc::channel(1);
        let (_steering_tx, mut steering_rx) = mpsc::channel(1);
        let (_cancel_tx, mut cancel_rx) = mpsc::channel(1);
        let queued_followups = AtomicUsize::new(0);
        let current_turn = Arc::new(Mutex::new(None));
        let phase = Arc::new(Mutex::new(SessionRuntimePhase::Idle));

        process_compact_session_command(
            &state,
            session_id,
            Arc::clone(&phase),
            &mut followup_rx,
            &mut steering_rx,
            &mut cancel_rx,
            &queued_followups,
            Arc::clone(&current_turn),
            ClientId::new(),
            SessionModelSelection {
                provider_plugin_id: Some("bcode.fake-provider".to_string()),
                requested_model_id: None,
                model_id: Some("fake-model".to_string()),
                ..SessionModelSelection::default()
            },
        )
        .await
        .unwrap_or_else(|error| panic!("manual compaction failed: {error}"));

        assert!(current_turn.lock().await.is_none());
        assert_eq!(*phase.lock().await, SessionRuntimePhase::Idle);
        let history = state
            .sessions
            .session_history(session_id)
            .await
            .expect("history should read");
        assert_eq!(
            history
                .iter()
                .filter(|event| matches!(event.kind, SessionEventKind::ContextCompacted { .. }))
                .count(),
            1
        );
    }

    #[tokio::test]
    async fn persisted_active_turn_that_exceeds_capacity_is_explicitly_uncompactable() {
        let sessions = SessionManager::default();
        let summary = sessions
            .create_session(
                Some("uncompactable turn".to_owned()),
                test_working_directory(),
            )
            .await
            .expect("session should be created");
        let session_id = summary.id;
        sessions
            .append_event(
                session_id,
                SessionEventKind::UserMessage {
                    client_id: ClientId::new(),
                    text: "x".repeat(4_000),
                    admission: bcode_session_models::TurnAdmissionMetadata::default(),
                },
            )
            .await
            .expect("append active turn");
        let persisted_before = sessions
            .session_history(session_id)
            .await
            .expect("history should read");
        let history = sessions
            .model_context_events(session_id)
            .await
            .expect("model context");

        let error = ensure_compactable_current_turn(&history, 1_000, 10)
            .expect_err("active turn must not be split or discarded");
        assert!(matches!(
            error,
            CompactionError::UncompactableCurrentTurn {
                available_input_tokens: 10,
                ..
            }
        ));
        let persisted_after = sessions
            .session_history(session_id)
            .await
            .expect("history should read");
        assert_eq!(persisted_after, persisted_before);
        assert!(!persisted_after.iter().any(|event| matches!(
            event.kind,
            SessionEventKind::ContextCompacted { .. }
                | SessionEventKind::ProviderContextCompacted { .. }
        )));
    }

