    #[test]
    fn compaction_transcript_keeps_recent_tail_out_of_summary() {
        let session_id = SessionId::new();
        let mut history = Vec::new();
        for sequence in 0_u64..6 {
            let kind = if sequence.is_multiple_of(2) {
                SessionEventKind::UserMessage {
                    client_id: ClientId::new(),
                    text: "x".repeat(COMPACTION_DEFAULT_KEEP_RECENT_CHARS / 4),
                    admission: bcode_session_models::TurnAdmissionMetadata::default(),
                }
            } else {
                SessionEventKind::AssistantMessage {
                    text: "x".repeat(COMPACTION_DEFAULT_KEEP_RECENT_CHARS / 4),
                }
            };
            history.push(session_event(session_id, sequence, kind));
        }

        let transcript =
            compaction_transcript(&history, 1_000, 1_000).expect("compaction transcript");

        assert!(transcript.compacted_through_sequence < 5);
        assert!(transcript.event_count < history.len());
    }

    #[test]
    fn compaction_progress_requirement_rejects_negligible_reclaim() {
        let transcript = CompactionTranscript {
            previous_summary: None,
            summary_input: vec!["small prefix".to_string()],
            compacted_through_sequence: 1,
            event_count: 1,
            estimated_reclaimable_tokens: 100,
        };

        assert!(!compaction_plan_meets_progress_requirement(
            &transcript,
            CompactionProgressRequirement {
                minimum_reclaimable_tokens: 101,
                previous_compacted_through_sequence: None,
            }
        ));
        assert!(compaction_plan_meets_progress_requirement(
            &transcript,
            CompactionProgressRequirement {
                minimum_reclaimable_tokens: 100,
                previous_compacted_through_sequence: None,
            }
        ));
        assert!(!compaction_plan_meets_progress_requirement(
            &transcript,
            CompactionProgressRequirement {
                minimum_reclaimable_tokens: 100,
                previous_compacted_through_sequence: Some(1),
            }
        ));

        let materially_advanced = CompactionTranscript {
            compacted_through_sequence: 5,
            estimated_reclaimable_tokens: 4_000,
            ..transcript
        };
        assert!(compaction_plan_meets_progress_requirement(
            &materially_advanced,
            CompactionProgressRequirement {
                minimum_reclaimable_tokens: 2_000,
                previous_compacted_through_sequence: Some(1),
            }
        ));
        assert!(!compaction_plan_meets_progress_requirement(
            &materially_advanced,
            CompactionProgressRequirement {
                minimum_reclaimable_tokens: 4_001,
                previous_compacted_through_sequence: Some(1),
            }
        ));
    }

