    #[tokio::test]
    async fn batch_permission_resolution_is_latched_and_batch_scoped() {
        let state = test_server_state(SessionManager::default());
        let session_id = SessionId::new();
        let first_batch = Arc::new(PendingPermissionBatch::new(session_id));
        let second_batch = Arc::new(PendingPermissionBatch::new(session_id));
        state
            .pending_permission_batches
            .lock()
            .unwrap_or_else(std::sync::PoisonError::into_inner)
            .extend([
                ("batch-1".to_string(), first_batch),
                ("batch-2".to_string(), second_batch),
            ]);
        let first = pending_permission_for_batch("perm-1", session_id, 0, "batch-1");
        let second = pending_permission_for_batch("perm-2", session_id, 1, "batch-1");
        let unrelated = pending_permission_for_batch("perm-3", session_id, 0, "batch-2");
        state.pending_permissions.lock().await.extend([
            ("perm-1".to_string(), first.clone()),
            ("perm-2".to_string(), second.clone()),
            ("perm-3".to_string(), unrelated.clone()),
        ]);

        let individual = take_pending_permission_for_individual(&state, "perm-1")
            .await
            .expect("per-call decision should win before batch latch");
        resolve_pending_permission(&state, individual, false, false).await;
        assert_eq!(resolve_permission_batch(&state, "batch-1", true).await, 1);
        assert_eq!(*first.decision.lock().await, Some(false));
        assert_eq!(*second.decision.lock().await, Some(true));
        assert_eq!(*unrelated.decision.lock().await, None);
        assert_eq!(
            permission_batch_decision(&state, "batch-1").await,
            Some(true)
        );
        assert_eq!(permission_batch_decision(&state, "batch-2").await, None);
        assert_eq!(resolve_permission_batch(&state, "batch-1", false).await, 0);
        assert_eq!(
            state
                .pending_permissions
                .lock()
                .await
                .keys()
                .cloned()
                .collect::<Vec<_>>(),
            ["perm-3"]
        );
        let after_latch = pending_permission_for_batch("perm-4", session_id, 2, "batch-1");
        state
            .pending_permissions
            .lock()
            .await
            .insert("perm-4".to_string(), after_latch);
        assert!(
            take_pending_permission_for_individual(&state, "perm-4")
                .await
                .is_none(),
            "batch latch must prevent a later per-call decision from winning"
        );
        state.pending_permissions.lock().await.remove("perm-4");

        let late = request_tool_permission(
            &state,
            session_id,
            &bcode_model::ToolCall {
                id: "call-late".to_string(),
                name: "example.tool".to_string(),
                arguments: serde_json::Value::Null,
            },
            "example.tool",
            "example.plugin",
            &TurnCancelState::default(),
            PermissionPolicyContext {
                batch: Some(PermissionBatchCorrelation {
                    batch_id: "batch-1".to_string(),
                    call_index: 2,
                    call_count: 3,
                }),
                ..PermissionPolicyContext::default()
            },
        )
        .await;
        assert!(late, "late sibling must inherit the latched batch decision");
        assert_eq!(state.pending_permissions.lock().await.len(), 1);
    }

    #[tokio::test]
    #[allow(clippy::too_many_lines)]
    async fn cancelling_session_denies_and_closes_only_its_pending_permissions() {
        let sessions = SessionManager::default();
        let target = sessions
            .create_session(Some("target".to_owned()), test_working_directory())
            .await
            .expect("target session");
        let unrelated = sessions
            .create_session(Some("unrelated".to_owned()), test_working_directory())
            .await
            .expect("unrelated session");
        let state = Arc::new(test_server_state(sessions));
        let target_batch = Arc::new(PendingPermissionBatch::new(target.id));
        let unrelated_batch = Arc::new(PendingPermissionBatch::new(unrelated.id));
        state
            .pending_permission_batches
            .lock()
            .unwrap_or_else(std::sync::PoisonError::into_inner)
            .extend([
                ("target-batch".to_owned(), Arc::clone(&target_batch)),
                ("unrelated-batch".to_owned(), Arc::clone(&unrelated_batch)),
            ]);
        let unrelated_permission =
            pending_permission_for_batch("unrelated-1", unrelated.id, 0, "unrelated-batch");
        state
            .pending_permissions
            .lock()
            .await
            .insert("unrelated-1".to_owned(), unrelated_permission.clone());

        let cancel_state = Arc::new(TurnCancelState::default());
        let mut tasks = Vec::new();
        for index in 0..2 {
            let task_state = Arc::clone(&state);
            let task_cancel = Arc::clone(&cancel_state);
            tasks.push(tokio::spawn(async move {
                request_tool_permission(
                    task_state.as_ref(),
                    target.id,
                    &bcode_model::ToolCall {
                        id: format!("target-call-{index}"),
                        name: "example.tool".to_owned(),
                        arguments: serde_json::Value::Null,
                    },
                    "example.tool",
                    "example.plugin",
                    task_cancel.as_ref(),
                    PermissionPolicyContext {
                        batch: Some(PermissionBatchCorrelation {
                            batch_id: "target-batch".to_owned(),
                            call_index: index,
                            call_count: 2,
                        }),
                        ..PermissionPolicyContext::default()
                    },
                )
                .await
            }));
        }
        let pending = wait_for_pending_permissions(state.as_ref(), 3).await;
        assert_eq!(
            pending
                .iter()
                .filter(|permission| permission.summary.session_id == target.id)
                .count(),
            2
        );

        cancel_state.close();
        cancel_pending_permissions_for_session(state.as_ref(), target.id).await;

        for task in tasks {
            assert!(!task.await.expect("permission waiter"));
        }
        assert_eq!(*target_batch.decision.lock().await, Some(false));
        assert_eq!(*unrelated_batch.decision.lock().await, None);
        assert_eq!(*unrelated_permission.decision.lock().await, None);
        assert_eq!(
            state
                .pending_permissions
                .lock()
                .await
                .keys()
                .cloned()
                .collect::<Vec<_>>(),
            ["unrelated-1"]
        );
        let history = state
            .sessions
            .session_history(target.id)
            .await
            .expect("target history");
        assert_eq!(
            history
                .iter()
                .filter(|event| matches!(event.kind, SessionEventKind::PermissionRequested { .. }))
                .count(),
            2
        );
        assert_eq!(
            history
                .iter()
                .filter(|event| matches!(
                    event.kind,
                    SessionEventKind::PermissionResolved {
                        approved: false,
                        ..
                    }
                ))
                .count(),
            2
        );
    }

    async fn wait_for_pending_permissions(
        state: &ServerState,
        expected: usize,
    ) -> Vec<PendingPermission> {
        tokio::time::timeout(Duration::from_secs(10), async {
            loop {
                let pending = state.pending_permissions.lock().await;
                if pending.len() == expected {
                    break pending.values().cloned().collect();
                }
                drop(pending);
                tokio::task::yield_now().await;
            }
        })
        .await
        .expect("all permissions should resolve before invocation starts")
    }

