    #[cfg(unix)]
    #[tokio::test]
    #[allow(clippy::too_many_lines)]
    async fn server_persists_shell_owned_contribution_opaquely() {
        let workspace = tempfile::tempdir().expect("shell contribution workspace");
        let sessions = SessionManager::persistent(workspace.path().join("sessions"))
            .expect("persistent shell contribution sessions");
        let session_id = sessions
            .create_session(
                Some("shell contribution".to_owned()),
                workspace.path().to_path_buf(),
            )
            .await
            .expect("shell contribution session")
            .id;
        let mut attachment = sessions
            .attach_session(session_id, ClientId::new())
            .await
            .expect("shell contribution session should attach");
        let mut state = test_server_state_with_shell_plugin(sessions);
        state.trace_store = TraceStore::new(workspace.path().join("traces"));
        let result = execute_server_tool_for_test(
            &state,
            session_id,
            bcode_model::ToolCall {
                id: "shell-contribution".to_owned(),
                name: "shell.run".to_owned(),
                arguments: serde_json::json!({"command": "printf server-contribution"}),
            },
            workspace.path().to_path_buf(),
            "bcode.shell",
            Arc::new(TurnCancelState::default()),
            None,
        )
        .await
        .expect("shell contribution result");
        assert!(!result.is_error, "{:?}", result.content);
        let mut saw_recording_contribution = false;
        while let Ok(live) = attachment.live_events.try_recv() {
            match live.kind {
                SessionLiveEventKind::ToolContributionPlaced { envelope }
                    if envelope.contribution.contribution_id == "shell-recording" =>
                {
                    assert_eq!(
                        envelope.placement,
                        bcode_session_models::ToolContributionPlacement::Progress
                    );
                    saw_recording_contribution |= envelope.contribution.artifact.is_some();
                }
                SessionLiveEventKind::ToolOutputDelta {
                    event: ToolInvocationStreamEvent::ArtifactUpdate { .. },
                } => panic!("shell emitted legacy artifact-update stream"),
                _ => {}
            }
        }
        assert!(saw_recording_contribution);
        assert!(
            active_artifact_snapshot_events(&state, session_id)
                .expect("shell reattach artifact snapshot")
                .iter()
                .any(|snapshot| matches!(
                    &snapshot.kind,
                    SessionLiveEventKind::ToolContributionPlaced { envelope }
                        if envelope.contribution.contribution_id == "shell-recording"
                            && envelope.contribution.artifact.is_some()
                            && envelope.placement
                                == bcode_session_models::ToolContributionPlacement::Progress
                ))
        );

        let history = state
            .sessions
            .session_history(session_id)
            .await
            .expect("shell contribution history");
        let contribution = history
            .iter()
            .find_map(|event| match &event.kind {
                SessionEventKind::ToolContributionPlaced { envelope }
                    if envelope.contribution.schema == "bcode.shell.run.summary"
                        && envelope.placement
                            == bcode_session_models::ToolContributionPlacement::Result =>
                {
                    Some(&envelope.contribution)
                }
                _ => None,
            })
            .expect("durable shell contribution");
        assert_eq!(contribution.invocation_id, "shell-contribution");
        assert_eq!(contribution.producer_id, "bcode.shell");
        assert_eq!(contribution.schema, "bcode.shell.run.summary");
        assert!(
            contribution
                .payload
                .to_string()
                .contains("server-contribution")
        );
        assert!(history.iter().any(|event| matches!(
            &event.kind,
            SessionEventKind::ToolInvocationLifecycle { event }
                if event.invocation_id == "shell-contribution"
                    && event.stage
                        == bcode_session_models::ToolInvocationLifecycleStage::Progress
                    && event
                        .message
                        .as_deref()
                        .is_some_and(|message| message.contains("starting command"))
        )));
    }

