    #[cfg(unix)]
    #[allow(clippy::too_many_lines)]
    #[tokio::test]
    async fn server_same_batch_shell_calls_overlap_after_complete_authorization() {
        let workspace = tempfile::tempdir().expect("parallel shell workspace");
        let sessions = SessionManager::persistent(workspace.path().join("sessions"))
            .expect("persistent parallel shell sessions");
        let summary = sessions
            .create_session(
                Some("parallel shell batch".to_string()),
                workspace.path().to_path_buf(),
            )
            .await
            .expect("parallel shell session");
        let session_id = summary.id;
        let mut state = test_server_state_with_shell_plugin(sessions);
        state.trace_store = TraceStore::new(workspace.path().join("traces"));
        state.tool_execution.parallel = true;
        let state = Arc::new(state);
        let calls = (0..5)
            .map(|index| bcode_model::ToolCall {
                id: format!("parallel-shell-{index}"),
                name: "shell.run".to_string(),
                arguments: serde_json::json!({
                    "command": format!(
                        "touch .parallel-{index}; while [ \"$(find . -maxdepth 1 -name '.parallel-*' | wc -l | tr -d ' ')\" -lt 5 ]; do sleep 0.02; done; sleep {delay}; printf 'call-{index}\\n'",
                        delay = f64::from(4 - index) * 0.05,
                    ),
                    "timeout_ms": 2_000
                }),
            })
            .collect::<Vec<_>>();
        let cancel_state = Arc::new(TurnCancelState::default());
        let task_state = Arc::clone(&state);
        let task_cancel = Arc::clone(&cancel_state);
        let task = tokio::spawn(async move {
            let (_followup_tx, mut followup_rx) = mpsc::channel(1);
            let (_steering_tx, mut steering_rx) = mpsc::channel(1);
            let (_cancel_tx, mut cancel_rx) = mpsc::channel(1);
            let queued_followups = AtomicUsize::new(0);
            let current_turn = Arc::new(Mutex::new(None));
            let mut command_context = RuntimeCommandContext::new(
                &mut followup_rx,
                &mut steering_rx,
                &mut cancel_rx,
                &queued_followups,
                current_turn,
            );
            execute_model_tool_batch(
                task_state.as_ref(),
                session_id,
                calls,
                task_cancel,
                &mut command_context,
                &bcode_session_models::TurnExecutionOptions::default(),
            )
            .await
        });

        let pending = wait_for_pending_permissions(state.as_ref(), 5).await;
        let correlations = pending
            .iter()
            .map(|permission| {
                permission
                    .summary
                    .batch
                    .clone()
                    .expect("batch permission must carry correlation")
            })
            .collect::<Vec<_>>();
        assert!(
            correlations
                .iter()
                .all(|correlation| correlation.batch_id == correlations[0].batch_id),
            "one authorization batch must use one batch ID"
        );
        assert!(
            correlations
                .iter()
                .all(|correlation| correlation.call_count == 5),
            "every summary must carry the complete batch size"
        );
        assert_eq!(
            correlations
                .iter()
                .map(|correlation| correlation.call_index)
                .collect::<BTreeSet<_>>(),
            BTreeSet::from([0, 1, 2, 3, 4]),
            "permission summaries must preserve unique provider-order indices"
        );
        assert_eq!(
            pending
                .iter()
                .map(|permission| {
                    let correlation = permission
                        .summary
                        .batch
                        .as_ref()
                        .expect("batch permission correlation");
                    (
                        permission.summary.tool_call_id.clone(),
                        correlation.call_index,
                    )
                })
                .collect::<BTreeMap<_, _>>(),
            (0..5)
                .map(|index| (format!("parallel-shell-{index}"), index))
                .collect::<BTreeMap<_, _>>(),
            "provider call IDs must remain correlated with their batch indices"
        );
        assert!(
            state
                .active_plugin_invocations
                .lock()
                .expect("active invocation registry")
                .is_empty(),
            "no shell invocation may start before the complete batch is authorized"
        );
        let mut pending = pending.into_iter();
        for permission in pending.by_ref().take(4) {
            approve_pending_permission_for_test(state.as_ref(), &permission).await;
        }
        tokio::task::yield_now().await;
        assert!(
            state
                .active_plugin_invocations
                .lock()
                .expect("active invocation registry")
                .is_empty(),
            "no shell invocation may start while one batch decision remains unresolved"
        );
        let final_permission = pending.next().expect("fifth shell permission");
        let batch_id = final_permission
            .summary
            .batch
            .as_ref()
            .expect("fifth shell batch correlation")
            .batch_id
            .clone();
        assert_eq!(
            resolve_permission_batch(state.as_ref(), &batch_id, true).await,
            1
        );

        assert!(
            tokio::time::timeout(Duration::from_secs(10), task)
                .await
                .expect("parallel shell batch should finish")
                .expect("parallel shell batch task should not panic")
        );
        assert!(
            (0..5).all(|index| workspace.path().join(format!(".parallel-{index}")).exists()),
            "every shell command must start before any can complete"
        );
        assert_persisted_tool_results_in_order(
            state.as_ref(),
            session_id,
            &(0..5)
                .map(|index| format!("parallel-shell-{index}"))
                .collect::<Vec<_>>(),
        )
        .await;
        let history = state
            .sessions
            .session_history(session_id)
            .await
            .expect("parallel shell history");
        for index in 0..5 {
            let invocation_id = format!("parallel-shell-{index}");
            let stages = history
                .iter()
                .filter_map(|event| match &event.kind {
                    SessionEventKind::ToolInvocationLifecycle { event }
                        if event.invocation_id == invocation_id =>
                    {
                        Some(event.stage)
                    }
                    _ => None,
                })
                .collect::<Vec<_>>();
            assert_eq!(
                stages,
                vec![
                    bcode_session_models::ToolInvocationLifecycleStage::Started,
                    bcode_session_models::ToolInvocationLifecycleStage::Progress,
                    bcode_session_models::ToolInvocationLifecycleStage::Completed,
                ]
            );
        }
    }

    async fn assert_current_session_writer_epoch(session_root: &Path, session_id: SessionId) {
        let db =
            bcode_session::db::SessionDb::open_existing_turso_in_root(session_id, session_root)
                .await
                .expect("migrated database");
        assert_eq!(
            db.storage_writer_epoch().await.expect("writer epoch"),
            u64::from(bcode_session::db::CURRENT_SESSION_STORAGE_WRITER_EPOCH)
        );
    }

    async fn wait_for_user_message(state: &ServerState, session_id: SessionId, expected: &str) {
        tokio::time::timeout(Duration::from_secs(5), async {
            loop {
                let history = state
                    .sessions
                    .session_history(session_id)
                    .await
                    .expect("history");
                if history.iter().any(|event| {
                    matches!(
                        &event.kind,
                        SessionEventKind::UserMessage { text, .. } if text == expected
                    )
                }) {
                    break;
                }
                tokio::time::sleep(Duration::from_millis(10)).await;
            }
        })
        .await
        .expect("message should persist");
    }

    async fn create_current_session(sessions: &SessionManager, workspace: &Path) -> SessionId {
        sessions
            .create_session(Some("current IPC".to_owned()), workspace.to_path_buf())
            .await
            .expect("current session")
            .id
    }

    async fn assert_current_session_prepares_and_attaches_without_migration(
        connection: &mut bcode_client::ClientConnection,
        state: &ServerState,
        session_id: SessionId,
    ) {
        let current = connection
            .prepare_session_open(session_id)
            .await
            .expect("prepare current session over IPC");
        assert_eq!(
            current.outcome,
            Some(bcode_session_models::SessionOpenTerminalOutcome::Ready)
        );
        assert_eq!(state.sessions.active_session_migration_count().await, 0);
        connection
            .attach_session_recent(session_id, 16)
            .await
            .expect("current bounded attach");
    }

    async fn prepare_legacy_session_with_two_clients_and_disconnect(
        client: &bcode_client::BcodeClient,
        mut initiator: bcode_client::ClientConnection,
        session_id: SessionId,
    ) -> (bcode_session_models::SessionOpenOperationSnapshot, bool) {
        let initial = initiator
            .prepare_session_open(session_id)
            .await
            .expect("initiating preparation");
        if initial.outcome.is_some() {
            return (initial, false);
        }
        let mut observer = client
            .connect("legacy-migration-observer-test")
            .await
            .expect("connect second observer");
        let mut joined = observer
            .prepare_session_open(session_id)
            .await
            .expect("join preparation");
        assert_eq!(joined.operation_id, initial.operation_id);
        while joined.progress.stage < bcode_session_models::SessionMigrationStage::CopyingBackup {
            joined = observer
                .wait_session_open_progress(
                    session_id,
                    joined.operation_id,
                    joined.revision,
                    Duration::from_secs(5),
                )
                .await
                .expect("wait for backup copy stage");
        }
        assert_eq!(
            joined.progress.stage,
            bcode_session_models::SessionMigrationStage::CopyingBackup,
            "responsiveness probe must run during backup copy"
        );
        let unrelated_started = std::time::Instant::now();
        tokio::time::timeout(Duration::from_secs(1), client.ping())
            .await
            .expect("active migration starved unrelated ping")
            .expect("unrelated ping during migration");
        assert!(
            unrelated_started.elapsed() < Duration::from_secs(1),
            "unrelated ping exceeded migration responsiveness threshold"
        );
        for stop in [
            client.server_stop_if_idle().await,
            client.server_stop().await,
        ] {
            assert!(matches!(
                stop,
                Err(bcode_client::ClientError::Server { code, message })
                    if code == "daemon_busy" && message.contains("active session migration")
            ));
        }
        drop(initiator);

        let mut snapshot = joined;
        while snapshot.outcome.is_none() {
            snapshot = observer
                .wait_session_open_progress(
                    session_id,
                    snapshot.operation_id,
                    snapshot.revision,
                    Duration::from_secs(5),
                )
                .await
                .expect("observe migration after initiator disconnect");
        }
        assert_eq!(
            snapshot.outcome,
            Some(bcode_session_models::SessionOpenTerminalOutcome::Ready)
        );
        (snapshot, true)
    }

    async fn create_current_and_legacy_ipc_sessions(
        session_root: &Path,
        workspace: &Path,
    ) -> (SessionId, SessionId) {
        let sessions = SessionManager::persistent(session_root).expect("persistent sessions");
        let current_session_id = create_current_session(&sessions, workspace).await;
        let session = sessions
            .create_session(Some("legacy IPC".to_owned()), workspace.to_path_buf())
            .await
            .expect("session");
        let db =
            bcode_session::db::SessionDb::open_existing_turso_in_root(session.id, session_root)
                .await
                .expect("session database");
        db.database()
            .update("session_storage_contract")
            .value("writer_epoch", DatabaseValue::Int64(2))
            .execute(db.database())
            .await
            .expect("writer epoch should become legacy");
        drop(db);
        drop(sessions);
        std::fs::write(
            bcode_session::db::session_dir_path(session_root, session.id)
                .join("migration-overlap.sidecar"),
            vec![0x5a; 16 * 1024 * 1024],
        )
        .expect("migration overlap sidecar");
        (session.id, current_session_id)
    }

    #[cfg(unix)]
    #[tokio::test]
    async fn legacy_session_migrates_across_real_attach_and_send_ipc() {
        let workspace = tempfile::tempdir().expect("IPC workspace");
        let session_root = workspace.path().join("sessions");
        let (session_id, current_session_id) =
            create_current_and_legacy_ipc_sessions(&session_root, workspace.path()).await;
        tokio::time::sleep(Duration::from_millis(50)).await;

        let sessions = SessionManager::persistent(&session_root).expect("restored sessions");
        let state = Arc::new(test_server_state(sessions));
        let socket_dir = tempfile::tempdir().expect("IPC socket directory");
        let endpoint = bcode_ipc::IpcEndpoint::unix_socket(socket_dir.path().join("server.sock"));
        let listener = LocalIpcListener::bind(&endpoint).expect("IPC listener");
        let server_state = Arc::clone(&state);
        let server = tokio::spawn(async move {
            loop {
                let stream = listener.accept().await.expect("client connection");
                let state = Arc::clone(&server_state);
                tokio::spawn(async move {
                    handle_client(stream, state).await.expect("handle client");
                });
            }
        });
        let client = bcode_client::BcodeClient::new(endpoint);
        let mut connection = client
            .connect("legacy-migration-test")
            .await
            .expect("connect");
        assert_current_session_prepares_and_attaches_without_migration(
            &mut connection,
            state.as_ref(),
            current_session_id,
        )
        .await;

        let (terminal, detached) =
            prepare_legacy_session_with_two_clients_and_disconnect(&client, connection, session_id)
                .await;
        let mut reconnected = client
            .connect("legacy-migration-reconnect-test")
            .await
            .expect("reconnect");
        if detached {
            let recovered = reconnected
                .wait_session_open_progress(
                    session_id,
                    terminal.operation_id,
                    terminal.revision,
                    Duration::from_secs(1),
                )
                .await
                .expect("recover retained terminal snapshot");
            assert_eq!(recovered, terminal);
        }
        let backup_root = workspace.path().join("session-migration-backups");
        assert_eq!(
            std::fs::read_dir(&backup_root)
                .expect("migration backup root")
                .count(),
            1,
            "two observers must share one retained backup"
        );
        let mut connection = reconnected;
        connection
            .attach_session_recent(session_id, 16)
            .await
            .expect("legacy attach should migrate transparently");
        connection
            .send_user_message(
                session_id,
                "after migration".to_owned(),
                bcode_ipc::PromptPlacement::Steering,
            )
            .await
            .expect("send should be accepted");
        wait_for_user_message(state.as_ref(), session_id, "after migration").await;
        assert_current_session_writer_epoch(&session_root, session_id).await;
        server.abort();
    }

