    #[tokio::test]
    async fn workflow_elevation_uses_normal_pending_permission_path() {
        let sessions = SessionManager::default();
        let session = sessions
            .create_session(Some("workflow".to_string()), PathBuf::from("."))
            .await
            .expect("session");
        let state = Arc::new(test_server_state(sessions));
        let scope = WorkflowGrantScope {
            definition: "review-flow".to_string(),
            definition_version: 1,
            workspace: "snapshot-1".to_string(),
            node: "commit".to_string(),
            run: Some("run-1".to_string()),
        };
        let request = bcode_workflow::WorkflowPolicyRequest {
            initiating: WorkflowToolCapability::ReadOnly,
            profile: WorkflowToolCapability::Mutating,
            node: WorkflowToolCapability::Mutating,
            scope: scope.clone(),
            grant: None,
        };
        let task = {
            let state = Arc::clone(&state);
            tokio::spawn(async move {
                bcode_workflow::authorize_workflow_policy(
                    &request,
                    &state.workflow_permission_resolver(
                        session.id,
                        "build".to_string(),
                        &bcode_workflow::WorkflowCancellation::new(),
                    ),
                )
                .await
            })
        };
        let permission = loop {
            let candidate = state
                .pending_permissions
                .lock()
                .await
                .values()
                .next()
                .cloned();
            if let Some(permission) = candidate {
                break permission;
            }
            tokio::task::yield_now().await;
        };
        assert_eq!(permission.summary.tool_name, "workflow.elevate");
        assert_eq!(
            permission.summary.policy_source.as_deref(),
            Some("workflow_policy")
        );
        let event = state
            .sessions
            .session_history(session.id)
            .await
            .expect("history")
            .into_iter()
            .find(|event| matches!(event.kind, SessionEventKind::PermissionRequested { .. }))
            .expect("permission event");
        assert!(matches!(
            event.kind,
            SessionEventKind::PermissionRequested { policy_source, .. }
                if policy_source.as_deref() == Some("workflow_policy")
        ));
        let pending =
            take_pending_permission_for_individual(&state, &permission.summary.permission_id)
                .await
                .expect("pending permission");
        resolve_pending_permission(&state, pending, true, false).await;
        let (effective, audit) = task.await.expect("join").expect("authorized");
        assert_eq!(effective, WorkflowToolCapability::Mutating);
        assert!(audit.contains(&format!("grant={}", permission.summary.permission_id)));
        assert!(state.pending_permissions.lock().await.is_empty());
        assert!(
            state
                .sessions
                .session_history(session.id)
                .await
                .expect("history")
                .iter()
                .any(|event| matches!(
                    &event.kind,
                    SessionEventKind::PermissionResolved { permission_id, approved }
                        if permission_id == &permission.summary.permission_id && *approved
                ))
        );
    }

    #[test]
    fn tool_invocation_metric_labels_exclude_unique_call_identity() {
        let labels =
            tool_invocation_metric_labels(SessionId::new(), "example.tool", Some("example.plugin"));

        assert_eq!(
            labels.get("tool_name").map(String::as_str),
            Some("example.tool")
        );
        assert_eq!(
            labels.get("plugin_id").map(String::as_str),
            Some("example.plugin")
        );
        for forbidden in [
            "tool_call_id",
            "call_id",
            "batch_id",
            "invocation_id",
            "permission_id",
        ] {
            assert!(
                !labels.contains_key(forbidden),
                "forbidden label: {forbidden}"
            );
        }
    }

    #[test]
    fn tool_output_publisher_coalesces_visual_updates_by_tool_call() {
        let mut publisher = ToolOutputLivePublisher::new();
        let update = |sequence| ToolInvocationStreamEvent::VisualUpdate {
            tool_call_id: "call".to_owned(),
            sequence,
            visual: bcode_session_models::PluginVisualDescriptor {
                visual_id: None,
                producer_plugin_id: Some("plugin".to_owned()),
                schema: "plugin.visual".to_owned(),
                schema_version: 1,
                title: None,
                subtitle: None,
                payload: serde_json::json!({"sequence": sequence}),
            },
            streaming: true,
        };
        publisher.enqueue_visual_update(update(1));
        publisher.enqueue_visual_update(update(2));
        assert_eq!(publisher.pending_visuals.len(), 1);
        assert!(matches!(
            publisher.pending_visuals.values().next(),
            Some(ToolInvocationStreamEvent::VisualUpdate { sequence: 2, .. })
        ));
    }

    #[test]
    #[ignore = "manual deterministic performance baseline"]
    fn artifact_update_publisher_baseline_report() {
        for raw_updates in [4_u64, 256, 4_096] {
            let mut publisher = ToolOutputLivePublisher::new();
            let metrics = MetricsRegistry::default();
            let started = Instant::now();
            for revision in 1..=raw_updates {
                let event = ToolInvocationStreamEvent::ArtifactUpdate {
                    tool_call_id: "call".to_owned(),
                    sequence: revision,
                    artifact_id: "artifact".to_owned(),
                    reference_key: "recording".to_owned(),
                    producer_plugin_id: "bcode.shell".to_owned(),
                    schema: "bcode.shell.run".to_owned(),
                    schema_version: 1,
                    content_type: None,
                    storage_uri: String::new(),
                    committed_bytes: revision.saturating_mul(17),
                    revision,
                    availability: None,
                    finalized: false,
                };
                let _ = publisher.enqueue_artifact_update(&metrics, event);
            }
            for pending in publisher.pending_artifacts.values() {
                record_artifact_update_published(&metrics, pending);
            }
            let report = metrics.report();
            let counter = |name: &str| report.snapshot.counters.get(name).copied().unwrap_or(0);
            println!(
                "BCODE_PERF_CASE {}",
                serde_json::json!({
                    "domain": "server_artifact_publisher",
                    "raw_updates": counter("tool.artifact_update.received_total"),
                    "coalesced_updates": counter("tool.artifact_update.coalesced_total"),
                    "published_updates": counter("tool.artifact_update.published_total"),
                    "committed_bytes": raw_updates.saturating_mul(17),
                    "wall_us": u64::try_from(started.elapsed().as_micros()).unwrap_or(u64::MAX),
                })
            );
        }
    }

    #[test]
    fn tool_output_publisher_coalesces_artifact_revisions_by_identity() {
        let mut publisher = ToolOutputLivePublisher::new();
        let update =
            |revision, committed_bytes, finalized| ToolInvocationStreamEvent::ArtifactUpdate {
                tool_call_id: "call".to_owned(),
                sequence: revision,
                artifact_id: "artifact".to_owned(),
                reference_key: "recording".to_owned(),
                producer_plugin_id: "plugin".to_owned(),
                schema: "plugin.recording".to_owned(),
                schema_version: 1,
                content_type: None,
                storage_uri: String::new(),
                committed_bytes,
                revision,
                availability: None,
                finalized,
            };

        let metrics = MetricsRegistry::default();
        assert_eq!(
            publisher.enqueue_artifact_update(&metrics, update(1, 10, false)),
            (true, false)
        );
        assert_eq!(
            publisher.enqueue_artifact_update(&metrics, update(2, 20, false)),
            (false, false)
        );
        assert_eq!(publisher.pending_artifacts.len(), 1);
        assert!(matches!(
            publisher
                .pending_artifacts
                .values()
                .next()
                .map(|pending| &pending.event),
            Some(ToolInvocationStreamEvent::ArtifactUpdate {
                revision: 2,
                committed_bytes: 20,
                ..
            })
        ));
        let report = metrics.report();
        assert_eq!(
            report
                .snapshot
                .counters
                .get("tool.artifact_update.received_total"),
            Some(&2)
        );
        assert_eq!(
            report
                .snapshot
                .counters
                .get("tool.artifact_update.coalesced_total"),
            Some(&1)
        );
        assert_eq!(
            publisher.enqueue_artifact_update(&metrics, update(3, 30, true)),
            (false, true)
        );
    }

    #[tokio::test]
    async fn tool_output_delta_is_transient_not_durable() {
        let sessions = SessionManager::default();
        let summary = sessions
            .create_session(Some("test".to_owned()), test_working_directory())
            .await
            .expect("session should be created");
        let session_id = summary.id;
        let mut attachment = sessions
            .attach_session(session_id, ClientId::new())
            .await
            .expect("session should attach");
        let state = test_server_state(sessions);
        let delta = ToolInvocationStreamEvent::OutputDelta {
            tool_call_id: "call-1".to_owned(),
            stream: SessionToolOutputStream::Pty,
            sequence: 1,
            text: "live".to_owned(),
            byte_len: 4,
        };

        append_tool_stream_event(&state, session_id, delta.clone()).await;

        let received = loop {
            let event = attachment
                .live_events
                .recv()
                .await
                .expect("subscriber should receive live delta");
            if matches!(event.kind, SessionLiveEventKind::ToolOutputDelta { .. }) {
                break event;
            }
        };
        assert_eq!(
            received.kind,
            SessionLiveEventKind::ToolOutputDelta { event: delta }
        );
        let history = state
            .sessions
            .session_history(session_id)
            .await
            .expect("history should read");
        assert!(!history.iter().any(|event| matches!(
            event.kind,
            SessionEventKind::ToolInvocationStream {
                event: ToolInvocationStreamEvent::OutputDelta { .. }
            }
        )));
    }

    #[tokio::test]
    #[allow(clippy::too_many_lines)] // One active-envelope test covers validation, ordering, replay, and removal.
    async fn transient_contribution_is_published_live_only_with_verified_identity() {
        let sessions = SessionManager::default();
        let session_id = sessions
            .create_session(Some("test".to_owned()), test_working_directory())
            .await
            .expect("session should be created")
            .id;
        let mut attachment = sessions
            .attach_session(session_id, ClientId::new())
            .await
            .expect("session should attach");
        let state = test_server_state(sessions);
        let contribution = bcode_session_models::ToolContributionEvent {
            invocation_id: "call-1".to_owned(),
            contribution_id: "surface".to_owned(),
            sequence: 1,
            producer_id: "test.plugin".to_owned(),
            schema: "test.surface".to_owned(),
            schema_version: 1,
            operation: bcode_session_models::ToolContributionOperation::Upsert,
            persistence: bcode_session_models::ToolContributionPersistence::Transient,
            artifact: None,
            payload: serde_json::json!({"live": true}),
        };

        append_tool_contribution_event(
            &state,
            session_id,
            "call-1",
            "test.plugin",
            contribution.clone(),
        )
        .await;
        assert_eq!(
            attachment
                .live_events
                .recv()
                .await
                .expect("live contribution")
                .kind,
            SessionLiveEventKind::ToolContribution {
                event: contribution.clone(),
            }
        );
        assert!(
            !state
                .sessions
                .session_history(session_id)
                .await
                .expect("history")
                .iter()
                .any(|event| matches!(event.kind, SessionEventKind::ToolContribution { .. }))
        );

        assert_eq!(
            active_contribution_snapshot_events(&state, session_id)
                .expect("active contribution snapshot"),
            vec![bcode_session_models::SessionLiveEvent {
                session_id,
                kind: SessionLiveEventKind::ToolContribution {
                    event: contribution.clone(),
                },
            }]
        );
        append_tool_contribution_event(
            &state,
            session_id,
            "call-1",
            "test.plugin",
            contribution.clone(),
        )
        .await;
        assert!(attachment.live_events.try_recv().is_err());

        let mut updated = contribution.clone();
        updated.sequence = 2;
        updated.payload = serde_json::json!({"live": "updated"});
        append_tool_contribution_event(
            &state,
            session_id,
            "call-1",
            "wrong.plugin",
            updated.clone(),
        )
        .await;
        assert!(attachment.live_events.try_recv().is_err());
        append_tool_contribution_event(
            &state,
            session_id,
            "call-1",
            "test.plugin",
            updated.clone(),
        )
        .await;
        assert_eq!(
            attachment
                .live_events
                .recv()
                .await
                .expect("updated contribution")
                .kind,
            SessionLiveEventKind::ToolContribution { event: updated }
        );

        append_tool_contribution_event(
            &state,
            session_id,
            "other-call",
            "test.plugin",
            contribution,
        )
        .await;
        assert!(attachment.live_events.try_recv().is_err());
        clear_active_contributions(&state, session_id, "call-1").await;
        assert!(
            active_contribution_snapshot_events(&state, session_id)
                .expect("cleared snapshots")
                .is_empty()
        );
        assert!(matches!(
            attachment.live_events.recv().await.expect("terminal removal").kind,
            SessionLiveEventKind::ToolContribution { event }
                if event.operation == bcode_session_models::ToolContributionOperation::Remove
                    && event.sequence == 3
        ));
    }

