    #[tokio::test]
    #[allow(clippy::too_many_lines)]
    async fn provider_native_compaction_persists_compatible_snapshot_and_portable_fallback() {
        let sessions = SessionManager::default();
        let summary = sessions
            .create_session(
                Some("native compaction".to_owned()),
                test_working_directory(),
            )
            .await
            .expect("session should be created");
        let session_id = summary.id;
        for text in ["first turn", "second turn", "active turn"] {
            sessions
                .append_event(
                    session_id,
                    SessionEventKind::UserMessage {
                        client_id: ClientId::new(),
                        text: text.to_string(),
                        admission: bcode_session_models::TurnAdmissionMetadata::default(),
                    },
                )
                .await
                .expect("append user turn");
            sessions
                .append_event(
                    session_id,
                    SessionEventKind::AssistantMessage {
                        text: format!("response to {text}"),
                    },
                )
                .await
                .expect("append assistant turn");
        }
        let mut state = test_server_state_with_fake_provider(sessions);
        state.auto_compaction.keep_recent_tokens = 1;
        state.auto_compaction.backend = bcode_config::CompactionBackend::ProviderNative;
        let selection = SessionModelSelection {
            provider_plugin_id: Some("bcode.fake-provider".to_string()),
            requested_model_id: None,
            model_id: Some("fake-model".to_string()),
            provider_context: bcode_model::ProviderRequestContext {
                auth_profile: Some("profile-a".to_string()),
                settings: BTreeMap::from([(
                    "fake_native_compaction".to_string(),
                    "true".to_string(),
                )]),
                ..bcode_model::ProviderRequestContext::default()
            },
            ..SessionModelSelection::default()
        };

        compact_session_context_with_limit(
            &state,
            session_id,
            &selection,
            None,
            None,
            &TurnCancelState::default(),
            None,
        )
        .await
        .unwrap_or_else(|error| panic!("provider-native compaction failed: {error}"));

        let history = state
            .sessions
            .session_history(session_id)
            .await
            .expect("history should read");
        let snapshot = history.iter().find_map(|event| match &event.kind {
            SessionEventKind::ProviderContextCompacted { snapshot, .. } => Some(snapshot),
            _ => None,
        });
        let snapshot = snapshot.expect("provider snapshot should persist");
        assert_eq!(snapshot.provider_plugin_id, "bcode.fake-provider");
        assert_eq!(snapshot.model_id, "fake-model");
        assert_eq!(snapshot.auth_profile.as_deref(), Some("profile-a"));
        assert_eq!(snapshot.format_version, 1);
        assert_eq!(snapshot.compatibility_key, "bcode.fake-provider/context-v1");
        assert!(!snapshot.messages_json.is_empty());
        assert!(!snapshot.portable_summary.is_empty());

        let incompatible_messages = session_events_to_model_messages_for_target(
            &history,
            state.tool_output_context_chars,
            Some("different-provider"),
            Some("different-model"),
            None,
            None,
            None,
        );
        assert!(incompatible_messages.iter().any(|message| {
            message.content.iter().any(|block| {
                matches!(block, ContentBlock::Text { text } if text.contains(&snapshot.portable_summary))
            })
        }));
        let incompatible_auth_messages = session_events_to_model_messages_for_target(
            &history,
            state.tool_output_context_chars,
            Some("bcode.fake-provider"),
            Some("fake-model"),
            Some("profile-b"),
            Some(1),
            Some("bcode.fake-provider/context-v1"),
        );
        assert!(incompatible_auth_messages.iter().any(|message| {
            message.content.iter().any(|block| {
                matches!(block, ContentBlock::Text { text } if text.contains(&snapshot.portable_summary))
            })
        }));
        assert!(!incompatible_auth_messages.iter().any(|message| {
            message
                .content
                .iter()
                .any(|block| matches!(block, ContentBlock::ProviderExtension { .. }))
        }));

        let incompatible_format_messages = session_events_to_model_messages_for_target(
            &history,
            state.tool_output_context_chars,
            Some("bcode.fake-provider"),
            Some("fake-model"),
            Some("profile-a"),
            Some(2),
            Some("bcode.fake-provider/context-v2"),
        );
        assert!(!incompatible_format_messages.iter().any(|message| {
            message
                .content
                .iter()
                .any(|block| matches!(block, ContentBlock::ProviderExtension { .. }))
        }));
    }

    #[tokio::test]
    async fn multiple_provider_native_compactions_advance_persisted_boundary() {
        let sessions = SessionManager::default();
        let summary = sessions
            .create_session(
                Some("multiple compactions".to_owned()),
                test_working_directory(),
            )
            .await
            .expect("session should be created");
        let session_id = summary.id;
        let mut state = test_server_state_with_fake_provider(sessions);
        state.auto_compaction.keep_recent_tokens = 1;
        state.auto_compaction.backend = bcode_config::CompactionBackend::ProviderNative;
        let selection = SessionModelSelection {
            provider_plugin_id: Some("bcode.fake-provider".to_string()),
            requested_model_id: None,
            model_id: Some("fake-model".to_string()),
            provider_context: bcode_model::ProviderRequestContext {
                settings: BTreeMap::from([(
                    "fake_native_compaction".to_string(),
                    "true".to_string(),
                )]),
                ..bcode_model::ProviderRequestContext::default()
            },
            ..SessionModelSelection::default()
        };

        for round in 0..2 {
            for turn in 0..3 {
                state
                    .sessions
                    .append_event(
                        session_id,
                        SessionEventKind::UserMessage {
                            client_id: ClientId::new(),
                            text: format!("round {round} user {turn}"),
                            admission: bcode_session_models::TurnAdmissionMetadata::default(),
                        },
                    )
                    .await
                    .expect("append user turn");
                state
                    .sessions
                    .append_event(
                        session_id,
                        SessionEventKind::AssistantMessage {
                            text: format!("round {round} assistant {turn}"),
                        },
                    )
                    .await
                    .expect("append assistant turn");
            }
            compact_session_context_with_limit(
                &state,
                session_id,
                &selection,
                None,
                None,
                &TurnCancelState::default(),
                None,
            )
            .await
            .unwrap_or_else(|error| panic!("compaction round {round} failed: {error}"));
        }

        let history = state
            .sessions
            .session_history(session_id)
            .await
            .expect("history should read");
        let boundaries = history
            .iter()
            .filter_map(|event| match &event.kind {
                SessionEventKind::ProviderContextCompacted {
                    compacted_through_sequence,
                    ..
                } => Some(*compacted_through_sequence),
                _ => None,
            })
            .collect::<Vec<_>>();
        assert_eq!(boundaries.len(), 2);
        assert!(boundaries[1] > boundaries[0]);

        let context = state
            .sessions
            .model_context_events(session_id)
            .await
            .expect("model context");
        assert!(matches!(
            context.first().map(|event| &event.kind),
            Some(SessionEventKind::ProviderContextCompacted { .. })
        ));
        assert_eq!(
            context.first().map(|event| event.sequence),
            history
                .iter()
                .rev()
                .find(|event| matches!(
                    event.kind,
                    SessionEventKind::ProviderContextCompacted { .. }
                ))
                .map(|event| event.sequence)
        );
    }

