    #[test]
    fn generic_final_result_is_model_visible_once_during_dual_write() {
        let session_id = SessionId::new();
        let history = vec![
            session_event(
                session_id,
                1,
                SessionEventKind::ToolCallRequested {
                    tool_call_id: "call-1".to_owned(),
                    producer_plugin_id: Some("example.plugin".to_owned()),
                    tool_name: "example.tool".to_owned(),
                    arguments_json: "{}".to_owned(),
                    working_directory: None,
                    request_visual: None,
                    legacy_request_presentation: None,
                },
            ),
            session_event(
                session_id,
                2,
                SessionEventKind::ToolInvocationResultRecorded {
                    record: bcode_session_models::ToolInvocationResultRecord {
                        invocation_id: "call-1".to_owned(),
                        model_output: "generic result".to_owned(),
                        is_error: false,
                        result: None,
                    },
                },
            ),
            session_event(
                session_id,
                3,
                SessionEventKind::ToolCallFinished {
                    tool_call_id: "call-1".to_owned(),
                    result: "legacy duplicate".to_owned(),
                    is_error: false,
                    output: None,
                    semantic_result: None,
                },
            ),
        ];

        let messages = session_events_to_model_messages_with_limit(&history, 1_000);
        let results = messages
            .iter()
            .flat_map(|message| &message.content)
            .filter_map(|content| match content {
                ContentBlock::ToolResult { result } => Some(result),
                _ => None,
            })
            .collect::<Vec<_>>();
        assert_eq!(results.len(), 1);
        assert_eq!(results[0].call_id, "call-1");
        assert_eq!(results[0].output, "generic result");
    }

    #[test]
    fn provider_context_snapshot_is_target_specific_with_portable_fallback() {
        let session_id = SessionId::new();
        let provider_messages = vec![ModelMessage {
            role: MessageRole::Assistant,
            content: vec![ContentBlock::Text {
                text: "opaque provider context".to_string(),
            }],
        }];
        let history = [session_event(
            session_id,
            1,
            SessionEventKind::ProviderContextCompacted {
                snapshot: bcode_session_models::ProviderContextSnapshot {
                    format_version: 1,
                    request_fingerprint: None,
                    request_id: None,
                    provider_plugin_id: "provider-a".to_string(),
                    model_id: "model-a".to_string(),
                    compatibility_key: "surface-a".to_string(),
                    auth_profile: Some("profile-a".to_string()),
                    origin: bcode_session_models::ProviderContextSnapshotOrigin::Explicit,
                    messages_json: serde_json::to_string(&provider_messages).expect("messages"),
                    portable_summary: "portable context".to_string(),
                },
                compacted_through_sequence: 1,
            },
        )];

        let matching = session_events_to_model_messages_for_target(
            &history,
            1_000,
            Some("provider-a"),
            Some("model-a"),
            Some("profile-a"),
            Some(1),
            Some("surface-a"),
        );
        let mismatched = [
            (
                Some("provider-b"),
                Some("model-a"),
                Some("profile-a"),
                Some(1),
                Some("surface-a"),
            ),
            (
                Some("provider-a"),
                Some("model-b"),
                Some("profile-a"),
                Some(1),
                Some("surface-a"),
            ),
            (
                Some("provider-a"),
                Some("model-a"),
                Some("profile-b"),
                Some(1),
                Some("surface-a"),
            ),
            (
                Some("provider-a"),
                Some("model-a"),
                Some("profile-a"),
                Some(2),
                Some("surface-a"),
            ),
            (
                Some("provider-a"),
                Some("model-a"),
                Some("profile-a"),
                Some(1),
                Some("surface-b"),
            ),
        ]
        .map(|(provider, model, auth, version, key)| {
            session_events_to_model_messages_for_target(
                &history, 1_000, provider, model, auth, version, key,
            )
        });

        let matching_after_switch_back = session_events_to_model_messages_for_target(
            &history,
            1_000,
            Some("provider-a"),
            Some("model-a"),
            Some("profile-a"),
            Some(1),
            Some("surface-a"),
        );
        assert_eq!(matching, provider_messages);
        assert_eq!(matching_after_switch_back, provider_messages);
        assert!(mismatched.iter().all(|messages| matches!(
            &messages[0].content[0],
            ContentBlock::Text { text } if text.contains("portable context")
        )));
    }

