    #[test]
    fn portable_fallback_preserves_tool_protocol_without_opaque_provider_data() {
        let messages = [
            ModelMessage {
                role: MessageRole::Assistant,
                content: vec![
                    ContentBlock::Text {
                        text: "checking".to_string(),
                    },
                    ContentBlock::ToolCall {
                        call: bcode_model::ToolCall {
                            id: "call-1".to_string(),
                            name: "filesystem.read".to_string(),
                            arguments: serde_json::json!({"path": "Cargo.toml"}),
                        },
                    },
                    ContentBlock::ProviderExtension {
                        value: serde_json::json!({"encrypted": "secret-opaque-value"}),
                    },
                ],
            },
            ModelMessage {
                role: MessageRole::Tool,
                content: vec![ContentBlock::ToolResult {
                    result: bcode_model::ToolResult {
                        call_id: "call-1".to_string(),
                        output: "workspace manifest".to_string(),
                        is_error: false,
                        content: Vec::new(),
                    },
                }],
            },
        ];

        let fallback = bounded_portable_context(&messages);

        assert!(fallback.contains("checking"));
        assert!(fallback.contains("tool call: id=call-1"));
        assert!(fallback.contains("filesystem.read"));
        assert!(fallback.contains("Cargo.toml"));
        assert!(fallback.contains("tool result: call_id=call-1"));
        assert!(fallback.contains("workspace manifest"));
        assert!(fallback.contains("provider-specific context omitted"));
        assert!(!fallback.contains("secret-opaque-value"));
    }

    #[test]
    fn portable_fallback_is_bounded() {
        let messages = [ModelMessage {
            role: MessageRole::User,
            content: vec![ContentBlock::Text {
                text: "x".repeat(COMPACTION_MAX_CARRIED_SUMMARY_CHARS * 2),
            }],
        }];

        assert!(
            bounded_portable_context(&messages).chars().count()
                <= COMPACTION_MAX_CARRIED_SUMMARY_CHARS
        );
    }

    #[tokio::test]
    #[allow(clippy::too_many_lines)] // Verifies one complete durable result/reference/projection boundary.
    async fn finalized_artifact_result_is_durable_and_projected_without_live_payloads() {
        let temp = tempfile::tempdir().expect("temp dir");
        let root = temp.path().join("sessions");
        let sessions = SessionManager::persistent(&root).expect("persistent sessions");
        let summary = sessions
            .create_session(Some("artifact-result".to_owned()), test_working_directory())
            .await
            .expect("session should be created");
        let session_id = summary.id;
        let state = test_server_state(sessions);
        state
            .sessions
            .append_tool_call_requested(
                session_id,
                bcode_session::AppendToolCallRequestedInput {
                    tool_call_id: "call-1".to_owned(),
                    tool_name: "fixture.run".to_owned(),
                    arguments_json: "{}".to_owned(),
                    producer_plugin_id: Some("fixture.plugin".to_owned()),
                    working_directory: None,
                    request_visual: None,
                    legacy_request_presentation: None,
                },
            )
            .await
            .expect("append tool request");
        let semantic_result = ToolInvocationResult::Artifact {
            artifact: Box::new(bcode_session_models::ToolArtifact {
                artifact_id: "artifact-1".to_owned(),
                producer_plugin_id: "fixture.plugin".to_owned(),
                schema: "fixture.recording".to_owned(),
                schema_version: 1,
                tool_call_id: Some("call-1".to_owned()),
                title: Some("Recording".to_owned()),
                metadata: serde_json::json!({"summary": "bounded"}),
                refs: vec![bcode_session_models::ToolArtifactRef {
                    key: "recording".to_owned(),
                    content_type: Some("application/octet-stream".to_owned()),
                    storage_uri: Some("recording.bin".to_owned()),
                    byte_len: Some(42),
                    metadata: Some(serde_json::json!({
                        "availability": "complete",
                        "complete": true,
                        "checksum_sha256": "abc123"
                    })),
                }],
            }),
        };
        let event = append_tool_finished_event_inner(
            &state,
            session_id,
            ToolFinishedEventInput {
                tool_call_id: "call-1".to_owned(),
                result: "bounded final result".to_owned(),
                is_error: false,
                content: Vec::new(),
                semantic_result: Some(semantic_result.clone()),
            },
        )
        .await
        .expect("append final artifact result");
        assert!(matches!(
            event.kind,
            SessionEventKind::ToolInvocationResultRecorded { record }
                if record.result.as_ref() == Some(&semantic_result)
        ));
        let reference = state
            .sessions
            .finalized_artifact_reference(session_id, "artifact-1", "recording")
            .await
            .expect("bounded artifact lookup")
            .expect("projected reference");
        assert_eq!(reference.byte_len, Some(42));
        assert_eq!(reference.checksum_sha256.as_deref(), Some("abc123"));

        let history = state
            .sessions
            .session_history(session_id)
            .await
            .expect("history");
        assert!(!history.iter().any(|event| matches!(
            event.kind,
            SessionEventKind::ToolInvocationStream {
                event: ToolInvocationStreamEvent::VisualUpdate { .. }
                    | ToolInvocationStreamEvent::OutputDelta { .. }
                    | ToolInvocationStreamEvent::ArtifactUpdate { .. }
            }
        )));
        let projection = state
            .sessions
            .session_projection_window(
                session_id,
                bcode_session_models::ProjectionWindowRequest {
                    projection: bcode_session_models::SessionProjectionKind::Transcript,
                    anchor: bcode_session_models::ProjectionWindowAnchor::Latest,
                    direction: bcode_session_models::ProjectionWindowDirection::Backward,
                    target: bcode_session_models::ProjectionWindowTarget {
                        min_items: Some(2),
                        min_estimated_rows: None,
                        min_bytes: None,
                        width_columns: None,
                    },
                    limits: bcode_session_models::ProjectionWindowLimits {
                        max_items: 10,
                        max_events_scanned: 10,
                        max_bytes: 4_096,
                    },
                },
            )
            .await
            .expect("transcript projection");
        assert_eq!(projection.transcript_items.len(), 1);
        assert!(projection.transcript_items.iter().any(|item| {
            item.kind == bcode_session_models::TranscriptProjectionItemKind::ToolInvocation
                && item.source_range.end_sequence == event.sequence
        }));
        assert!(projection.transcript_items.iter().all(|item| {
            item.source_range.start_sequence <= item.source_range.end_sequence
                && item.content_bytes <= 4_096
        }));
        remove_session_artifact_dir(&root).expect("session cleanup");
    }

    #[tokio::test]
    async fn append_tool_finished_event_inner_persists_semantic_result() {
        let sessions = SessionManager::default();
        let summary = sessions
            .create_session(Some("test".to_owned()), test_working_directory())
            .await
            .expect("session should be created");
        let session_id = summary.id;
        let state = ServerState::new(
            sessions,
            bcode_plugin::PluginHost::default().into(),
            ServerStateInit {
                model_catalog: Some(bcode_model_catalog::ModelCatalogResolver::embedded()),
                selected_provider_plugin_id: None,
                selected_model_id: None,
                selected_provider_context: bcode_model::ProviderRequestContext::default(),
                prompt_cache_mode: bcode_model::PromptCacheMode::default(),
                conversation_reuse_mode: bcode_model::ConversationReuseMode::default(),
                selected_reasoning: bcode_config::ReasoningConfig::default(),
                selected_reasoning_capabilities: None,
                provider_state: ProviderStateStore::load(PathBuf::new()),
                observability: bcode_config::ObservabilityConfig::default(),
                trace_store: TraceStore::new(PathBuf::new()),
                max_tool_rounds: None,
                tool_execution: bcode_tool::ToolExecutionOptions::default(),
                tool_output_context_chars: 1_000,
                model_streaming: bcode_config::StreamingConfig::default(),
                model_retry: bcode_config::ModelRetryConfig::default(),
                auto_compaction: bcode_config::CompactionConfig::default(),
                skills: None,
                skill_context_bytes: 0,
                skill_prompt_options: SkillPromptCatalogOptions::default(),
                skill_model_policy: bcode_config::SkillModelPolicyConfig::default(),
                system_prompt: bcode_config::SystemPromptConfig::default(),
                daemon_status: DaemonStatus::default(),
                daemon_record_path: None,
                metrics: MetricsRegistry::default(),
                ralph_store: bcode_ralph::RalphStateStore::default(),
            },
        );
        let semantic_result = ToolInvocationResult::Text {
            text: "semantic text".to_owned(),
        };

        let event = append_tool_finished_event_inner(
            &state,
            session_id,
            ToolFinishedEventInput {
                tool_call_id: "call-semantic".to_owned(),
                result: "legacy text".to_owned(),
                is_error: false,
                content: Vec::new(),
                semantic_result: Some(semantic_result.clone()),
            },
        )
        .await
        .expect("tool result event should append");

        let history = state
            .sessions
            .session_history(session_id)
            .await
            .expect("tool result history");
        assert!(history.iter().any(|event| matches!(
            &event.kind,
            SessionEventKind::ToolInvocationResultRecorded { record }
                if record.invocation_id == "call-semantic"
                    && record.model_output == "legacy text"
                    && record.result.as_ref() == Some(&semantic_result)
        )));

        assert_eq!(
            history
                .iter()
                .filter(|event| matches!(event.kind, SessionEventKind::ToolCallFinished { .. }))
                .count(),
            0,
            "production result persistence must not dual-write the legacy finish event"
        );
        assert_eq!(
            history
                .iter()
                .filter(|event| matches!(
                    event.kind,
                    SessionEventKind::ToolInvocationResultRecorded { .. }
                ))
                .count(),
            1
        );
        let SessionEventKind::ToolInvocationResultRecorded { record } = event.kind else {
            panic!("expected generic tool result event");
        };
        assert_eq!(record.model_output, "legacy text");
        assert_eq!(record.result, Some(semantic_result));
    }

